int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    // 'e', 'r', 'o' are used by both, but 'n' is unique to 'one' and 'z' is unique to 'zero'.
    // The number of 'one's is limited by 'n'.
    // The number of 'zero's is limited by 'z'.
    // The other letters ('e', 'r', 'o') will always be sufficient if 'n' and 'z' are sufficient,
    // because the problem guarantees that it's possible to rearrange the letters.
    // This means we don't need to worry about 'e', 'r', 'o' counts explicitly for the final number of words.

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
    }

    // To maximize the binary number, we want to place all '1's before all '0's.
    // The number of '1's is determined by the count of 'n's (from "one").
    // The number of '0's is determined by the count of 'z's (from "zero").

    bool first_digit = true;

    for (int i = 0; i < count_n; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < count_z; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }

    std::cout << std::endl;

    return 0;
}

