int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick n chairs starting from 4n and going downwards,
        // skipping chairs that are multiples of 2 but not 4, or are odd.
        // Specifically, we want to pick chairs that are multiples of 4.
        // However, the problem statement implies we can pick any n chairs.
        // A simpler strategy that works is to pick chairs 4n, 4n-2, 4n-4, ...
        // No, this is not correct. The example output for n=3 is 4 6 10.
        // These are 2*2, 2*3, 2*5. All are even.
        // gcd(4,6)=2, 4 not div 6, 6 not div 4. OK.
        // gcd(4,10)=2, 4 not div 10, 10 not div 4. OK.
        // gcd(6,10)=2, 6 not div 10, 10 not div 6. OK.
        // This suggests picking numbers that are all even, and not multiples of each other.
        // The simplest way to ensure they are not multiples of each other and share a common factor
        // is to pick numbers that are all multiples of 2, but not multiples of 4, and are distinct.
        // Or, more generally, pick numbers that are all multiples of some k > 1, and
        // ensure that for any two chosen numbers k*x and k*y, x does not divide y and y does not divide x.
        //
        // Let's try picking numbers of the form 2 * (2n - i) for i from 0 to n-1.
        // This would be 4n, 4n-2, 4n-4, ..., 2*(2n - (n-1)) = 2*(n+1).
        // These are n distinct even numbers.
        // For any two such numbers 2a and 2b:
        // gcd(2a, 2b) = 2 * gcd(a, b) >= 2, so gcd is not 1.
        // 2a divides 2b iff a divides b.
        // We need to ensure that for any two chosen numbers 2x and 2y, x does not divide y and y does not divide x.
        // The numbers are 2*(n+1), 2*(n+2), ..., 2*(2n).
        // The underlying numbers are n+1, n+2, ..., 2n.
        // For any two distinct numbers x, y from {n+1, ..., 2n}, if x divides y, then y = kx for some integer k.
        // Since x < y, k must be >= 2.
        // If y = kx and x >= n+1, then y >= 2(n+1) = 2n+2.
        // But all numbers in the set {n+1, ..., 2n} are less than or equal to 2n.
        // So, y cannot be kx for k >= 2.
        // Therefore, no number in {n+1, ..., 2n} divides another number in the same set.
        //
        // So, the set of chairs {2*(n+1), 2*(n+2), ..., 2*(2n)} satisfies all conditions.
        // These are n distinct chairs.
        // The smallest chair is 2*(n+1). The largest chair is 2*(2n) = 4n.
        // All chairs are within the range [1, 4n].
        //
        // Example n=2: {2*(2+1), 2*(2+2)} = {6, 8}. Output: 6 4. My strategy gives 6 8.
        // Example n=3: {2*(3+1), 2*(3+2), 2*(3+3)} = {8, 10, 12}. Output: 4 6 10. My strategy gives 8 10 12.
        // Example n=4: {2*(4+1), 2*(4+2), 2*(4+3), 2*(4+4)} = {10, 12, 14, 16}. Output: 14 10 12 8. My strategy gives 10 12 14 16.
        //
        // The example outputs are different but valid. My strategy also produces valid outputs.
        // The problem states "If there are multiple answers, print any of them."
        //
        // Let's implement this strategy: print 2*(n+1), 2*(n+2), ..., 2*(2n).

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (n + 1 + i) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

