#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks needed for k torches and k coal
        // k torches require k sticks.
        // k coal require k * y sticks.
        // Total sticks to acquire = k * y + k = k * (y + 1)
        long long total_sticks_to_acquire = k * (y + 1);

        // We start with 1 stick.
        // Each trade of type 1 (1 stick for x sticks) gives us x-1 net sticks.
        // We need to reach total_sticks_to_acquire sticks.
        // Let's say we perform N_stick_trades of type 1.
        // The number of sticks we have will be 1 + N_stick_trades * (x - 1).
        // We need this to be >= total_sticks_to_acquire.
        // 1 + N_stick_trades * (x - 1) >= total_sticks_to_acquire
        // N_stick_trades * (x - 1) >= total_sticks_to_acquire - 1
        // N_stick_trades >= (total_sticks_to_acquire - 1) / (x - 1)
        // Since N_stick_trades must be an integer, we use ceiling division.
        long long num_stick_trades = (total_sticks_to_acquire - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = num_stick_trades (for acquiring sticks) + k (for acquiring coal)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

