#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position,
        // or it can be achieved if both +1 and -1 are available (or neither if a[i] is 0).
        // The crucial part is that if we need to increase/decrease, we must have the corresponding 1/-1 available *before* this index.
        // The `has_one` and `has_minus_one` flags correctly track this because they are updated only after processing the current index.
        // So, if a[i] is 1 or -1, it contributes to the flags for subsequent indices.
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // With 2n students, if we sort them, the optimal strategy is to pick
        // the n-th student (0-indexed, a[n-1]) and the (n+1)-th student (a[n])
        // as the medians of the two classes.
        // This is because if we pick a[i] and a[j] as medians,
        // to minimize |a[i] - a[j]|, we should pick them as close as possible.
        // The smallest possible median for a class of size 2k+1 is a[k].
        // The largest possible median for a class of size 2k+1 is a[2k].
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // We need to form two classes, C1 and C2, each with an odd number of students.
        // Let |C1| = 2k1+1 and |C2| = 2k2+1, where k1+k2 = n-1.
        //
        // The median of C1 will be some a_i, and the median of C2 will be some a_j.
        //
        // The key insight is that to minimize the difference between medians,
        // we should choose the medians to be adjacent elements in the sorted full list.
        // Specifically, the median of one class will be a[n-1] and the median of the other will be a[n].
        //
        // To see why:
        // Suppose we pick a[i] as the median of C1 and a[j] as the median of C2.
        // For a[i] to be the median of C1, C1 must contain k1 elements smaller than or equal to a[i],
        // and k1 elements greater than or equal to a[i].
        // Similarly for a[j] and C2.
        //
        // If we choose a[n-1] as the median of one class and a[n] as the median of the other,
        // we can always construct valid classes.
        //
        // Let's say C1 has median a[n-1] and C2 has median a[n].
        // We need to form C1 with 2k1+1 elements and C2 with 2k2+1 elements.
        //
        // For C1 (median a[n-1]):
        // We need k1 elements <= a[n-1] and k1 elements >= a[n-1].
        // We can pick a[n-1] itself.
        // We have a[0]...a[n-2] (n-1 elements) available that are <= a[n-1].
        // We have a[n]...a[2n-1] (n elements) available that are >= a[n-1].
        //
        // For C2 (median a[n]):
        // We need k2 elements <= a[n] and k2 elements >= a[n].
        // We can pick a[n] itself.
        // We have a[0]...a[n-1] (n elements) available that are <= a[n].
        // We have a[n+1]...a[2n-1] (n-1 elements) available that are >= a[n].
        //
        // We can always form two classes with medians a[n-1] and a[n].
        // For example, let C1 take a[0], ..., a[n-1] (n elements).
        // Let C2 take a[n], ..., a[2n-1] (n elements).
        // This is not a valid partition because class sizes must be odd.
        //
        // However, the problem is simpler: the minimum difference will always be between a[n-1] and a[n].
        // This is a known property for problems involving partitioning into two groups and minimizing median difference.
        // The two medians will be the two "middle" elements of the entire sorted array.
        //
        // Example 1: n=1, 2n=2. a = [1, 1]. Sorted: [1, 1].
        // n-1 = 0, n = 1. Medians are a[0] and a[1]. Diff = |1-1| = 0.
        //
        // Example 2: n=3, 2n=6. a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // n-1 = 2, n = 3. Medians are a[2] and a[3]. Diff = |a[3] - a[2]| = |4 - 3| = 1.
        //
        // Example 3: n=5, 2n=10. a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16].
        // Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // n-1 = 4, n = 5. Medians are a[4] and a[5]. Diff = |a[5] - a[4]| = |13 - 8| = 5.
        //
        // The logic holds for all examples.
        // The minimum difference is simply a[n] - a[n-1] after sorting.
        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

