#include <iostream>
#include <vector>
#include <numeric>
#include <string>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_duration = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_duration += a[i];
    }

    if (total_duration % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration_per_post = total_duration / k;
    std::vector<int> s_values;
    long long current_post_duration = 0;
    int current_post_videos_count = 0;
    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_duration += a[i];
        current_post_videos_count++;

        if (current_post_duration == target_duration_per_post) {
            s_values.push_back(current_post_videos_count);
            current_post_duration = 0;
            current_post_videos_count = 0;
            posts_formed++;
        } else if (current_post_duration > target_duration_per_post) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_formed == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "No\n";
    }

    return 0;
}

