#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i must be distinct from previous p_j if it's a new max
                // But it's good to check for robustness.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else { // q_i == q_{i-1}
            // p_i must be some number not yet used, and p_i < q_i (which is q_{i-1})
            // We need to find the smallest available number that is not used and is less than q_i.
            // The numbers available are those from 1 to n that are not in used_numbers.
            // We can iterate from 1 upwards to find the smallest available number.
            // However, a more efficient way is to keep track of available numbers.
            // For this problem, we need to pick a number that is *not* q_i, and *not* already used.
            // The smallest available number strategy is generally good.
            // Let's find the smallest number 'x' such that 1 <= x <= n and x is not in used_numbers.
            // If such an 'x' exists and x < q_i, we can use it.
            // If all available numbers are >= q_i, then it's impossible.
            // A simpler approach: we know all numbers from 1 to n must be used.
            // The numbers that are *not* q_j for some j are the ones we need to fill in.
            // Let's collect all numbers from 1 to n that are not present in the 'q' values that became 'p_i's.
            // This is equivalent to finding numbers not in `used_numbers`.
            // We need to find the smallest number `x` such that `x` is not in `used_numbers` and `x < q_i`.
            // If we use a `std::set` for `used_numbers`, we can iterate through `1...n` to find the smallest unused.
            // A more efficient way is to pre-populate a set of all numbers from 1 to n, then remove used ones.
            // Or, just iterate from 1 to n and find the first unused.

            int current_val = 1;
            while (current_val <= n && used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val > n || current_val > q[i]) { // current_val > q[i] implies no suitable number found
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

