int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_stair_cells = 3; // Cells for n=1 (1*2/2=1) + n=2 (2*3/2=3) = 4. No, this is wrong.
                                           // The sequence of cells for nice staircases is:
                                           // n=1: 1 cell (1*2/2)
                                           // n=3: 1+2+3 = 6 cells (3*4/2)
                                           // n=7: 1+2+...+7 = 28 cells (7*8/2)
                                           // The number of cells for a nice staircase with k stairs is (k*(k+1))/2
                                           // where k is of the form 2^m - 1.
                                           // For m=1, k=1, cells = 1.
                                           // For m=2, k=3, cells = 6.
                                           // For m=3, k=7, cells = 28.
                                           // For m=4, k=15, cells = 120.
                                           // For m=5, k=31, cells = 496.
                                           // The number of cells for a nice staircase with 2^m - 1 stairs is (2^m - 1) * (2^m) / 2.
                                           // Let's call this C_m.
                                           // C_1 = (2^1 - 1) * 2^1 / 2 = 1 * 2 / 2 = 1
                                           // C_2 = (2^2 - 1) * 2^2 / 2 = 3 * 4 / 2 = 6
                                           // C_3 = (2^3 - 1) * 2^3 / 2 = 7 * 8 / 2 = 28
                                           // C_4 = (2^4 - 1) * 2^4 / 2 = 15 * 16 / 2 = 120
                                           // C_m = (2^m - 1) * 2^(m-1)

        long long k = 1; // Represents 2^m - 1 for m=1
        long long cells_needed = 1; // Cells for k=1

        while (x >= cells_needed) {
            x -= cells_needed;
            count++;

            // Calculate next k and next cells_needed
            // k_next = 2 * k + 1
            // cells_needed_next = (k_next * (k_next + 1)) / 2
            // This can be simplified:
            // k_next = 2 * (2^m - 1) + 1 = 2^(m+1) - 2 + 1 = 2^(m+1) - 1
            // cells_needed_next = (2^(m+1) - 1) * 2^m
            // From current k = 2^m - 1, we have 2^m = k + 1
            // So, cells_needed_next = (2*(k+1) - 1) * (k+1) / 2
            // This is (2k+1) * (k+1) / 2

            // To avoid overflow with (2k+1)*(k+1), let's use the direct formula for cells_needed_next
            // cells_needed_next = (2^(m+1) - 1) * 2^m
            // We can get 2^m from k+1.
            // So, cells_needed_next = (2*(k+1) - 1) * (k+1) / 2

            // Let's use the pattern:
            // k_new = 2*k + 1
            // cells_needed_new = (k_new * (k_new + 1)) / 2
            // This is equivalent to cells_needed_new = (2*k+1) * (k+1) / 2
            // This is also equivalent to cells_needed_new = 2 * cells_needed + (k+1)^2
            // No, this is not right.
            // The sequence of cells is 1, 6, 28, 120, 496, ...
            // The difference between consecutive terms is not simple.
            // Let's use the formula: C_m = (2^m - 1) * 2^(m-1)
            // C_{m+1} = (2^(m+1) - 1) * 2^m
            // C_{m+1} = (2 * (2^m) - 1) * 2^m
            // C_{m+1} = (2 * (k+1) - 1) * (k+1) / 2 * 2
            // C_{m+1} = (2k+1) * (k+1)
            // This is the number of cells for the next staircase.

            // k is 2^m - 1.
            // The next k will be 2^(m+1) - 1.
            // So, k_next = 2 * k + 1.
            // The cells for k_next is (k_next * (k_next + 1)) / 2.

            // Let's calculate k_next first.
            long long k_next = 2 * k + 1;

            // Check for potential overflow before calculating cells_needed_next
            // k_next can go up to 2^62 - 1 (approx) for x up to 10^18.
            // (k_next * (k_next + 1)) / 2 can exceed long long if k_next is too large.
            // Max k_next for x=10^18:
            // (k_next * (k_next + 1)) / 2 <= 10^18
            // k_next^2 approx 2 * 10^18
            // k_next approx sqrt(2 * 10^18) = sqrt(200 * 10^16) approx 14 * 10^8.
            // 2^30 approx 10^9. So k_next can be around 2^30.
            // 2*k+1 can reach 2* (2^30-1) + 1 = 2^31 - 1.
            // (2^31-1) * (2^31) / 2 = (2^31-1) * 2^30. This is approx 2^61, which fits in long long.
            // So, direct calculation should be fine.

            long long cells_needed_next;
            if (k_next % 2 == 0) { // k_next is even
                cells_needed_next = (k_next / 2) * (k_next + 1);
            } else { // k_next is odd
                cells_needed_next = k_next * ((k_next + 1) / 2);
            }

            // Check for overflow for cells_needed_next
            // If k_next is very large, k_next * (k_next + 1) might overflow before division.
            // Max k_next is around 1.4 * 10^9.
            // (1.4 * 10^9)^2 is 1.96 * 10^18. This fits in long long.
            // So, cells_needed_next calculation is safe.

            k = k_next;
            cells_needed = cells_needed_next;
        }
        std::cout << count << "\n";
    }
    return 0;
}

