#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak for the decreasing suffix
    // This is the first index `i` from the right such that a[i] < a[i+1]
    // All elements from `i+1` to `n-1` are in non-increasing order.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-increasing.
    // If i is 0, the whole array is non-increasing.

    // Find the rightmost peak for the increasing suffix
    // This is the first index `j` from the right such that a[j] > a[j+1]
    // All elements from `j+1` to `n-1` are in non-decreasing order.
    int j = i; // Start search from `i`
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...n-1] is a "good" array.
    // The elements a[j...i-1] are non-decreasing, and a[i...n-1] are non-increasing.
    // This forms a "mountain" or "valley" shape (or a monotonic sequence).
    // The elements a[j...n-1] can be picked to form a non-decreasing sequence.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // n=7
    // i starts at 6. a[5]=3, a[6]=2. a[5] > a[6]. i becomes 5.
    // i=5. a[4]=5, a[5]=3. a[4] > a[5]. i becomes 4.
    // i=4. a[3]=4, a[4]=5. a[3] < a[4]. Stop. i=4.
    // Suffix a[4...6] = [5, 3, 2] is non-increasing.
    //
    // j starts at i=4.
    // j=4. a[3]=4, a[4]=5. a[3] < a[4]. j becomes 3.
    // j=3. a[2]=1, a[3]=4. a[2] < a[3]. j becomes 2.
    // j=2. a[1]=3, a[2]=1. a[1] > a[2]. Stop. j=2.
    // Suffix a[2...6] = [1, 4, 5, 3, 2] is the good array.
    // The prefix to remove has length j.
    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

