}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx and max_idx are both pos[1].
        // For m > 1, we need to expand the segment to include 'm'.
        // The number 'm' is at pos[m].
        // We need to update current_min_idx and current_max_idx to cover
        // the range from 1 to m.
        // This means the new segment must span from min(current_min_idx, pos[m])
        // to max(current_max_idx, pos[m]).

        if (m > 1) {
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);
        }

        // A number m is beautiful if the segment p[current_min_idx ... current_max_idx]
        // contains exactly numbers 1 to m.
        // This implies two conditions:
        // 1. The length of the segment must be m.
        //    Length = current_max_idx - current_min_idx + 1.
        // 2. The maximum value in this segment must be m.
        //    (The minimum value is guaranteed to be 1 because we always expand
        //    the segment to include 1, and then 2, ..., up to m).
        //
        // The second condition (max value is m) is implicitly handled by the first condition.
        // If the length is m, and it contains 1, ..., m, then the max must be m.
        // If the length is m, and it contains 1, ..., m-1, and m, then it's a permutation.
        // If the length is m, and it contains 1, ..., m-1, but not m, then it's not a permutation.
        // But we are expanding the segment to include 'm' at each step.
        // So, the segment p[current_min_idx ... current_max_idx] *always* contains
        // all numbers from 1 to m.
        // Therefore, the only condition we need to check is if its length is exactly m.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    std::vector<int> result_subsequence;
    result_subsequence.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum (peak or valley)
        // A peak: p[i-1] < p[i] > p[i+1]
        // A valley: p[i-1] > p[i] < p[i+1]
        // If p[i] is not a local extremum, it means p[i-1], p[i], p[i+1] are monotonic.
        // E.g., p[i-1] < p[i] < p[i+1] or p[i-1] > p[i] > p[i+1].
        // In such cases, p[i] can be removed without decreasing the total sum of differences
        // and potentially shortening the subsequence.
        // For example, if we have A, B, C where A < B < C, then |A-B| + |B-C| = (B-A) + (C-B) = C-A.
        // If we remove B, we get |A-C| = C-A. The sum is the same.
        // If we have A, B, C where A > B > C, then |A-B| + |B-C| = (A-B) + (B-C) = A-C.
        // If we remove B, we get |A-C| = A-C. The sum is the same.
        // So, we only keep p[i] if it's a local extremum.
        if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
            result_subsequence.push_back(p[i]);
        }
    }

    result_subsequence.push_back(p[n-1]);

    std::cout << result_subsequence.size() << "\n";
    for (size_t i = 0; i < result_subsequence.size(); ++i) {
        std::cout << result_subsequence[i] << (i == result_subsequence.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

