        // So, final magnitude < 1 is possible if B + C > 0.
        // Exception: If A+D=0, then B+C must be > 0, and final magnitude is always < 1.
        // So, final magnitude < 1 is possible if B + C > 0.
        bool final_mag_lt_1_possible = (B + C > 0);

        // Determine if the final toy can have magnitude >= 1.
        // This is possible if there's at least one toy with magnitude >= 1 (from Box 1 or Box 4).
        // If A+D > 0, we can always ensure the final product has magnitude >= 1.
        // E.g., keep multiplying all small toys together until they form one small toy.
        // Then multiply this small toy with a large toy.
        // If the result is still small, multiply it with another large toy, etc.
        // As long as there's at least one large toy, we can make the final product large.
        // Example: (0.5 * 0.5) = 0.25. (0.25 * 3) = 0.75. (0.75 * 3) = 2.25.
        // So, final magnitude >= 1 is possible if A + D > 0.
        bool final_mag_ge_1_possible = (A + D > 0);

        // Box 1: Negative, magnitude >= 1
        // Possible if final_is_negative is true AND final_mag_ge_1_possible is true.
        bool box1_possible = final_is_negative && final_mag_ge_1_possible;

        // Box 2: Negative, magnitude < 1
        // Possible if final_is_negative is true AND final_mag_lt_1_possible is true.
        bool box2_possible = final_is_negative && final_mag_lt_1_possible;

        // Box 3: Positive, magnitude < 1
        // Possible if final_is_negative is false AND final_mag_lt_1_possible is true.
        bool box3_possible = !final_is_negative && final_mag_lt_1_possible;

        // Box 4: Positive, magnitude >= 1
        // Possible if final_is_negative is false AND final_mag_ge_1_possible is true.
        bool box4_possible = !final_is_negative && final_mag_ge_1_possible;

        // Special case: If A+D=0, then all toys have magnitude < 1.
        // The final toy must have magnitude < 1.
        // So, box1_possible and box4_possible must be false.
        if (A + D == 0) {
            box1_possible = false;
            box4_possible = false;
        }
        // Special case: If B+C=0, then all toys have magnitude >= 1.
        // The final toy must have magnitude >= 1.
        // So, box2_possible and box3_possible must be false.
        if (B + C == 0) {
            box2_possible = false;
            box3_possible = false;
        }

        // One edge case: If A+D > 0 and B+C > 0, then both mag_lt_1 and mag_ge_1 are possible.
        // This is covered by the logic above.

        // Another edge case: What if A+B+C+D = 0? Problem statement says A+B+C+D > 0.
        // What if A+B+C+D = 1? Handled at the beginning.

        print_bool(box1_possible);
        std::cout << " ";
        print_bool(box2_possible);
        std::cout << " ";
        print_bool(box3_possible);
        std::cout << " ";
        print_bool(box4_possible);
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int prev_diff_01 = -1; // Index of the last '0' in a that needs to be '1' in b
    int prev_diff_10 = -1; // Index of the last '1' in a that needs to be '0' in b

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                if (prev_diff_10 != -1) { // Found a '1' in a that needs to be '0' in b
                    // We can swap a[prev_diff_10] and a[i]
                    // This fixes both positions.
                    // a[prev_diff_10] becomes '0' (correct for b[prev_diff_10])
                    // a[i] becomes '1' (correct for b[i])
                    cost += (i - prev_diff_10);
                    prev_diff_10 = -1; // This '10' mismatch is resolved
                    prev_diff_01 = -1; // This '01' mismatch is resolved
                } else {
                    // No '10' mismatch to pair with.
                    // This '01' mismatch might be paired later, or flipped.
                    // If prev_diff_01 was set, it means we had a '01' mismatch
                    // at prev_diff_01, and now we have another at i.
                    // These cannot be resolved by a single swap.
                    // We must either flip both, or swap one with a '10' mismatch.
                    // For now, just update prev_diff_01.
                    prev_diff_01 = i;
                }
            } else { // a[i] = '1', b[i] = '0'
                if (prev_diff_01 != -1) { // Found a '0' in a that needs to be '1' in b
                    // We can swap a[prev_diff_01] and a[i]
                    // This fixes both positions.
                    // a[prev_diff_01] becomes '1' (correct for b[prev_diff_01])
                    // a[i] becomes '0' (correct for b[i])
                    cost += (i - prev_diff_01);
                    prev_diff_01 = -1; // This '01' mismatch is resolved
                    prev_diff_10 = -1; // This '10' mismatch is resolved
                } else {
                    // No '01' mismatch to pair with.
                    // This '10' mismatch might be paired later, or flipped.
                    prev_diff_10 = i;
                }
            }
        }
    }

    // Any remaining prev_diff_01 or prev_diff_10 means there's an unmatched mismatch.
    // These must be fixed by flipping. Each flip costs 1.
    if (prev_diff_01 != -1) {
        cost += 1;
    }
    if (prev_diff_10 != -1) {
        cost += 1;
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Adjust elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end
        // The condition is x[right_ptr] <= x[i] + d
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy the condition
        // x[k] - x[i] <= d for k in [i+1, right_ptr-1]

        // We need to choose two points from the range [x[i+1], ..., x[right_ptr-1]]
        // Let m be the number of points available in this range.
        // The points are x[i+1], x[i+2], ..., x[right_ptr-1].
        // The number of such points is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        long long m = right_ptr - 1 - i;

        // If m < 2, we cannot choose two distinct points, so no triplets can be formed with x[i] as the smallest.
        if (m >= 2) {
            // The number of ways to choose 2 points from m available points is m * (m - 1) / 2
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i; // Not strictly needed for B, but good practice
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareA);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    // Create the result array A'
    // The element a_elements[i].value (which is the i-th smallest A value)
    // should be placed at the original index of b_elements[m-1-i].value
    // (which is the i-th largest B value).
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // a_elements[i] is the i-th smallest value from A
        // b_elements[m - 1 - i] is the i-th largest value from B
        // We want to assign a_elements[i].value to the position originally held by b_elements[m - 1 - i].value
        result_a_prime[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a prefix is a permutation
bool is_permutation_prefix(const std::vector<int>& a, int len, const std::vector<int>& max_val_prefix) {
    if (len == 0) return false; // Permutation length must be at least 1
    return max_val_prefix[len - 1] == len;
}

// Function to check if a suffix is a permutation
bool is_permutation_suffix(const std::vector<int>& a, int start_idx, int len, const std::vector<int>& max_val_suffix) {
    if (len == 0) return false; // Permutation length must be at least 1
    return max_val_suffix[start_idx] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max_val_prefix: max value in a[0...i]
    std::vector<int> max_val_prefix(n);
    if (n > 0) {
        max_val_prefix[0] = a[0];
        for (int i = 1; i < n; ++i) {
            max_val_prefix[i] = std::max(max_val_prefix[i - 1], a[i]);
        }
    }

    // Precompute max_val_suffix: max value in a[i...n-1]
    std::vector<int> max_val_suffix(n);
    if (n > 0) {
        max_val_suffix[n - 1] = a[n - 1];
        for (int i = n - 2; i >= 0; --i) {
            max_val_suffix[i] = std::max(max_val_suffix[i + 1], a[i]);
        }
    }

    // Precompute counts for prefixes
    std::vector<int> prefix_counts(n + 1, 0); // counts[x] for values 1 to n
    int distinct_prefix = 0;
    std::vector<bool> seen_prefix(n + 1, false); // seen_prefix[x] for values 1 to n
    std::vector<bool> is_perm_prefix_memo(n + 1, false); // is_perm_prefix_memo[l] is true if a[0...l-1] is a permutation of length l

    for (int l = 1; l <= n; ++l) {
        int val = a[l - 1];
        if (val >= 1 && val <= n) { // Only consider values within potential permutation range
            if (!seen_prefix[val]) {
                seen_prefix[val] = true;
                distinct_prefix++;
            }
            prefix_counts[val]++;
        }
        // A prefix a[0...l-1] is a permutation of length l if:
        // 1. All elements are <= l
        // 2. All elements from 1 to l appear exactly once
        // Condition 1 is checked by max_val_prefix[l-1] == l
        // Condition 2 is checked by distinct_prefix == l and all counts are 1
        if (max_val_prefix[l - 1] == l && distinct_prefix == l) {
            is_perm_prefix_memo[l] = true;
        }
    }

    // Precompute counts for suffixes
    std::vector<int> suffix_counts(n + 1, 0); // counts[x] for values 1 to n
    int distinct_suffix = 0;
    std::vector<bool> seen_suffix(n + 1, false); // seen_suffix[x] for values 1 to n
    std::vector<bool> is_perm_suffix_memo(n + 1, false); // is_perm_suffix_memo[l] is true if a[n-l...n-1] is a permutation of length l

    for (int l = 1; l <= n; ++l) {
        int val = a[n - l]; // Current element from the end
        if (val >= 1 && val <= n) { // Only consider values within potential permutation range
            if (!seen_suffix[val]) {
                seen_suffix[val] = true;
                distinct_suffix++;
            }
            suffix_counts[val]++;
        }
        // A suffix a[n-l...n-1] is a permutation of length l if:
        // 1. All elements are <= l
        // 2. All elements from 1 to l appear exactly once
        // Condition 1 is checked by max_val_suffix[n-l] == l
        // Condition 2 is checked by distinct_suffix == l and all counts are 1
        if (max_val_suffix[n - l] == l && distinct_suffix == l) {
            is_perm_suffix_memo[l] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_perm_prefix_memo[l1] && is_perm_suffix_memo[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case: N=2, Chanek takes 1, Opponent takes 1. Chanek gets 1.
                chanek_coins += 1;
                n -= 1; // N becomes 1, then opponent takes 1.
            } else {
                // Check if N is a power of 2
                // A number is a power of 2 if (n & (n - 1)) == 0
                if ((n & (n - 1)) == 0) { // N is a power of 2 (and N > 2)
                    // If N is a power of 2, taking N/2 is optimal for Chanek.
                    // Opponent will be left with N/2, which is also a power of 2.
                    // This continues until N=2, where Chanek takes 1.
                    // Example: N=8. Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 4+1=5. Opponent: 2+1=3.
                    // If Chanek takes 1: N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                    // It seems taking N/2 is always optimal for powers of 2.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    // Chanek can choose to take 1 or N/2.
                    // If Chanek takes 1: N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                    // If Chanek takes N/2: N becomes N/2.
                    // Since N is even and not a power of 2, N/2 is not a power of 2 or N/2 is odd.
                    // If N/2 is odd, opponent takes 1.
                    // If N/2 is even and not a power of 2, opponent takes N/4.
                    // If N/2 is a power of 2, opponent takes N/4.
                    // In general, taking N/2 is better for Chanek if it leaves the opponent with a smaller number or a number that leads to a worse outcome for the opponent.
                    // The strategy is to take N/2 if N is even and not a power of 2.
                    // This is because taking N/2 leaves an even number (N/2) for the opponent,
                    // unless N/2 is odd, in which case opponent takes 1.
                    // If N is even and not a power of 2, it means N has at least one odd factor greater than 1.
                    // N = 2^k * M, where M > 1 and M is odd.
                    // Taking N/2 leaves 2^(k-1) * M.
                    // Taking 1 leaves N-1 (odd). Opponent takes 1. N-2 (even).
                    // The optimal strategy for Chanek is to take N/2 if N is even and not a power of 2.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        }
        // Opponent's turn
        if (n > 0) {
            if (n % 2 != 0) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                if (n == 2) {
                    n -= 1; // Opponent takes 1
                } else {
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        n /= 2; // Opponent takes N/2
                    } else { // N is even but not a power of 2
                        n /= 2; // Opponent takes N/2
                    }
                }
            }
        }
    }
    return chanek_coins;
}

