void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    char best_bot_move = ' ';
    int max_count = -1;

    if (counts['R'] > max_count) {
        max_count = counts['R'];
        best_bot_move = 'R';
    }
    if (counts['P'] > max_count) {
        max_count = counts['P'];
        best_bot_move = 'P';
    }
    if (counts['S'] > max_count) {
        max_count = counts['S'];
        best_bot_move = 'S';
    }
    // If counts are equal, any choice is fine. The order of if statements
    // implicitly prioritizes P then S then R if counts are equal.
    // For example, if R=1, P=1, S=1, best_bot_move will be 'S'.
    // If R=2, P=1, S=1, best_bot_move will be 'R'.

    char our_winning_move;
    if (best_bot_move == 'R') {
        our_winning_move = 'P';
    } else if (best_bot_move == 'P') {
        our_winning_move = 'S';
    } else { // best_bot_move == 'S'
        our_winning_move = 'R';
    }

    for (int i = 0; i < n; ++i) {
        std::cout << our_winning_move;
    }
    std::cout << std::endl;
}

