#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends with w_i = 1 get two copies of the largest available numbers.
    // These are the k_ones largest numbers from 'a'.
    // Since w is sorted, friends with w_i = 1 are at the beginning of the sorted w array.
    // We iterate from the end of 'a' for these.
    int a_ptr_end = n - 1;
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_end];
            a_ptr_end--;
        } else {
            // All remaining w_i will be > 1. Break and handle them.
            // This relies on w being sorted.
            break;
        }
    }

    // Friends with w_i > 1 get the largest available number as their max,
    // and the smallest available number as their min.
    // The largest available numbers are taken from the remaining 'a_ptr_end' part of 'a'.
    // The smallest available numbers are taken from the beginning of 'a'.
    // To maximize sum, we pair the largest remaining w_i with the largest remaining max_val,
    // and the smallest remaining w_i with the smallest remaining min_val.
    // Since w is sorted ascending, we iterate w from largest w_i (end of w array)
    // and assign them the largest available max_val.
    // The smallest available min_val will be taken from the beginning of 'a'.

    int a_ptr_start = 0;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_end]; // Max value for this friend
            a_ptr_end--;

            total_happiness += a[a_ptr_start]; // Min value for this friend
            a_ptr_start += (w[i] - 1); // Consume w[i]-1 smallest elements
        }
    }

    std::cout << total_happiness << std::endl;
}

