            // X' = X ^ X = 0
            // We need S' = 2 * X' => S + X = 0. This is only possible if S=0, X=0.

            // A known trick for this problem type:
            // Append X.
            // New XOR sum becomes X_new = current_xor_sum ^ current_xor_sum = 0.
            // New sum becomes S_new = current_sum + current_xor_sum.
            // Now we need S_new = 2 * X_new, which means S_new = 2 * 0 = 0.
            // This is generally not true. S_new = current_sum + current_xor_sum.
            // If current_sum + current_xor_sum is not 0, we need to add another element.

            // Let's append two elements: current_xor_sum and current_sum + current_xor_sum.
            // Let b1 = current_xor_sum
            // Let b2 = current_sum + current_xor_sum
            // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
            // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
            // X' = 0 ^ (current_sum + current_xor_sum)
            // X' = current_sum + current_xor_sum

            // New sum: S' = current_sum + b1 + b2
            // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
            // S' = 2 * (current_sum + current_xor_sum)

            // Check condition: S' = 2 * X'
            // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
            // This always holds!

            // So, we can always append two elements:
            // b1 = current_xor_sum
            // b2 = current_sum + current_xor_sum
            // This uses 2 elements.
            // The problem states "at most 3 elements". This is fine.

            std::cout << 2 << "\n";
            std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
        }
    }
    return 0;
}

#include <iostream>
