int calculate_score(int n, const std::string& s) {
    if (n == 0) return 0;
    int current_score = 0;
    if (s[0] == 'W') {
        current_score += 1;
    }
    for (int i = 1; i < n; ++i) {
        if (s[i] == 'W') {
            if (s[i - 1] == 'W') {
                current_score += 2;
            } else {
                current_score += 1;
            }
        }
    }
    return current_score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins == 0) { // All 'L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else { // Change one 'L' to 'W'
                std::cout << 1 << "\n";
            }
            continue;
        }

        // Strategy:
        // 1. Convert 'L's at the ends to 'W's.
        // 2. Convert 'L's in gaps between 'W's to 'W's, prioritizing smaller gaps.

        // Step 1: Convert 'L's at the ends
        int current_k = k;
        int current_score = calculate_score(n, s);

        // Find first and last 'W'
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        // Convert 'L's before first 'W'
        for (int i = 0; i < first_W; ++i) {
            if (s[i] == 'L' && current_k > 0) {
                s[i] = 'W';
                current_k--;
            }
        }
        // Convert 'L's after last 'W'
        for (int i = n - 1; i > last_W; --i) {
            if (s[i] == 'L' && current_k > 0) {
                s[i] = 'W';
                current_k--;
            }
        }

        // Step 2: Convert 'L's in gaps
        std::vector<int> gap_lengths;
        int current_gap = 0;
        bool in_gap = false;
        for (int i = first_W + 1; i <= last_W; ++i) { // Iterate only between first and last W
            if (s[i] == 'L') {
                if (!in_gap) {
                    in_gap = true;
                    current_gap = 1;
                } else {
                    current_gap++;
                }
            } else { // s[i] == 'W'
                if (in_gap) {
                    gap_lengths.push_back(current_gap);
                    in_gap = false;
                }
            }
        }
        std::sort(gap_lengths.begin(), gap_lengths.end());

        for (int gap_len : gap_lengths) {
            if (current_k >= gap_len) {
                current_k -= gap_len;
                // These 'L's are converted to 'W's.
                // Each 'L' converted to 'W' in a gap between 'W's
                // effectively adds 2 points (1 for itself, 1 for previous W now getting 2 points).
                // The score calculation function will handle this.
            } else {
                break; // Cannot fill this gap or any larger ones
            }
        }

        // After applying changes, recalculate the score.
        // The above logic for changing s is conceptual.
        // A simpler way is to calculate the score based on the original string,
        // then add points for changes.
        // Each 'L' changed to 'W' adds 1 point.
        // If it connects two 'W's, it also adds 1 point to the left 'W'.
        // If it extends a 'W' sequence, it adds 1 point to the left 'W'.

        // Let's re-evaluate the score calculation after changes.
        // The initial score calculation is correct for the original string.
        // We need to count how many 'L's we can change to 'W's.
        // Each 'L' changed to 'W' adds 1 point.
        // If this 'W' is adjacent to another 'W', it adds an additional 1 point.

        // Let's count the number of 'W's and 'L's.
        // The maximum possible score is 2*n - 1 (if all are W, 1+2+2+...+2).
        // If k is large enough to make all games 'W', then the score is 2*n - 1.
        if (k >= n - initial_wins) { // Can make all games 'W'
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        // If not all games can be 'W', we need to be more precise.
        // Calculate initial score.
        int score = 0;
        if (s[0] == 'W') score = 1;
        for (int i = 1; i < n; ++i) {
            if (s[i] == 'W') {
                if (s[i-1] == 'W') score += 2;
                else score += 1;
            }
        }

        // Identify 'L' segments.
        // We want to convert 'L's to 'W's.
        // An 'L' converted to 'W' always adds 1 point.
        // If this 'W' becomes adjacent to an existing 'W', it adds another 1 point.
        // This means converting an 'L' to 'W' can add 1 or 2 points.
        // - If s[i] is 'L', and s[i-1] is 'L' and s[i+1] is 'L': adds 1 point.
        // - If s[i] is 'L', and s[i-1] is 'W' and s[i+1] is 'L': adds 2 points (1 for s[i], 1 for s[i-1]).
        // - If s[i] is 'L', and s[i-1] is 'L' and s[i+1] is 'W': adds 2 points (1 for s[i], 1 for s[i+1]).
        // - If s[i] is 'L', and s[i-1] is 'W' and s[i+1] is 'W': adds 2 points (1 for s[i], 1 for s[i-1], but s[i+1] already gets 2 points from s[i-1] if s[i] was W).
        // This is getting complicated. Let's use the gap filling strategy.

        // The strategy is:
        // 1. Fill 'L's at the beginning and end of the string.
        // 2. Fill 'L's in gaps between 'W's.
        // Each 'L' converted to 'W' costs 1 `k`.
        // Each 'L' converted to 'W' adds 1 point.
        // If this 'W' connects to an existing 'W' (or another 'L' converted to 'W'), it adds an additional 1 point.

        // Let's count the number of 'W's and 'L's.
        // The maximum possible score is 2*n - 1 (if all are W, 1+2+2+...+2).
        // If k is large enough to make all games 'W', then the score is 2*n - 1.
        if (k >= n - initial_wins) { // Can make all games 'W'
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        // If there are no 'W's initially, and k > 0, we can make one 'W'. Score 1.
        if (initial_wins == 0 && k > 0) {
            std::cout << 1 << "\n";
            continue;
        }
        // If there are no 'W's initially, and k == 0, score 0.
        if (initial_wins == 0 && k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate initial score
        score = 0;
        if (s[0] == 'W') score = 1;
        for (int i = 1; i < n; ++i) {
            if (s[i] == 'W') {
                if (s[i-1] == 'W') score += 2;
                else score += 1;
            }
        }

        // Collect lengths of 'L' segments between 'W's
        std::vector<int> internal_gaps;
        int current_L_count = 0;
        bool found_first_W = false;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                found_first_W = true;
                if (current_L_count > 0) {
                    internal_gaps.push_back(current_L_count);
                    current_L_count = 0;
                }
            } else { // s[i] == 'L'
                if (found_first_W) {
                    current_L_count++;
                }
            }
        }
        std::sort(internal_gaps.begin(), internal_gaps.end());

        // Fill internal gaps
        for (int gap_len : internal_gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                score += 2 * gap_len; // Each 'L' in a gap becomes 'W', connecting two 'W's.
                                      // It adds 1 for itself, and 1 for the 'W' to its left.
                                      // So, 2 points per 'L' converted.
            } else {
                score += 2 * k; // Use remaining k to fill part of this gap
                k = 0;
                break;
            }
        }

        // Fill 'L's at the ends
        // Find first and last 'W' again (after conceptual internal gap filling)
        first_W = -1;
        last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }
        // If all 'L's were converted and k is still available, this means all games are 'W'.
        // But we already handled the case where k is enough to make all games 'W'.
        // So, there must be some 'L's remaining at ends.

        // Count 'L's at the beginning
        int leading_Ls = 0;
        for (int i = 0; i < first_W; ++i) {
            if (s[i] == 'L') leading_Ls++;
        }
        // Count 'L's at the end
        int trailing_Ls = 0;
        for (int i = n - 1; i > last_W; --i) {
            if (s[i] == 'L') trailing_Ls++;
        }

        // Prioritize filling trailing 'L's because they can connect to last_W and give 2 points.
        // Filling leading 'L's only gives 1 point for the first 'W' and 2 for subsequent.
        // But if we fill an 'L' next to an existing 'W', it gives 2 points.
        // If we fill an 'L' not next to an existing 'W', it gives 1 point.
        // The current score already accounts for existing 'W's.
        // When we convert an 'L' to 'W':
        // - If it's next to an existing 'W' (or a newly converted 'W' that is next to an existing 'W'), it adds 2 points.
        // - If it's the first 'W' in a sequence (e.g., at the beginning of the string, or after an 'L' that remains 'L'), it adds 1 point.

        // The current `score` already reflects the points from original 'W's and 'W's from filled internal gaps.
        // Now we have `k` changes left. We can use them to convert 'L's at the ends.
        // Each 'L' converted to 'W' will add 1 point.
        // If it connects to an existing 'W' (or a previously converted 'L' that connected to an existing 'W'), it adds an additional 1 point.

        // Let's consider the 'L's at the end of the string (after last_W).
        // If we convert s[last_W+1] from 'L' to 'W', it connects to s[last_W] (which is 'W').
        // This adds 2 points.
        // If we convert s[last_W+2] from 'L' to 'W', and s[last_W+1] is now 'W', it adds 2 points.
        // So, converting 'L's after last_W adds 2 points per 'L'.
        int can_convert_trailing = std::min(k, trailing_Ls);
        score += 2 * can_convert_trailing;
        k -= can_convert_trailing;

        // Now consider 'L's at the beginning of the string (before first_W).
        // If we convert s[first_W-1] from 'L' to 'W', it connects to s[first_W] (which is 'W').
        // This adds 2 points.
        // If we convert s[first_W-2] from 'L' to 'W', and s[first_W-1] is now 'W', it adds 2 points.
        // This is true IF first_W is not 0.
        // If first_W is 0, then s[0] is 'W'.
        // If we convert s[0] from 'L' to 'W', it adds 1 point.
        // If we convert s[1] from 'L' to 'W' and s[0] is 'W', it adds 2 points.

        // The current `score` already includes 1 point for the first 'W' if `s[0]` was 'W'.
        // If `s[0]` was 'L' and we convert it to 'W', it adds 1 point.
        // If `s[0]` was 'W', and we convert `s[1]` from 'L' to 'W', it adds 2 points.
        // The logic for `score += 2 * gap_len` for internal gaps is correct.
        // The logic for `score += 2 * can_convert_trailing` is correct.

        // What about leading 'L's?
        // If `s[0]` is 'L' and we convert it to 'W', it adds 1 point.
        // If `s[0]` is 'W', and we convert `s[1]` from 'L' to 'W', it adds 2 points.
        // The `first_W` variable points to the first 'W' in the *original* string.
        // If `first_W` is 0, then `s[0]` was 'W'.
        // If `first_W > 0`, then `s[0]` was 'L'.
        // If `s[0]` was 'L' and we convert it, it adds 1 point.
        // If `s[0]` was 'W', and we convert `s[1]` (if it was 'L'), it adds 2 points.

        // The `score` variable already has points from original 'W's and internal gap 'W's.
        // The `k` variable is remaining changes.
        // We have `leading_Ls` and `trailing_Ls` (from original string).
        // `can_convert_trailing` already used `k` and added to score.
        // Now, `k` is even smaller.

        // The `score` calculation is tricky. Let's use a simpler approach.
        // 1. Calculate initial score.
        // 2. Identify all 'L' segments.
        // 3. Sort internal 'L' segments by length.
        // 4. Greedily fill internal 'L' segments. Each 'L' filled adds 2 points.
        // 5. Fill 'L' segments at ends. Each 'L' filled adds 2 points if it connects to an existing 'W'.
        //    If it's the very first 'L' being converted (and no 'W's before it), it adds 1 point.

        // Let's restart the score calculation logic.
        // `score` is the current score.
        // `k` is the remaining changes.

        // Case 1: All 'L's initially.
        if (initial_wins == 0) {
            if (k > 0) std::cout << 1 << "\n";
            else std::cout << 0 << "\n";
            continue;
        }

        // Case 2: Some 'W's initially.
        // Calculate initial score.
        score = 0;
        if (s[0] == 'W') score = 1;
        for (int i = 1; i < n; ++i) {
            if (s[i] == 'W') {
                if (s[i-1] == 'W') score += 2;
                else score += 1;
            }
        }

        // Find first and last 'W' in the original string.
        first_W = -1;
        last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        // Collect internal 'L' gap lengths.
        internal_gaps.clear();
        current_L_count = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_L_count++;
            } else { // s[i] == 'W'
                if (current_L_count > 0) {
                    internal_gaps.push_back(current_L_count);
                    current_L_count = 0;
                }
            }
        }
        std::sort(internal_gaps.begin(), internal_gaps.end());

        // Fill internal gaps greedily. Each 'L' converted adds 2 points.
        for (int gap_len : internal_gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                score += 2 * gap_len;
            } else {
                score += 2 * k;
                k = 0;
                break;
            }
        }

        // If k is still available, fill 'L's at the ends.
        // These 'L's are outside the [first_W, last_W] range.
        // They will connect to an existing 'W' (first_W or last_W).
        // Each 'L' converted adds 2 points.
        if (k > 0) {
            // Count 'L's before first_W
            int Ls_before_first_W = 0;
            for (int i = 0; i < first_W; ++i) {
                if (s[i] == 'L') Ls_before_first_W++;
            }
            // Count 'L's after last_W
            int Ls_after_last_W = 0;
            for (int i = last_W + 1; i < n; ++i) {
                if (s[i] == 'L') Ls_after_last_W++;
            }

            // Fill 'L's after last_W
            int convert_after = std::min(k, Ls_after_last_W);
            score += 2 * convert_after;
            k -= convert_after;

            // Fill 'L's before first_W
            int convert_before = std::min(k, Ls_before_first_W);
            score += 2 * convert_before;
            k -= convert_before;
        }

        std::cout << score << "\n";
    }
    return 0;
}

