// Function to find prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x is a divisor of p and x is not divisible by q.
        // This means we need to remove some prime factors from p such that the resulting number is no longer divisible by q.
        // To maximize x, we should remove as few factors as possible, and specifically,
        // for each prime factor f of q, we should try to reduce its power in p by just enough
        // so that p/f^k is no longer divisible by q.

        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);
        long long max_x = 1;

        for (const auto& q_factor_pair : q_factors) {
            long long f = q_factor_pair.first;
            // int q_exponent = q_factor_pair.second; // This is not directly used, we just need the prime factor f

            long long current_p = p;
            // Count how many times f divides p
            int p_exponent_f = 0;
            while (current_p > 0 && current_p % f == 0) {
                current_p /= f;
                p_exponent_f++;
            }

            // We need to find the largest divisor of p that is not divisible by q.
            // If we remove f from p (p_exponent_f - 1) times, the resulting number
            // p / f^(p_exponent_f - 1) will still be divisible by q if q has other prime factors
            // or if q is f itself.
            // We need to remove f from p until p is no longer divisible by q.
            // The smallest number of f's to remove is 1, but we might need to remove more.
            // The largest x will be p / f^k for some k >= 1.
            // We want to find the smallest k such that (p / f^k) % q != 0.
            // This is equivalent to finding the largest x = p / f^k such that x % q != 0.

            // Let's try to remove factors of f from p one by one until p is no longer divisible by q.
            // The candidate x will be p / f^k.
            // We want to maximize x, so we want to minimize k.
            // But we must ensure x % q != 0.
            // The strategy is: for each prime factor f of q, divide p by f until p is no longer divisible by q.
            // The largest such value will be the answer.

            long long temp_p = p;
            while (temp_p % q == 0) {
                temp_p /= f;
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

