#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate constraints based on s[i] == s[i+k]
    // For each i, s[i] must be equal to s[i+k], s[i+2k], etc.
    // This means all characters at indices i, i+k, i+2k, ... must be the same.
    // We can iterate through the first k characters and propagate their values.
    for (int i = 0; i < k; ++i) {
        char fixed_char = '?';
        // Find if any character in this "k-chain" is fixed
        for (int j = i; j < n; j += k) {
            if (s[j] != '?') {
                if (fixed_char == '?') {
                    fixed_char = s[j];
                } else if (fixed_char != s[j]) {
                    // Conflict: s[j] is different from an already fixed char in the same chain
                    std::cout << "NO\n";
                    return;
                }
            }
        }
        // If a fixed_char was found, apply it to all '?' in this chain
        if (fixed_char != '?') {
            for (int j = i; j < n; j += k) {
                s[j] = fixed_char;
            }
        }
    }

    // Step 2: Check if the first k characters can form a k-balanced substring
    // After propagation, the first k characters s[0...k-1] are either '0', '1', or '?'.
    // All other characters s[i] for i >= k are determined by s[i % k].
    // So, if s[0...k-1] can be made k-balanced, the entire string can be.
    // Count '0's, '1's, and '?'s in the first k characters.
    int zeros = 0;
    int ones = 0;
    int questions = 0;
    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            zeros++;
        } else if (s[i] == '1') {
            ones++;
        } else {
            questions++;
        }
    }

    // A k-balanced substring needs k/2 zeros and k/2 ones.
    // Check if it's possible to fill '?'s to meet this requirement.
    // The number of '0's must not exceed k/2.
    // The number of '1's must not exceed k/2.
    // The total count of '0's and '1's must be exactly k.
    if (zeros > k / 2 || ones > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // We need (k/2 - zeros) more '0's and (k/2 - ones) more '1's.
    // The sum of these needed counts must be equal to the number of '?'s.
    // (k/2 - zeros) + (k/2 - ones) = k - (zeros + ones)
    // This is exactly the number of '?'s.
    // So, if the individual counts don't exceed k/2, it's always possible.
    std::cout << "YES\n";
}

