#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val;
    if (b == 1) { // If b=1, then r must be 0, but r!=0. So no nice integers.
        sum_r_val = 0;
    } else {
        sum_r_val = (b - 1);
        sum_r_val = (sum_r_val * b) % (2 * MOD); // Multiply by b, then take modulo 2*MOD to handle division by 2
        // sum_r_val is now (b-1)*b. We need to divide by 2.
        // Since (b-1)*b is always even, we can divide by 2 directly.
        sum_r_val /= 2;
    }

    // Sum of (k*b + 1) for k from 1 to a
    // This is sum_k_term
    // sum_{k=1 to a} (k*b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_k_term;
    long long sum_k_val = (a % MOD);
    sum_k_val = (sum_k_val * ((a + 1) % MOD)) % MOD;
    // sum_k_val is now a*(a+1) mod MOD. We need to divide by 2.
    // Modular inverse of 2 modulo 10^9+7 is (10^9+7+1)/2 = 500000004
    long long inv2 = 500000004;
    sum_k_val = (sum_k_val * inv2) % MOD; // sum_k_val is now (a*(a+1)/2) % MOD

    long long term1 = (b % MOD * sum_k_val) % MOD; // b * (a*(a+1)/2) % MOD
    long long term2 = (a % MOD);                   // a % MOD
    sum_k_term = (term1 + term2) % MOD;

    // Total sum = (sum_r_val % MOD) * (sum_k_term % MOD)
    long long total_sum = (sum_r_val % MOD * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
