#include <deque>

long long solve() {
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    long long min_h = -1;
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
        if (min_h == -1 || h[i] < min_h) {
            min_h = h[i];
        }
    }

    if (n == 1) {
        return (h[0] + 1) / 2;
    }

    long long ans = min_h;

    std::vector<long long> current_h(n);
    for (int i = 0; i < n; ++i) {
        current_h[i] = h[i] - min_h;
    }

    long long max_len_odd = 0;
    long long max_len_even = 0;

    long long current_len_odd = 0;
    long long current_len_even = 0;

    for (int i = 0; i < n; ++i) {
        if (current_h[i] == 0) {
            current_len_odd = 0;
            current_len_even = 0;
        } else {
            if (current_h[i] % 2 == 1) { // odd height
                current_len_odd++;
                current_len_even = 0;
            } else { // even height
                current_len_even++;
                current_len_odd = 0;
            }
            max_len_odd = std::max(max_len_odd, current_len_odd);
            max_len_even = std::max(max_len_even, current_len_even);
        }
    }

    long long max_ops_odd = 0;
    if (max_len_odd > 0) {
        max_ops_odd = (max_len_odd + 1) / 2;
    }

    long long max_ops_even = 0;
    if (max_len_even > 0) {
        max_ops_even = max_len_even;
    }

    long long max_ops_isolated = 0;
    for (int i = 0; i < n; ++i) {
        max_ops_isolated = std::max(max_ops_isolated, (current_h[i] + 1) / 2);
    }

    long long max_ops_type1 = std::max(max_ops_odd, max_ops_isolated);
    long long max_ops_type2 = max_ops_even;

    long long low = 0, high = 2000000000LL; // Max possible operations for remaining blocks
    long long result_ops = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        long long needed_odd = mid;
        long long needed_even = mid / 2;

        if (needed_odd >= max_ops_type1 && needed_even >= max_ops_type2) {
            result_ops = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return ans + result_ops;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::cout << solve() << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operations 2 and 3: Do nothing
        std::cout << "1 1\n";
        std::cout << "0\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Handle n-1 elements from index 0 to n-2
    // For each a[i], we want to add a multiple of n to make it 0 mod n.
    // a[i] + b[i] = 0 (mod n)
    // b[i] = -a[i] (mod n)
    // b[i] = (-a[i] % n + n) % n
    // Then we add b[i] to a[i].
    // The length of this segment is n-1.
    // We need b[i] to be a multiple of n-1.
    // This is not the strategy.

    // Strategy:
    // 1. For elements a[0] to a[n-2]:
    //    Add (n - (a[i] % n + n) % n) to a[i].
    //    This makes a[i] a multiple of n.
    //    The amount added is (n - (a[i] % n + n) % n).
    //    This amount is between 0 and n-1.
    //    This is a multiple of (n-1) only if it's 0.
    //    This operation is on segment [1, n-1] (0-indexed). Length is n-1.
    //    We need to add a multiple of (n-1).
    //    Let's make a[i] become a multiple of n * (n-1).
    //    No, this is not right.

    // Correct strategy:
    // Operation 1: For elements a[0] to a[n-2] (segment [1, n-1] 1-indexed)
    // Length is n-1.
    // For each a[i] in this segment, we want to add x_i such that x_i is a multiple of (n-1)
    // AND (a[i] + x_i) is a multiple of n.
    // (a[i] + x_i) % n = 0
    // x_i % (n-1) = 0
    // Let x_i = k * (n-1).
    // (a[i] + k * (n-1)) % n = 0
    // (a[i] + k * (-1)) % n = 0  (since n-1 = -1 mod n)
    // (a[i] - k) % n = 0
    // k % n = a[i] % n
    // So, k = (a[i] % n + n) % n.
    // Then x_i = ((a[i] % n + n) % n) * (n-1).
    // Add x_i to a[i].
    // After this, a[i] will be a multiple of n.
    // And x_i is a multiple of (n-1).

    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder_n = (a[i] % n + n) % n;
        long long add_val = remainder_n * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // Operation 2: For the last element a[n-1] (segment [n, n] 1-indexed)
    // Length is 1.
    // We want to add x_{n-1} such that x_{n-1} is a multiple of 1
    // AND (a[n-1] + x_{n-1}) is a multiple of n.
    // x_{n-1} = (n - (a[n-1] % n + n) % n).
    // Add this to a[n-1].
    // After this, a[n-1] will also be a multiple of n.
    // All elements a[0]...a[n-1] are now multiples of n.

    std::cout << n << " " << n << "\n";
    long long remainder_n_last = (a[n - 1] % n + n) % n;
    long long add_val_last = (n - remainder_n_last) % n; // This makes a[n-1] a multiple of n
    std::cout << add_val_last << "\n";
    a[n - 1] += add_val_last;

    // Operation 3: For all elements a[0] to a[n-1] (segment [1, n] 1-indexed)
    // Length is n.
    // All a[i] are currently multiples of n.
    // We want to add x_i such that x_i is a multiple of n
    // AND (a[i] + x_i) = 0.
    // So, x_i = -a[i].
    // Since a[i] is a multiple of n, -a[i] is also a multiple of n.
    // This operation makes all elements zero.

    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

