    // Let x_j be the j-th bit of the input.
    // Let f_j(x_j) be the j-th bit of the final result.
    //
    // If x_j = 0, the final j-th bit is (val0 >> j) & 1.
    // If x_j = 1, the final j-th bit is (val1 >> j) & 1.
    //
    // We need to find A, B, C such that for any x_j:
    // ((x_j & A_j) | B_j) ^ C_j = f_j(x_j)
    //
    // Let's determine A_j, B_j, C_j for each bit j.
    //
    // Case 1: f_j(0) = 0, f_j(1) = 0
    //   This means the j-th bit is always 0.
    //   We can achieve this with: A_j=0, B_j=0, C_j=0  => ((x_j & 0) | 0) ^ 0 = 0
    //   Or: A_j=1, B_j=0, C_j=0  => ((x_j & 1) | 0) ^ 0 = x_j (not 0 for x_j=1)
    //   Or: A_j=0, B_j=1, C_j=1  => ((x_j & 0) | 1) ^ 1 = 1 ^ 1 = 0
    //   So, A_j=0, B_j=0, C_j=0 works.
    //   Also A_j=0, B_j=1, C_j=1 works.
    //   The simplest is A_j=1, B_j=0, C_j=1 (if we want to use XOR to flip)
    //   Or A_j=0, B_j=0, C_j=0 (if we want to use AND to zero out)
    //   Let's use A_j=0, B_j=0, C_j=0 for now.
    //   This means the j-th bit of A is 0, B is 0, C is 0.
    //   Or, more simply, we can use `& 0` for this bit.
    //   If f_j(0) = 0 and f_j(1) = 0, then the j-th bit of the result is always 0.
    //   This means the j-th bit of the final `&` constant should be 0.
    //   So, `A_j = 0`.
    //
    // Case 2: f_j(0) = 0, f_j(1) = 1
    //   This means the j-th bit is always x_j.
    //   We can achieve this with: A_j=1, B_j=0, C_j=0  => ((x_j & 1) | 0) ^ 0 = x_j
    //   So, `A_j = 1`.
    //
    // Case 3: f_j(0) = 1, f_j(1) = 0
    //   This means the j-th bit is always !x_j.
    //   We can achieve this with: A_j=1, B_j=0, C_j=1  => ((x_j & 1) | 0) ^ 1 = x_j ^ 1 = !x_j
    //   So, `A_j = 1`, `C_j = 1`.
    //
    // Case 4: f_j(0) = 1, f_j(1) = 1
    //   This means the j-th bit is always 1.
    //   We can achieve this with: A_j=0, B_j=1, C_j=0  => ((x_j & 0) | 1) ^ 0 = 1
    //   So, `B_j = 1`.

    // Let's construct the final A, B, C constants.
    // We want to find `&A`, `|B`, `^C` such that `((input & A) | B) ^ C`
    // produces the same result.
    //
    // For each bit j:
    // Let `bit0 = (val0 >> j) & 1` (result for input bit 0)
    // Let `bit1 = (val1 >> j) & 1` (result for input bit 1)
    //
    // If `bit0 == 0` and `bit1 == 0`:
    //   The j-th bit of the result is always 0.
    //   This can be achieved by `& 0` for this bit. So `A_j = 0`.
    //   Or by `| 1 ^ 1` for this bit. So `B_j = 1, C_j = 1`.
    //   To minimize operations, we prefer `& 0`.
    //   So, `A_j = 0`.
    //
    // If `bit0 == 0` and `bit1 == 1`:
    //   The j-th bit of the result is `x_j`.
    //   This can be achieved by `& 1` for this bit. So `A_j = 1`.
    //
    // If `bit0 == 1` and `bit1 == 0`:
    //   The j-th bit of the result is `!x_j`.
    //   This can be achieved by `& 1 ^ 1` for this bit. So `A_j = 1, C_j = 1`.
    //
    // If `bit0 == 1` and `bit1 == 1`:
    //   The j-th bit of the result is always 1.
    //   This can be achieved by `| 1` for this bit. So `B_j = 1`.

    // Let's define the constants for the three operations:
    // `and_const`: constant for the '&' operation
    // `or_const`: constant for the '|' operation
    // `xor_const`: constant for the '^' operation
    int and_const = 1023; // Initially all 1s, so & with it doesn't change bits
    int or_const = 0;     // Initially all 0s, so | with it doesn't change bits
    int xor_const = 0;    // Initially all 0s, so ^ with it doesn't change bits

    for (int j = 0; j < 10; ++j) {
        int bit0 = (val0 >> j) & 1;
        int bit1 = (val1 >> j) & 1;

        if (bit0 == 0 && bit1 == 0) {
            // Result bit is always 0.
            // To achieve this with `((x_j & A_j) | B_j) ^ C_j`:
            // We need A_j=0, B_j=0, C_j=0 (makes it 0)
            // Or A_j=0, B_j=1, C_j=1 (makes it 0)
            // Or A_j=1, B_j=0, C_j=1 (makes it !x_j, not always 0)
            // Or A_j=1, B_j=1, C_j=0 (makes it 1, not always 0)
            // The simplest is to set A_j=0.
            and_const &= ~(1 << j); // Set j-th bit of and_const to 0
        } else if (bit0 == 0 && bit1 == 1) {
            // Result bit is x_j.
            // To achieve this: A_j=1, B_j=0, C_j=0
            // and_const already has 1 at j-th bit (default 1023)
            // or_const already has 0 at j-th bit (default 0)
            // xor_const already has 0 at j-th bit (default 0)
            // No change needed for this bit in and_const, or_const, xor_const.
        } else if (bit0 == 1 && bit1 == 0) {
            // Result bit is !x_j.
            // To achieve this: A_j=1, B_j=0, C_j=1
            // and_const already has 1 at j-th bit (default 1023)
            // or_const already has 0 at j-th bit (default 0)
            xor_const |= (1 << j); // Set j-th bit of xor_const to 1
        } else { // bit0 == 1 && bit1 == 1
            // Result bit is always 1.
            // To achieve this: A_j=0, B_j=1, C_j=0 (makes it 1)
            // Or A_j=1, B_j=1, C_j=0 (makes it 1)
            // Or A_j=0, B_j=0, C_j=1 (makes it 1)
            // Or A_j=1, B_j=0, C_j=0 (makes it x_j, not always 1)
            // The simplest is to set B_j=1.
            or_const |= (1 << j); // Set j-th bit of or_const to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (and_const != 1023) { // If any bit of and_const is 0, we need an '&' operation
        result_ops.push_back({'&', and_const});
    }
    if (or_const != 0) { // If any bit of or_const is 1, we need an '|' operation
        result_ops.push_back({'|', or_const});
    }
    if (xor_const != 0) { // If any bit of xor_const is 1, we need an '^' operation
        result_ops.push_back({'^', xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for differences (strawberry - blueberry)
    // For a[i]=1, diff increases by 1. For a[i]=2, diff decreases by 1.
    std::vector<int> diff_left(n + 1, 0); // diff_left[k] = diff for jars 1 to k
    for (int i = 0; i < n; ++i) {
        diff_left[i + 1] = diff_left[i] + (a[i] == 1 ? 1 : -1);
    }

    std::vector<int> diff_right(n + 1, 0); // diff_right[k] = diff for jars 2n to 2n-k+1
    for (int i = 0; i < n; ++i) {
        diff_right[i + 1] = diff_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars taken from the left to achieve a certain difference
    // map: difference -> jars_taken_from_left
    std::map<int, int> min_left_jars;
    for (int k = 0; k <= n; ++k) {
        int current_diff = diff_left[k];
        if (min_left_jars.find(current_diff) == min_left_jars.end()) {
            min_left_jars[current_diff] = k;
        }
    }

    int min_total_eaten = 2 * n; // Max possible jars to eat

    // Iterate through possible number of jars taken from the right (k_right)
    for (int k_right = 0; k_right <= n; ++k_right) {
        int current_right_diff = diff_right[k_right];
        // We need diff_left_remaining + diff_right_remaining = 0
        // This means diff_left_remaining = -diff_right_remaining
        // The difference for the remaining jars on the left side is diff_left[n] - diff_left[k_left]
        // The difference for the remaining jars on the right side is diff_right[n] - diff_right[k_right]
        // So, (diff_left[n] - diff_left[k_left]) + (diff_right[n] - diff_right[k_right]) = 0
        // We are looking for diff_left[k_left] such that diff_left[k_left] = diff_left[n] + diff_right[n] - diff_right[k_right]

        int target_diff_left_taken = diff_left[n] + diff_right[n] - current_right_diff;

        if (min_left_jars.count(target_diff_left_taken)) {
            int k_left = min_left_jars[target_diff_left_taken];
            min_total_eaten = std::min(min_total_eaten, k_left + k_right);
        }
    }

    std::cout << min_total_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

