#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs_count = 0;

    // max_r_for_l[i] stores the maximum r (0-indexed) such that the substring s[i...r]
    // does NOT contain any bad triplet.
    // Initialize max_r_for_l[i] to n-1, meaning initially, any substring s[i...n-1]
    // is considered "good" until a bad triplet is found.
    std::vector<int> max_r_for_l(n);
    std::iota(max_r_for_l.begin(), max_r_for_l.end(), 0); // max_r_for_l[i] = i initially
    for (int i = 0; i < n; ++i) {
        max_r_for_l[i] = n - 1;
    }

    // Iterate through all possible x and k to find bad triplets
    // x is 0-indexed, k is 1-indexed
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet (x, x+k, x+2k)
                // This triplet starts at index x and ends at index x + 2k.
                // Any substring s[l...r] that contains this triplet is "bad".
                // That means, for any l <= x, and r >= x + 2k, the pair (l, r) is bad.

                // We are interested in finding the smallest r_prime such that
                // s[l...r_prime] contains a bad triplet.
                // For a given l, if max_r_for_l[l] is currently R, it means
                // s[l...R] is good. If we find a bad triplet (x, x+k, x+2k)
                // such that x >= l, then any r >= x+2k makes s[l...r] bad.
                // So, we must update max_r_for_l[l] to be at most x+2k-1.
                // More precisely, for any l_prime <= x, the substring s[l_prime...r]
                // becomes bad if r >= x + 2k.
                // So, for all l_prime from 0 to x, we must ensure that
                // max_r_for_l[l_prime] is at most x + 2k - 1.
                // We take the minimum of its current value and x + 2k - 1.
                int triplet_end_idx = x + 2 * k;
                for (int l_prime = 0; l_prime <= x; ++l_prime) {
                    max_r_for_l[l_prime] = std::min(max_r_for_l[l_prime], triplet_end_idx - 1);
                }
            }
        }
    }

    // Calculate the number of good pairs (l, r)
    // A pair (l, r) is good if l <= r <= max_r_for_l[l].
    // For each l (0-indexed), the number of good r's is max_r_for_l[l] - l + 1.
    long long good_pairs_count = 0;
    for (int l = 0; l < n; ++l) {
        if (max_r_for_l[l] >= l) { // Ensure r is not less than l
            good_pairs_count += (max_r_for_l[l] - l + 1);
        }
    }

    bad_pairs_count = total_pairs - good_pairs_count;

    std::cout << bad_pairs_count << std::endl;

    return 0;
}

