// Function to check if all required tracks can be covered within time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for required tracks p
    for (int i = 0; i < n; ++i) { // Iterate through each head
        if (p_idx == m) { // All required tracks have been covered
            return true;
        }

        long long current_head_pos = h[i];
        long long first_uncovered_p = p[p_idx];

        // If the current head cannot reach the first uncovered track,
        // it means this head cannot help cover it, and we need to move to the next head.
        // This is only true if first_uncovered_p is far to the left of current_head_pos.
        // If first_uncovered_p is to the right, this head might cover it.
        if (first_uncovered_p > current_head_pos + t) {
            // This head is too far left to cover first_uncovered_p, even moving right for 't' time.
            // This head cannot cover any of the remaining p_j tracks.
            // This case should ideally not happen if p_idx is advanced correctly.
            // It implies a previous head should have covered this.
            // Or, if this is the first head, then t is too small.
            continue;
        }

        // Determine the range this head can cover.
        // The head starts at current_head_pos.
        // It can move to [current_head_pos - t, current_head_pos + t].
        // The actual range covered depends on which direction it moves first.
        // If it moves left to L and then right to R, it covers [min(L, R, current_head_pos), max(L, R, current_head_pos)].
        // The time taken is max(abs(current_head_pos - L), abs(current_head_pos - R)).
        // This is equivalent to saying it covers a range [X, Y] such that
        // max(abs(current_head_pos - X), abs(current_head_pos - Y)) <= t.
        // This means X >= current_head_pos - t and Y <= current_head_pos + t.
        // And the total span Y - X must be <= t.
        // So, the head can cover any interval [L, R] such that:
        // 1. L >= current_head_pos - t
        // 2. R <= current_head_pos + t
        // 3. R - L <= t
        // The goal is to cover p[p_idx] and as many subsequent p_j as possible.

        // Option 1: Move right first, then potentially left.
        // The rightmost point it can reach is current_head_pos + t.
