    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // Cut s into s1 | s2. Form s2s1.
    // s2s1 must be a palindrome and s2s1 != s.
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
