    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick numbers of the form 2k where k is odd,
        // or more generally, numbers that are multiples of 2 but not multiples of each other.
        // A simple pattern that works is to pick numbers starting from 2*n + 2,
        // and then 2*n + 4, and so on, up to 4*n.
        // However, the example output suggests a different pattern.
        // For n=2, output is 6 4. (2*2+2, 2*2)
        // For n=3, output is 4 6 10. (2*2, 2*3, 2*5)
        // For n=4, output is 14 10 12 8. (2*7, 2*5, 2*6, 2*4)
        //
        // Let's try to pick numbers that are all even, to satisfy gcd(a,b) != 1.
        // To avoid a|b or b|a, we need numbers that are not multiples of each other.
        //
        // Consider numbers of the form 2 * k.
        // If we pick 2 * k1, 2 * k2, ..., 2 * kn.
        // Then gcd(2*ki, 2*kj) = 2 * gcd(ki, kj), which is always >= 2.
        // So the first condition is satisfied.
        //
        // Now we need to ensure that 2*ki does not divide 2*kj (i.e., ki does not divide kj)
        // and 2*kj does not divide 2*ki (i.e., kj does not divide ki).
        //
        // The example outputs suggest picking numbers from the upper half of the range [1, 4n].
        // For n=2, range [1, 8]. Output: 6 4.
        // For n=3, range [1, 12]. Output: 4 6 10.
        // For n=4, range [1, 16]. Output: 14 10 12 8.
        //
        // Let's try picking numbers starting from 4n and going downwards, skipping some.
        // If we pick 4n, 4n-2, 4n-4, ...
        // This would be 2 * (2n), 2 * (2n-1), 2 * (2n-2), ...
        // This sequence would have numbers like 2*(2n), 2*(n), 2*(n-1), etc.
        // For example, if n=4, 4n=16.
        // We need 4 numbers.
        // 16, 14, 12, 10.
        // Check:
        // 16, 14: gcd=2, no division. OK.
        // 16, 12: gcd=4, no division. OK.
        // 16, 10: gcd=2, no division. OK.
        // 14, 12: gcd=2, no division. OK.
        // 14, 10: gcd=2, no division. OK.
        // 12, 10: gcd=2, no division. OK.
        // All good. This sequence works.
        //
        // The numbers are 4n, 4n-2, 4n-4, ..., 4n - 2*(n-1).
        // This is 4n, 4n-2, ..., 2n+2.
        // These are n distinct even numbers.
        // All are even, so gcd is at least 2.
        // None divides another because they are all in a relatively small range [2n+2, 4n].
        // If a divides b, then b >= 2a.
        // Smallest number is 2n+2. Largest is 4n.
        // If (2n+2) divides some other number x in the set, then x must be at least 2*(2n+2) = 4n+4.
        // But the largest number in our set is 4n.
        // So no number in this set can divide another number in this set.
        //
        // This strategy seems robust.
        // The numbers are: 2n+2, 2n+4, ..., 4n.
        // There are (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n numbers.
        // All are distinct and within [1, 4n].

        for (int i = 0; i < n; ++i) {
            std::cout << 4 * n - 2 * i << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

