    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for crafting and buying coal = k + k * y.
        long long total_sticks_needed = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) additional sticks using trade offer 1.
        long long sticks_to_acquire_via_trade1 = total_sticks_needed - 1;

        // Each trade offer 1 (1 stick -> x sticks) effectively gives us (x - 1) sticks.
        // Number of trade 1 operations = ceil(sticks_to_acquire_via_trade1 / (x - 1)).
        long long num_trade1_operations = (sticks_to_acquire_via_trade1 + (x - 1) - 1) / (x - 1);

        // Total trades = number of trade 1 operations + number of trade 2 operations.
        // Number of trade 2 operations is simply k (to get k coal).
        long long total_trades = num_trade1_operations + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

