int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration = total_sum / k;
    std::vector<int> s_lengths;
    long long current_sum = 0;
    int current_length = 0;
    int posts_found = 0;

    for (int i = 0; i < n; ++i) {
        current_sum += a[i];
        current_length++;

        if (current_sum == target_duration) {
            s_lengths.push_back(current_length);
            current_sum = 0;
            current_length = 0;
            posts_found++;
        } else if (current_sum > target_duration) {
            // This segment exceeds target_duration, so no solution
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_found == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_lengths.size(); ++i) {
            std::cout << s_lengths[i] << (i == s_lengths.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be caught by current_sum > target_duration
        // or total_sum % k != 0, but as a safeguard.
        // It means we didn't form exactly k posts with the target duration.
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    if (a[0] == 1) {
        has_pos_one = true;
    } else if (a[0] == -1) {
        has_neg_one = true;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < 0) {
            has_neg_one = true;
        } else if (a[i] > 0) {
            has_pos_one = true;
        }

        if (a[i] == b[i]) {
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // a[i] > b[i], Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
