        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_R_pos = -1; // Represents cell 0
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After the loop, last_R_pos is the index of the last 'R' character.
        // The gap from the last 'R' to cell n+1 needs to be considered.
        // The length of the string is s.length(), so cell n+1 is at index s.length().
        max_gap = std::max(max_gap, (int)s.length() - last_R_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

