#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            int val;
            std::cin >> val;
            if (i == j) {
                continue;
            }
            if (val > max_val_in_row) {
                max_val_in_row = val;
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and no other element is n-1.
    // If all elements are n-1, it means n was not present in any min(p_i, p_j)
    // which implies n was one of the p_i values.
    // If p_i = n, then max_{j!=i} min(p_i, p_j) = max_{j!=i} p_j = n-1.
    // If p_i < n, then max_{j!=i} min(p_i, p_j) could be p_i or some p_j.
    // If p_i is not n, then there must be some p_k = n.
    // For that p_k = n, its corresponding max_val_in_row will be n-1.
    // So, there must be at least one n-1 in the computed p array.
    // If all computed p values are n-1, it means all p_i are n. This is impossible.
    // The problem guarantees a solution exists.
    // The only case where we need to change an n-1 to n is if all elements in p are n-1.
    // This happens if the original permutation contained n, and for all other elements p_j,
    // p_j < n. So, for the element p_k = n, its max_val_in_row would be n-1.
    // For any other element p_i < n, its max_val_in_row would be max(p_i, max_{j!=i,j!=k} p_j).
    // This max_val_in_row could be p_i or some p_j.
    // However, if p_i is not n, then max_{j!=i} min(p_i, p_j) will be at most p_i.
    // This is incorrect. max_{j!=i} min(p_i, p_j) can be larger than p_i if p_i is small.
    // Example: p = {1, 5, 4, 3, 2}. For p_0=1, max_{j!=0} min(1, p_j) = 1.
    // For p_1=5, max_{j!=1} min(5, p_j) = 4.
    // The logic is: if p_i is the largest element (n), then max_{j!=i} min(p_i, p_j) = max_{j!=i} p_j = n-1.
    // If p_i is not the largest element, then there is some p_k = n.
    // Then max_{j!=i} min(p_i, p_j) will include min(p_i, p_k) = p_i.
    // So, max_{j!=i} min(p_i, p_j) >= p_i.
    // Also, max_{j!=i} min(p_i, p_j) <= n-1 (since all p_j are at most n, and if p_i is not n, then n is somewhere else).
    // The only way for p[i] to be n-1 is if p[i] was n in the original permutation.
    // If there is exactly one element in p that is n-1, then that element corresponds to the original n.
    // If there are multiple elements that are n-1, it means some p_i < n also resulted in n-1.
    // This can happen if p_i is not n, but it is the second largest element (n-1).
    // Then max_{j!=i} min(p_i, p_j) = max(min(n-1, n), min(n-1, other_elements)) = max(n-1, other_elements) = n-1.
    // So, if p_i = n-1, its computed value is n-1.
    // If p_i = n, its computed value is n-1.
    // This means there will be at least two n-1s in the computed array if n > 2.
    // If n=2, p={1,2}. p_0=1 -> max(min(1,2))=1. p_1=2 -> max(min(2,1))=1. Both are 1.
    // So, if all elements in the computed p are n-1, it means the original permutation contained n.
    // We need to find one such element and change it to n.
    // The problem guarantees a solution.
    // The simplest approach is to find if n-1 is present in the computed p.
    // If it is not present, it means n was not in the original permutation, which is impossible.
    // If it is present, it means the element that was originally n (or n-1) resulted in n-1.
    // If all elements in p are n-1, then one of them must be n.
    // We can just pick the first one and change it to n.

    bool found_n_minus_1 = false;
    for (int val : p) {
        if (val == n - 1) {
            found_n_minus_1 = true;
            break;
        }
    }

    if (!found_n_minus_1) {
        // This case should not happen based on problem constraints (guaranteed solution).
        // But if it did, it would mean n was not present in any min(p_i, p_j)
        // which implies n was one of the p_i values, and all other p_j were smaller than n-1.
        // This would mean max_val_in_row for p_i=n would be n-1.
        // So, found_n_minus_1 must be true.
    }

    // If all elements in p are n-1, it means the original permutation contained n,
    // and for the element p_k = n, its max_val_in_row was n-1.
    // For any other element p_i < n, its max_val_in_row was also n-1.
    // This implies that for every p_i, max_{j!=i} min(p_i, p_j) = n-1.
    // This can only happen if n is present in the original permutation,
    // and for every p_i, there is some p_j such that min(p_i, p_j) = n-1.
    // This means either p_i = n-1 and p_j = n, or p_i = n and p_j = n-1.
    // If all computed values are n-1, it means one of the original values was n.
    // We need to change one of the n-1s to n.
    // The problem guarantees a solution, so this logic should be sound.
    // If there is at least one n-1, and we need to ensure n is in the output,
    // we can simply increment one of the n-1s to n.
    // If there are multiple n-1s, it doesn't matter which one we pick.
    // If there's only one n-1, that's the one.
    // If there are no n-1s, this implies an issue with the problem statement or my understanding.
    // But since it's guaranteed, we assume there's at least one n-1.

    // The simplest way to ensure n is in the output and the rest are correct
    // is to find the first occurrence of n-1 and change it to n.
    // This covers the case where all elements are n-1 (e.g., n=2, p={1,1} -> {2,1}).
    // And it covers the case where only one element is n-1 (e.g., n=3, p={1,2,2} -> {1,2,3}).
    // And it covers the case where multiple elements are n-1 (e.g., n=4, p={1,3,3,2} -> {1,4,3,2} or {1,3,4,2}).
    // The problem asks for *any* permutation.

    bool n_assigned = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n - 1 && !n_assigned) {
            p[i] = n;
            n_assigned = true;
        }
    }

    // If n was not assigned (meaning no n-1 was found), this implies an error in logic or problem statement.
    // Given the problem constraints, this should not happen.
    // If it did, it would mean all p[i] < n-1. This is impossible for a permutation of 1..n.
    // For example, if p_k = n, then max_{j!=k} min(p_k, p_j) = n-1. So n-1 must appear.

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

