    p[0] = q[0];
    used_numbers.insert(q[0]);

    // Fill in p_i for i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(p[i])) {
                // This should not happen if q_i are distinct and within [1,n]
                // and q_i > q_{i-1} implies q_i is a new value.
                // But as a safety check for permutation validity.
                possible = false;
                break;
            }
            used_numbers.insert(p[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some unused number less than q_i
            p[i] = -1; // Placeholder, will be filled later
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect available numbers
    std::vector<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        if (!used_numbers.count(i)) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort descending for greedy assignment

    int current_available_idx = 0;
    for (int i = 1; i < n; ++i) {
        if (p[i] == -1) { // This means q_i == q_{i-1}
            if (current_available_idx >= available_numbers.size()) {
                possible = false; // Not enough numbers to fill
                break;
            }
            int num_to_assign = available_numbers[current_available_idx];
            if (num_to_assign > q[i]) { // p_i must be <= q_i (which is q_{i-1})
                possible = false;
                break;
            }
            p[i] = num_to_assign;
            current_available_idx++;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

