    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // For each x[i], find the maximum right_ptr such that x[right_ptr] - x[i] <= d
        // Since x is sorted, right_ptr will only increase or stay the same.
        // This makes the overall complexity O(N).
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy the condition
        // x[k] - x[i] <= d.
        // We need to choose two points from the range (x[i], ..., x[right_ptr-1]).
        // The number of points available to choose from (excluding x[i]) is (right_ptr - 1) - (i + 1) + 1
        // which simplifies to right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the number of points strictly greater than x[i]
        // and less than or equal to x[i] + d.
        // If m < 2, we cannot choose two distinct points, so we add 0.
        // Otherwise, we can choose 2 points from these m points in m * (m - 1) / 2 ways.

        long long m = static_cast<long long>(right_ptr - 1 - i);
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

