void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This `i` marks the start of the first non-increasing segment from the right.
    // All elements from `i` to `n-1` are in non-decreasing order.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }

    // Now `i` is the first index from the right where a[i-1] > a[i] (if such exists).
    // If `i` is 0, the whole array is non-decreasing.
    // The suffix a[i...n-1] is non-decreasing.

    // From this `i`, we need to find the rightmost index `j` such that a[j] > a[j-1]
    // This `j` marks the start of the first non-decreasing segment from the right
    // that is *not* part of the initial non-decreasing suffix.
    // All elements from `j` to `i-1` are in non-increasing order.
    int j = i;
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }

    // The prefix to remove is of length `j`.
    // The remaining array `a[j...n-1]` is the candidate for a good array.
    // This logic correctly identifies the shortest prefix to remove.
    // For example, if a = [1, 3, 1, 4, 5, 3, 2]
    // n=7
    // i starts at 6.
    // a[5]=3, a[6]=2. a[5] > a[6]. So i becomes 6.
    // a[4]=5, a[5]=3. a[4] > a[5]. So i becomes 5.
    // a[3]=4, a[4]=5. a[3] < a[4]. Loop stops. i = 4.
    // Suffix a[4...6] = [5, 3, 2] is not non-decreasing.
    // The first loop finds the rightmost point where a[k-1] >= a[k] fails.
    // It should be:
    // i = n-1; while (i > 0 && a[i-1] >= a[i]) i--;
    // For [1, 3, 1, 4, 5, 3, 2]:
    // i=6, a[5]=3, a[6]=2. a[5] > a[6]. i=6.
    // i=5, a[4]=5, a[5]=3. a[4] > a[5]. i=5.
    // i=4, a[3]=4, a[4]=5. a[3] < a[4]. Loop stops. i=4.
    // So, a[4...6] = [5, 3, 2] is the suffix that starts non-decreasingly.
    // This means a[i...n-1] is the longest non-decreasing suffix.
    // For [1, 3, 1, 4, 5, 3, 2], i=4. Suffix is [5, 3, 2]. This is wrong.
    // The condition for the first loop should be `a[i-1] <= a[i]` to find the end of a non-decreasing sequence.
    // Let's re-evaluate the conditions.

    // The array `b` is good if it can be formed by taking elements from ends to make a non-decreasing `c`.
    // This implies `b` must have a structure like:
    // [decreasing part] [increasing part] [decreasing part]
    // Or more precisely, it must be a "bitonic" sequence if we consider the elements picked from left and right.
    // The elements picked from the left form an increasing sequence.
    // The elements picked from the right form an increasing sequence (when read from right to left).
    // The remaining elements in the middle must be greater than or equal to the last element picked from left
    // and greater than or equal to the last element picked from right.
    // This is equivalent to saying that the array must be of the form:
    // `X_1 >= X_2 >= ... >= X_k <= X_{k+1} <= ... <= X_m`
    // where `X_k` is the minimum element.
    // Or, it can be `X_1 <= X_2 <= ... <= X_k >= X_{k+1} >= ... >= X_m`
    // where `X_k` is the maximum element.
    // The problem statement example `b = [1, 2, 3, 4, 4, 2, 1]` is `increasing then decreasing`.
    // The elements are picked to form `c = [1, 1, 2, 2, 3, 4, 4]`.
    // This means the original array `b` must be "valley-shaped" or "mountain-shaped"
    // if we consider the elements that are *not* picked from the ends.
    // The elements that are picked from the ends to form a non-decreasing sequence `c`
    // must themselves be non-decreasing.
    // This means the original array `b` must be of the form:
    // `[decreasing_prefix] [increasing_suffix]`
    // Example: `[4, 3, 2, 1, 2, 3, 4]`
    // Or `[increasing_prefix] [decreasing_suffix]`
    // Example: `[1, 2, 3, 4, 3, 2, 1]`
    // The problem statement example `[1, 2, 3, 4, 4, 2, 1]` is of the second type.
    // The elements `1, 2, 3, 4, 4` are increasing/stable. Then `4, 2, 1` are decreasing.
    // The "good" array property means that the array `b` must be non-decreasing up to some point,
    // and then non-increasing from that point onwards.
    // i.e., `b_1 <= b_2 <= ... <= b_k >= b_{k+1} >= ... >= b_m`.
    // This is a "mountain" shape.

    // Let's find the longest suffix that is a "mountain" shape.
    // A mountain shape is `X_1 <= X_2 <= ... <= X_k >= X_{k+1} >= ... >= X_m`.
    // We need to find the smallest `k` such that `a[k...n-1]` is a mountain.

    // Find the end of the non-increasing part from the right.
    // `p1` will be the index of the peak or the start of the non-increasing part.
    // `a[p1...n-1]` is non-increasing.
    int p1 = n - 1;
    while (p1 > 0 && a[p1-1] >= a[p1]) { // Find first element from right that is smaller than its left neighbor
        p1--;
    }
    // After this loop, `a[p1...n-1]` is a non-increasing sequence.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // p1=6, a[5]=3, a[6]=2. a[5] > a[6]. p1=6.
    // p1=5, a[4]=5, a[5]=3. a[4] > a[5]. p1=5.
    // p1=4, a[3]=4, a[4]=5. a[3] < a[4]. Loop stops. p1=4.
    // So, `a[4...6]` is `[5, 3, 2]`. This is the non-increasing suffix.
    // The peak is `a[4]=5`.

    // Now, from `p1`, find the start of the non-decreasing part.
    // `p2` will be the index of the valley or the start of the non-decreasing part.
    // `a[p2...p1]` is non-decreasing.
    int p2 = p1;
    while (p2 > 0 && a[p2-1] <= a[p2]) { // Find first element from right that is larger than its left neighbor
        p2--;
    }
    // After this loop, `a[p2...p1]` is a non-decreasing sequence.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // p1=4.
    // p2=4, a[3]=4, a[4]=5. a[3] < a[4]. p2=4.
    // p2=3, a[2]=1, a[3]=4. a[2] < a[3]. p2=3.
    // p2=2, a[1]=3, a[2]=1. a[1] > a[2]. Loop stops. p2=2.
    // So, `a[2...4]` is `[1, 4, 5]`. This is the non-decreasing part leading to the peak.

    // The length of the prefix to erase is `p2`.
    // The remaining array `a[p2...n-1]` is `[1, 4, 5, 3, 2]`. This is a good array.
    // The length of the prefix to erase is `p2`.
    std::cout << p2 << std::endl;
}

