// Helper function to print "Ya" or "Tidak"
void print_bool(bool b) {
    if (b) {
        std::cout << "Ya";
    } else {
        std::cout << "Tidak";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        // Total number of toys
        long long total_toys = A + B + C + D;

        // If only one toy, that toy is the super toy.
        // The special box is determined by its initial category.
        if (total_toys == 1) {
            print_bool(A == 1);
            std::cout << " ";
            print_bool(B == 1);
            std::cout << " ";
            print_bool(C == 1);
            std::cout << " ";
            print_bool(D == 1);
            std::cout << "\n";
            continue;
        }

        // Possible outcomes for each box
        bool can_be_box1 = false; // (-inf, -1]
        bool can_be_box2 = false; // (-1, 0)
        bool can_be_box3 = false; // (0, 1)
        bool can_be_box4 = false; // [1, inf)

        // Case 0: No toys in Box 2 or Box 3 (no values between -1 and 1, excluding 0)
        // All values have magnitude >= 1.
        // The final product's magnitude will be >= 1.
        // The sign depends on the parity of A (number of negative values).
        if (B == 0 && C == 0) {
            if (A % 2 == 1) { // Odd number of negative values -> final product is negative
                can_be_box1 = true; // Magnitude >= 1, negative
            } else { // Even number of negative values -> final product is positive
                can_be_box4 = true; // Magnitude >= 1, positive
            }
        } else { // Case 1: There are toys in Box 2 or Box 3 (or both)
            // This means there are values with magnitude < 1.
            // It's possible to make the final product's magnitude < 1.
            // It's also possible to make the final product's magnitude >= 1.

            // Consider the sign of the final product:
            // The sign is determined by the parity of A + B (total negative numbers).
            // If (A + B) is odd, the final product is negative.
            // If (A + B) is even, the final product is positive.

            // Can be Box 1 (negative, magnitude >= 1):
            // Requires (A+B) to be odd.
            // Requires at least one toy with magnitude >= 1 (A > 0 or D > 0).
            // If A+B is odd:
            //   If A > 0 or D > 0:
            //     It's possible to make magnitude >= 1.
            //     Example: Multiply all B, C toys to get a value in (0,1).
            //     Then multiply with A or D toys.
            //     If A+B is odd, and A+D > 0, then can be Box 1.
            //     If A+B is odd, and A+D == 0, then all toys are B or C.
            //     If all toys are B or C, then the final product will have magnitude < 1.
            //     So, if A+B is odd AND (A > 0 or D > 0), then can be Box 1.
            if ((A + B) % 2 == 1 && (A > 0 || D > 0)) {
                can_be_box1 = true;
            }

            // Can be Box 2 (negative, magnitude < 1):
            // Requires (A+B) to be odd.
            // Requires at least one toy with magnitude < 1 (B > 0 or C > 0).
            // If A+B is odd:
            //   It's possible to make magnitude < 1.
            //   Example: Multiply all A, D toys to get a value >= 1.
            //   Then multiply with B or C toys.
            //   If A+B is odd, then can be Box 2.
            if ((A + B) % 2 == 1) {
                can_be_box2 = true;
            }

            // Can be Box 3 (positive, magnitude < 1):
            // Requires (A+B) to be even.
            // Requires at least one toy with magnitude < 1 (B > 0 or C > 0).
            // If A+B is even:
            //   It's possible to make magnitude < 1.
            //   If A+B is even, then can be Box 3.
            if ((A + B) % 2 == 0) {
                can_be_box3 = true;
            }

            // Can be Box 4 (positive, magnitude >= 1):
            // Requires (A+B) to be even.
            // Requires at least one toy with magnitude >= 1 (A > 0 or D > 0).
            // If A+B is even:
            //   If A > 0 or D > 0:
            //     It's possible to make magnitude >= 1.
            //     If A+B is even AND (A > 0 or D > 0), then can be Box 4.
            if ((A + B) % 2 == 0 && (A > 0 || D > 0)) {
                can_be_box4 = true;
            }
        }

        print_bool(can_be_box1);
        std::cout << " ";
        print_bool(can_be_box2);
        std::cout << " ";
        print_bool(can_be_box3);
        std::cout << " ";
        print_bool(can_be_box4);
        std::cout << "\n";
    }
    return 0;
}

