        a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a sub-array is a permutation
// `arr` is the original array
// `start_idx` is the 0-based starting index of the sub-array
// `length` is the length of the sub-array
// `max_val` is the maximum value expected in the permutation (i.e., `length`)
bool is_permutation(const std::vector<int>& arr, int start_idx, int length, int max_val) {
    if (length == 0) { // A permutation must have non-zero length
        return false;
    }
    if (max_val != length) { // The maximum value in a permutation of length L must be L
        return false;
    }

    std::vector<bool> seen(length + 1, false); // Use 1-based indexing for values
    int current_max = 0;

    for (int i = 0; i < length; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > length || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > current_max) {
            current_max = val;
        }
    }
    return current_max == length; // All numbers from 1 to length must be present
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int overall_max = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > overall_max) {
            overall_max = a[i];
        }
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix max and suffix max
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i-1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i+1], a[i]);
    }

    // Precompute prefix counts and suffix counts
    // `prefix_counts[i]` stores a bitmask or boolean array for elements 1 to `i+1`
    // `prefix_valid[i]` is true if `a[0...i]` is a permutation of length `i+1`
    std::vector<bool> prefix_valid(n, false);
    std::vector<bool> seen_prefix(n + 1, false); // For values 1 to n
    int current_prefix_max = 0;
    bool current_prefix_distinct = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] < 1 || a[i] > (i + 1) || seen_prefix[a[i]]) {
            current_prefix_distinct = false;
        }
        if (current_prefix_distinct) {
            seen_prefix[a[i]] = true;
            if (a[i] > current_prefix_max) {
                current_prefix_max = a[i];
            }
            if (current_prefix_max == (i + 1)) {
                prefix_valid[i] = true;
            }
        }
    }

    // `suffix_valid[i]` is true if `a[i...n-1]` is a permutation of length `n-i`
    std::vector<bool> suffix_valid(n, false);
    std::vector<bool> seen_suffix(n + 1, false); // For values 1 to n
    int current_suffix_max = 0;
    bool current_suffix_distinct = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        if (a[i] < 1 || a[i] > len || seen_suffix[a[i]]) {
            current_suffix_distinct = false;
        }
        if (current_suffix_distinct) {
            seen_suffix[a[i]] = true;
            if (a[i] > current_suffix_max) {
                current_suffix_max = a[i];
            }
            if (current_suffix_max == len) {
                suffix_valid[i] = true;
            }
        }
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Optimization: Check if max element in p1 is l1 and max element in p2 is l2
        // This is a necessary condition for a permutation
        if (prefix_max[l1-1] != l1 || suffix_max[l1] != l2) {
            continue;
        }

        // Use precomputed validity checks
        if (prefix_valid[l1-1] && suffix_valid[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

