int calculate_score(int n, const std::string& s) {
    if (n == 0) return 0;
    int score = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (i > 0 && s[i - 1] == 'W') {
                score += 2;
            } else {
                score += 1;
            }
        }
    }
    return score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            if (n == 0) { // Edge case for n=0, though constraints say n>=1
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + (n - 1) * 2 << "\n";
            }
            continue;
        }

        if (initial_wins == 0 && k == 0) { // No wins, no changes
            std::cout << 0 << "\n";
            continue;
        }

        if (initial_wins == 0 && k > 0) { // All 'L's initially, but can make changes
            std::cout << 1 + (k - 1) * 2 << "\n"; // Change k 'L's to 'W's, forming a block of k 'W's
            continue;
        }

        // General case: initial_wins > 0 and initial_wins + k < n
        // We have some 'W's and some 'L's, and we can't make all 'W's.
        // Strategy: Fill 'L' gaps between 'W's first, then extend from ends.

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        int current_gap_len = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_gap_len++;
            } else { // s[i] == 'W'
                if (current_gap_len > 0) {
                    gaps.push_back(current_gap_len);
                }
                current_gap_len = 0;
            }
        }
        if (current_gap_len > 0) {
            gaps.push_back(current_gap_len);
        }
        std::sort(gaps.begin(), gaps.end());

        int score = calculate_score(n, s);
        int changes_made = 0;

        for (int gap_len : gaps) {
            if (changes_made + gap_len <= k) {
                score += gap_len * 2 + 1; // Each L in gap becomes W, adds 2 points, plus 1 for connecting
                changes_made += gap_len;
            } else {
                break;
            }
        }

        int remaining_k = k - changes_made;

        // Extend from right (after last_W)
        for (int i = n - 1; i > last_W && remaining_k > 0; --i) {
            if (s[i] == 'L') {
                score += 2; // L becomes W, previous was W (last_W), so +2
                remaining_k--;
            }
        }

        // Extend from left (before first_W)
        for (int i = 0; i < first_W && remaining_k > 0; ++i) {
            if (s[i] == 'L') {
                score += 2; // L becomes W, next is W (first_W), so +2
                remaining_k--;
            }
        }

        std::cout << score << "\n";
    }
    return 0;
}

