void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        // We need to append elements b1, b2, ... such that
        // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor(b_i))

        // Let's try to append two elements.
        // Let b1 = current_xor_sum
        // New XOR sum X' = current_xor_sum ^ b1 = current_xor_sum ^ current_xor_sum = 0
        // New sum S' = current_sum + b1 = current_sum + current_xor_sum
        // We need S' = 2 * X' => current_sum + current_xor_sum = 2 * 0 = 0
        // This is generally not true since current_sum and current_xor_sum are non-negative.

        // Let's try to append two elements: b1 and b2.
        // We want the final XOR sum to be some value, say Y.
        // And the final sum to be 2Y.
        // Let's try to make the final XOR sum equal to current_xor_sum.
        // This means we need b1 ^ b2 = 0, so b1 = b2.
        // If we append b1 and b1, then new XOR sum is current_xor_sum ^ b1 ^ b1 = current_xor_sum.
        // New sum is current_sum + b1 + b1 = current_sum + 2*b1.
        // We need current_sum + 2*b1 = 2 * current_xor_sum.
        // 2*b1 = 2 * current_xor_sum - current_sum.
        // b1 = current_xor_sum - current_sum / 2.
        // This requires (2 * current_xor_sum - current_sum) to be non-negative and even.
        // The problem statement guarantees a solution exists with at most 3 elements.

        // A common strategy for these problems is to make the XOR sum 0.
        // If we append current_xor_sum, the new XOR sum becomes 0.
        // The new sum is current_sum + current_xor_sum.
        // The condition becomes current_sum + current_xor_sum = 2 * 0 = 0.
        // This is only true if current_sum and current_xor_sum are both 0, which is a trivial case.

        // Consider appending two elements: current_xor_sum and current_sum + current_xor_sum.
        // Let b1 = current_xor_sum.
        // Let b2 = current_sum + current_xor_sum.
        // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
        // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X' = 0 ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum.
        // New sum: S' = current_sum + b1 + b2
        // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S' = 2 * (current_sum + current_xor_sum).
        // We need S' = 2 * X'.
        // S' = 2 * (current_sum + current_xor_sum)
        // X' = current_sum + current_xor_sum
        // So, S' = 2 * X' is satisfied.
        // The elements to append are current_xor_sum and current_sum + current_xor_sum.
        // These are non-negative.
        // This strategy always works and uses 2 elements.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << "\n";
        std::cout << b1 << " " << b2 << "\n";
    }
}

