                // } else if (a[i] == '1' && b[i] == '0') {
                //     if (count01 > 0) { // There was a previous '0'->'1' mismatch
                //         cost += 1; // This resolves both the current 1->0 and one previous 0->1
                //         count01--;
                //     } else {
                //         count10++;
                //     }
                // }
                // After the loop, cost += count01 + count10; (for remaining flips)
                // This logic is also correct and simpler. It implicitly assumes that any swap between a 0->1 and 1->0 mismatch costs 1.
                // This is because a swap effectively moves a '1' from a position where it's unwanted to a position where it's needed.
                // This "transfer" of a '1' (or '0') costs 1.
                // The actual cost of a swap is |i-j|.
                // If we have a 0->1 at index i and a 1->0 at index j, we can swap a[i] and a[j].
                // This fixes both. Cost |i-j|.
                // Or we can flip a[i] and flip a[j]. Cost 2.
                // So we choose min(|i-j|, 2).
                // The greedy strategy of pairing up any 0->1 with any 1->0 and adding 1 to cost is equivalent to
                // saying that we can always find a pair that can be swapped for cost 1.
                // This is not true. The example 0101 -> 0011 has a swap cost of 1.
                // a = 0101, b = 0011
                // i=0: match
                // i=1: a[1]=1, b[1]=0. count10=1.
                // i=2: a[2]=0, b[2]=1. count01=1.
                // Now we have count10=1, count01=1.
                // The previous logic would say: cost += 1.
                // This is correct for this example.
                // Example 1: a = 100, b = 001
                // i=0: a[0]=1, b[0]=0. count10=1.
                // i=1: match
                // i=2: a[2]=0, b[2]=1. count01=1.
                // Now we have count10=1, count01=1.
                // The previous logic would say: cost += 1.
                // After loop: cost = 1. Remaining count10=0, count01=0. Total cost 1.
                // But the example output is 2.
                // This means the simple "cost += 1 for each pair" is wrong.
                // The simple "cost += 1 for each pair" is only correct if the swap cost is always 1.
                // The swap cost is |i-j|.
                // The problem is that we want to minimize sum of |i-j| for swaps, plus sum of 1 for flips.

                // Let's reconsider the problem.
                // We have positions where a[i] != b[i].
                // Type 1: a[i] = '0', b[i] = '1' (needs a '1')
                // Type 2: a[i] = '1', b[i] = '0' (needs a '0')

                // We can either:
                // 1. Flip a bit at i: cost 1. This fixes one mismatch.
                // 2. Swap a[i] and a[j]: cost |i-j|.
                //    If a[i] is Type 1 and a[j] is Type 2, then swapping a[i] and a[j] fixes both.
                //    a[i] becomes '1', a[j] becomes '0'.
                //    This costs |i-j| to fix two mismatches.
                //    Compared to 2 flips (cost 2), this is better if |i-j| < 2.
                //    If |i-j| = 1, swap costs 1.
                //    If |i-j| >= 2, 2 flips costs 2, which is better or equal.
                //    So, we only consider swaps for adjacent mismatches of different types.

                // This leads to the greedy strategy:
                // Iterate i from 0 to n-1.
                // If a[i] != b[i]:
                //   If a[i] == '0' and b[i] == '1': // Current is 0->1
                //     If i+1 < n and a[i+1] == '1' and b[i+1] == '0': // Next is 1->0
                //       // Adjacent mismatches of different types. Swap them.
                //       cost += 1; // Cost of swap |(i+1)-i| = 1
                //       i++; // Skip next position as it's now fixed
                //     Else:
                //       // Cannot find an adjacent 1->0 to swap with. Must flip this one.
                //       cost += 1;
                //   Else (a[i] == '1' and b[i] == '0'): // Current is 1->0
                //     If i+1 < n and a[i+1] == '0' and b[i+1] == '1': // Next is 0->1
                //       // Adjacent mismatches of different types. Swap them.
                //       cost += 1; // Cost of swap |(i+1)-i| = 1
                //       i++; // Skip next position as it's now fixed
                //     Else:
                //       // Cannot find an adjacent 0->1 to swap with. Must flip this one.
                //       cost += 1;

                // Let's test this strategy with examples:
                // Example 1:
                // n=3
                // a=100
                // b=001
                // i=0: a[0]=1, b[0]=0. Mismatch (1->0).
                //      i+1=1 < 3. a[1]=0, b[1]=0. Match.
                //      Cannot swap. Flip a[0]. cost += 1. cost = 1.
                // i=1: a[1]=0, b[1]=0. Match.
                // i=2: a[2]=0, b[2]=1. Mismatch (0->1).
                //      i+1=3 >= 3. No next position.
                //      Cannot swap. Flip a[2]. cost += 1. cost = 2.
                // Total cost = 2. This matches example output.

                // Example 2:
                // n=4
                // a=0101
                // b=0011
                // i=0: a[0]=0, b[0]=0. Match.
                // i=1: a[1]=1, b[1]=0. Mismatch (1->0).
                //      i+1=2 < 4. a[2]=0, b[2]=1. Mismatch (0->1).
                //      Adjacent mismatches of different types. Swap.
                //      cost += 1. cost = 1.
                //      i becomes 2 (will be incremented to 3 by loop).
                // i=3: a[3]=1, b[3]=1. Match.
                // Total cost = 1. This matches example output.

                // This greedy strategy seems correct.
                // The logic is that any swap between non-adjacent positions (cost >= 2) is never better than two flips (cost 2).
                // So we only need to consider adjacent swaps.
                // Any mismatch that cannot be resolved by an adjacent swap must be resolved by a flip.
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0' && b[i] == '1') { // a[i] is '0', needs to be '1'
                if (i + 1 < n && a[i+1] == '1' && b[i+1] == '0') { // a[i+1] is '1', needs to be '0'
                    // Found a '0'->'1' at i and '1'->'0' at i+1. Swap them.
                    cost += 1; // Cost of swap is |(i+1) - i| = 1
                    i++; // Skip i+1 as it's now fixed
                } else {
                    // Cannot find an adjacent '1'->'0' to swap with. Must flip this one.
                    cost += 1;
                }
            } else { // a[i] is '1', needs to be '0'
                if (i + 1 < n && a[i+1] == '0' && b[i+1] == '1') { // a[i+1] is '0', needs to be '1'
                    // Found a '1'->'0' at i and '0'->'1' at i+1. Swap them.
                    cost += 1; // Cost of swap is |(i+1) - i| = 1
                    i++; // Skip i+1 as it's now fixed
                } else {
                    // Cannot find an adjacent '0'->'1' to swap with. Must flip this one.
                    cost += 1;
                }
            }
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    int k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends with w_i = 1: they get one number, happiness is 2 * number.
    // To maximize, give them the largest available numbers.
    // These are the friends with the largest w_i values if w_i = 1.
    // Since w is sorted, these are at the end of w.
    // However, it's simpler to think about it this way:
    // The k largest numbers from 'a' will always be used as 'max_val' for some friend.
    // For friends with w_i = 1, their single number is both max and min.
    // For friends with w_i > 1, their max_val will be one of the largest numbers.
    // So, the k largest numbers from 'a' should be assigned as the 'max_val' for each of the k friends.
    // This means a[n-1], a[n-2], ..., a[n-k] will be the max_val for some friend.

    // Assign the k largest numbers from 'a' as the maximum for each friend.
    // These are a[n-1], a[n-2], ..., a[n-k].
    // The friends with w_i = 1 will get one of these numbers, and their happiness will be 2 * number.
    // The friends with w_i > 1 will get one of these numbers as their max_val.

    // Iterate through w from largest to smallest.
    // Friends with w_i = 1: give them the largest remaining numbers.
    // These are the friends at the end of the sorted 'w' array.
    int a_idx = n - 1; // Pointer to the largest available number in 'a'
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += a[a_idx] * 2;
            a_idx--;
        } else {
            // Break when w_i is no longer 1.
            // The remaining friends (with w_i > 1) will be handled next.
            break;
        }
    }

    // Friends with w_i > 1: they get w_i numbers.
    // Their happiness is max_val + min_val.
    // We've already assigned the largest available numbers (from a_idx down to n-k) as max_val for friends with w_i=1.
    // For friends with w_i > 1, their max_val will be one of the remaining largest numbers.
    // The k largest numbers from 'a' are a[n-1], a[n-2], ..., a[n-k].
    // We've used some of these for friends with w_i=1.
    // The remaining ones (from a_idx down to n-k) will be the max_val for friends with w_i > 1.
    // We want to pair these remaining largest numbers with the smallest available numbers.
    // The friends with larger w_i values need more numbers, so they will consume more of the smaller numbers.
    // The friends with smaller w_i values (but still > 1) will consume fewer smaller numbers.
    // To maximize sum of min_val, we should give the smallest available numbers to friends who need fewer numbers.
    // This means friends with smaller w_i (but > 1) should get the smallest numbers.
    // So, iterate through w from smallest to largest for w_i > 1.

    int current_a_smallest_idx = 0; // Pointer to the smallest available number in 'a'
    // Iterate through w from smallest to largest.
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            // This friend gets w[i] numbers.
            // Their max_val is one of the remaining largest numbers.
            // Their min_val should be one of the smallest available numbers.
            // The largest numbers are assigned from a_idx down to n-k.
            // The smallest numbers are assigned from current_a_smallest_idx upwards.

            // The max_val for this friend is a[a_idx].
            total_happiness += a[a_idx];
            a_idx--; // This largest number is used.

            // The min_val for this friend is a[current_a_smallest_idx].
            total_happiness += a[current_a_smallest_idx];
            // This friend consumes w[i] - 1 additional numbers (besides min_val and max_val).
            // These numbers are not used in happiness calculation, but they are consumed.
            // So, advance the smallest_idx by w[i] - 1.
            current_a_smallest_idx += (w[i] - 1);
        }
    }

    std::cout << total_happiness << std::endl;
}

