#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // First pass: Determine which w[j] must be 0
    // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Second pass: Verify if the constructed w can produce s
    // For each s[i], check if it matches the rule based on our w.
    // If s[i] is '1', then at least one of w[i-x] or w[i+x] must be '1'.
    // If s[i] is '0', then both w[i-x] and w[i+x] must be '0'. (This is already handled by the first pass)
    for (int i = 0; i < n; ++i) {
        char calculated_s_i = '0'; // Assume s_i is '0' by default

        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            calculated_s_i = '1';
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            calculated_s_i = '1';
        }

        if (calculated_s_i != s[i]) {
            std::cout << -1 << std::endl;
            return;
        }
    }

    std::cout << w << std::endl;
}

