#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            long long current_prime_factor = i;

            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= current_prime_factor;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    if (temp_q > 1) { // temp_q is now a prime factor itself
        long long current_prime_factor = temp_q;

        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= current_prime_factor;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

