    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_operations = 0;
    int consecutive_pairs = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }
        if (m > 0) {
            // Check for the chain starting with 1
            if (chain[0] == 1) {
                // Count consecutive pairs starting from 1
                int current_consecutive = 0;
                for (int j = 0; j < m; ++j) {
                    if (chain[j] == j + 1) {
                        current_consecutive++;
                    } else {
                        break;
                    }
                }
                consecutive_pairs = current_consecutive;
            }
        }
    }
    // Total operations to disassemble everything: n - k (each chain needs m-1 unnestings, sum of m is n, so sum of m-1 is n-k)
    // Total operations to assemble everything: n - 1 (n-1 nestings)
    // Total potential operations: (n - k) + (n - 1)
    // We save operations if we have existing correct nestings.
    // The 'consecutive_pairs' variable counts how many matryoshkas are correctly nested
    // starting from 1 (i.e., 1 in 2, 2 in 3, ..., (consecutive_pairs-1) in consecutive_pairs).
    // This means (consecutive_pairs - 1) nestings are already correct.
    // These (consecutive_pairs - 1) nestings do not need to be disassembled or reassembled.
    // So, we save (consecutive_pairs - 1) unnesting operations and (consecutive_pairs - 1) nesting operations.
    // The first matryoshka '1' is part of the 'consecutive_pairs' count, but it's not a nesting.
    // The actual number of correct nestings is `consecutive_pairs - 1`.
    // For example, if consecutive_pairs = 3 (1, 2, 3), then 1->2 and 2->3 are correct. That's 2 nestings.
    // The number of matryoshkas that are part of this initial correct segment is `consecutive_pairs`.
    // The number of matryoshkas that are NOT part of this initial correct segment is `n - consecutive_pairs`.
    // These `n - consecutive_pairs` matryoshkas must be taken out of their current chains (if any)
    // and then nested into the final chain.
    // Each of these `n - consecutive_pairs` matryoshkas (except the first one in its original chain)
    // needs to be unnested.
    // The number of unnesting operations for the parts that are NOT 1->2->...->consecutive_pairs:
    // Total matryoshkas not in the initial correct segment: n - consecutive_pairs.
    // These form `k-1` chains (if `consecutive_pairs > 0`) or `k` chains (if `consecutive_pairs == 0`).
    // The number of unnesting operations needed for these is `(n - consecutive_pairs) - (k - (consecutive_pairs > 0 ? 1 : 0))`.
    // This simplifies to `n - k - (consecutive_pairs - 1)`.
    // The number of nesting operations needed for these is `(n - consecutive_pairs) - 1`.
    // Total operations = (unnestings for non-correct part) + (nestings for non-correct part)
    // Total operations = (n - k - (consecutive_pairs - 1)) + (n - consecutive_pairs - 1)
    // Total operations = n - k - consecutive_pairs + 1 + n - consecutive_pairs - 1
    // Total operations = 2 * n - k - 2 * consecutive_pairs.

    // Let's re-evaluate.
    // Total matryoshkas: n
    // Total chains: k
    // Target: 1 -> 2 -> ... -> n
    // Number of matryoshkas that are correctly placed at the beginning: `consecutive_pairs`.
    // This means `1, 2, ..., consecutive_pairs` are already in the correct sequence.
    // So, `consecutive_pairs - 1` nestings are already correct (1 in 2, 2 in 3, ..., (consecutive_pairs-1) in consecutive_pairs).
    // These `consecutive_pairs - 1` nestings don't need to be touched.
    //
    // The remaining `n - consecutive_pairs` matryoshkas need to be processed.
    // These `n - consecutive_pairs` matryoshkas are distributed among `k` chains (or `k-1` if the first chain started with 1).
    //
    // Number of unnesting operations:
    // Each matryoshka that is nested in another matryoshka, and is NOT part of the `1->...->consecutive_pairs` segment,
    // must be unnested.
    // Total initial nestings: `n - k`.
    // Number of correct initial nestings: `consecutive_pairs - 1`.
    // So, number of unnestings needed: `(n - k) - (consecutive_pairs - 1)`.
    //
    // Number of nesting operations:
    // The final chain has `n - 1` nestings.
    // Number of correct initial nestings: `consecutive_pairs - 1`.
    // So, number of new nestings needed: `(n - 1) - (consecutive_pairs - 1)`.
    //
    // Total time = (unnestings needed) + (nestings needed)
    // Total time = `((n - k) - (consecutive_pairs - 1))` + `((n - 1) - (consecutive_pairs - 1))`
    // Total time = `n - k - consecutive_pairs + 1` + `n - 1 - consecutive_pairs + 1`
    // Total time = `2 * n - k - 2 * consecutive_pairs + 1`.

    total_operations = (long long)(n - k - (consecutive_pairs - 1)) + (long long)(n - 1 - (consecutive_pairs - 1));

    std::cout << total_operations << std::endl;

    return 0;
}

