#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate known characters based on s[i] == s[i+k]
    // This means s[i] must be equal to s[i+k], s[i+2k], etc.
    // And s[i] must be equal to s[i-k], s[i-2k], etc.
    // Effectively, all characters at indices i, i+k, i+2k, ... must be the same.
    // We can iterate through the first k characters and propagate their values.
    for (int i = 0; i < k; ++i) {
        char fixed_char = '?';
        // Find if any character in this "k-chain" is fixed
        for (int j = i; j < n; j += k) {
            if (s[j] != '?') {
                if (fixed_char == '?') {
                    fixed_char = s[j];
                } else if (fixed_char != s[j]) {
                    // Conflict: s[j] is '0' but fixed_char is '1', or vice-versa
                    std::cout << "NO\n";
                    return;
                }
            }
        }
        // If a fixed_char was found, apply it to all '?' in this chain
        if (fixed_char != '?') {
            for (int j = i; j < n; j += k) {
                s[j] = fixed_char;
            }
        }
    }

    // Step 2: Check if the first k characters can form a k-balanced prefix
    // After propagation, s[0...k-1] might still contain '?'
    // We need to count 0s, 1s, and '?'s in s[0...k-1]
    int count0 = 0;
    int count1 = 0;
    int count_q = 0; // count of '?'

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            count0++;
        } else if (s[i] == '1') {
            count1++;
        } else { // s[i] == '?'
            count_q++;
        }
    }

    // For the first k characters to be k-balanced, they must have k/2 zeros and k/2 ones.
    // We have count0 zeros, count1 ones, and count_q question marks.
    // We need to assign (k/2 - count0) zeros and (k/2 - count1) ones to the '?'s.
    // These counts must be non-negative and sum up to count_q.
    int needed0 = k / 2 - count0;
    int needed1 = k / 2 - count1;

    if (needed0 < 0 || needed1 < 0) {
        // Already too many 0s or 1s in the first k characters
        std::cout << "NO\n";
        return;
    }
    if (needed0 + needed1 != count_q) {
        // The number of '?'s is not exactly what's needed to balance
        // This case should ideally be covered by needed0 < 0 or needed1 < 0
        // if count0 + count1 > k/2 + k/2 = k.
        // But if count0 + count1 < k, then count_q = k - (count0 + count1).
        // needed0 + needed1 = k - count0 - count1 = count_q.
        // So this check is redundant if needed0 and needed1 are non-negative.
    }

    // If we reach here, it means:
    // 1. No conflicts during propagation (s[i] == s[i+k] is consistent).
    // 2. The first k characters can be made k-balanced by filling '?'s.
    // Since s[i] == s[i+k] must hold for all i, if the first k characters are k-balanced,
    // then all subsequent k-length substrings will also be k-balanced.
    // For example, s[k...2k-1] will have the same characters as s[0...k-1]
    // (after filling '?'s consistently), so it will also be k-balanced.

    std::cout << "YES\n";
}

