    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::vector<char> current_coloring(n);
        char last_digit_color1 = '0';
        char first_digit_color2 = '9' + 1; // Larger than any digit

        bool possible_pivot = true;
        for (int i = 0; i < n; ++i) {
            if (s[i] < (pivot_digit + '0')) {
                current_coloring[i] = '1';
                last_digit_color1 = std::max(last_digit_color1, s[i]);
            } else if (s[i] > (pivot_digit + '0')) {
                current_coloring[i] = '2';
                first_digit_color2 = std::min(first_digit_color2, s[i]);
            } else { // s[i] == pivot_digit
                // This digit can be either 1 or 2.
                // If it's less than last_digit_color1, it must be 2.
                // If it's greater than first_digit_color2, it must be 1.
                // Otherwise, we can choose.
                if (s[i] < last_digit_color1) {
                    current_coloring[i] = '2';
                    first_digit_color2 = std::min(first_digit_color2, s[i]);
                } else { // s[i] >= last_digit_color1
                    current_coloring[i] = '1';
                    last_digit_color1 = std::max(last_digit_color1, s[i]);
                }
            }
        }

        // Check if the coloring is valid
        // 1. Check if S1 is sorted
        char prev_d1 = '0';
        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '1') {
                if (s[i] < prev_d1) {
                    possible_pivot = false;
                    break;
                }
                prev_d1 = s[i];
            }
        }
        if (!possible_pivot) continue;

        // 2. Check if S2 is sorted
        char prev_d2 = '0';
        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '2') {
                if (s[i] < prev_d2) {
                    possible_pivot = false;
                    break;
                }
                prev_d2 = s[i];
            }
        }
        if (!possible_pivot) continue;

        // 3. Check if last_digit_color1 <= first_digit_color2
        // This is implicitly handled by the logic of assigning pivot_digit values.
        // If a digit `d` is assigned '1', then `d >= last_digit_color1` must hold.
        // If a digit `d` is assigned '2', then `d <= first_digit_color2` must hold.
        // The critical check is that `last_digit_color1 <= first_digit_color2`
        // where `last_digit_color1` is the maximum digit assigned '1' and
        // `first_digit_color2` is the minimum digit assigned '2'.
        // The way we constructed `last_digit_color1` and `first_digit_color2`
        // ensures this for the pivot_digit values.
        // For example, if we have `... 5 ... 3 ...` and pivot is 4.
        // 5 is '2', first_digit_color2 = 5.
        // 3 is '1', last_digit_color1 = 3.
        // If we have `... 3 ... 5 ...` and pivot is 4.
        // 3 is '1', last_digit_color1 = 3.
        // 5 is '2', first_digit_color2 = 5.
        // The logic for assigning pivot_digit values:
        // If s[i] == pivot_digit:
        //   If s[i] < last_digit_color1 (meaning a '1' digit before this one was larger than s[i]),
        //     then s[i] must be '2'. This ensures S1 remains sorted.
        //     And this s[i] becomes a candidate for first_digit_color2.
        //   Else (s[i] >= last_digit_color1),
        //     then s[i] can be '1'. This ensures S1 remains sorted.
        //     And this s[i] becomes a candidate for last_digit_color1.
        // This greedy assignment for pivot_digit values ensures that if a solution exists for this pivot,
        // this specific coloring will find it and satisfy the `last_digit_color1 <= first_digit_color2` condition.
        // The `last_digit_color1` and `first_digit_color2` variables track the actual max/min digits assigned.
        // If `last_digit_color1 > first_digit_color2` at the end, it means the combined sequence is not sorted.
        // This can happen if a digit `d_k` was colored '1' and `d_k > d_j` where `d_j` was colored '2'.
        // Our current logic for `s[i] == pivot_digit` tries to push `s[i]` to '1' if possible.
        // Let's re-verify the condition `last_digit_color1 <= first_digit_color2`.
        // `last_digit_color1` is the maximum digit value assigned '1'.
        // `first_digit_color2` is the minimum digit value assigned '2'.
        // If `last_digit_color1 > first_digit_color2`, then the combined sequence is not sorted.
        // This check is crucial.
        if (last_digit_color1 > first_digit_color2) {
            possible_pivot = false;
        }

        if (possible_pivot) {
            for (int i = 0; i < n; ++i) {
                result[i] = current_coloring[i];
            }
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long val = (dq.empty() ? 0 : L[dq.back()]);
        L[i] = val + 1;
        dq.push_back(i);
    }

    dq.clear();
    std::vector<long long> R(n);
    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long val = (dq.empty() ? 0 : R[dq.back()]);
        R[i] = val + 1;
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min({h[i], L[i], R[i]}));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    // Sum of k for 1 <= k <= a: a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = sum_k * ((MOD + 1) / 2) % MOD; // Multiply by inverse of 2 mod MOD

    // Sum of r for 1 <= r < b: (b - 1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = sum_r * ((MOD + 1) / 2) % MOD; // Multiply by inverse of 2 mod MOD

    // The total sum is sum_{k=1 to a} sum_{r=1 to b-1} (r * (k * b + 1))
    // = sum_{k=1 to a} sum_{r=1 to b-1} (k * b * r + r)
    // = sum_{k=1 to a} (k * b * sum_{r=1 to b-1} r + sum_{r=1 to b-1} r)
    // = sum_{k=1 to a} ((k * b + 1) * sum_{r=1 to b-1} r)
    // = (sum_{r=1 to b-1} r) * sum_{k=1 to a} (k * b + 1)
    // = (sum_{r=1 to b-1} r) * (b * sum_{k=1 to a} k + sum_{k=1 to a} 1)
    // = (sum_{r=1 to b-1} r) * (b * sum_{k=1 to a} k + a)

    long long term_k_b_plus_a = (b % MOD * sum_k) % MOD;
    term_k_b_plus_a = (term_k_b_plus_a + (a % MOD)) % MOD;

    long long total_sum = (sum_r * term_k_b_plus_a) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

