    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            // Chanek's turn
            if (n % 2 == 1) {
                // If N is odd, Chanek must take 1.
                chanek_coins += 1;
                n -= 1;
            } else {
                // N is even. Chanek has two choices: take 1 or take N/2.
                // If N is 2, taking 1 leaves 1 for opponent, taking N/2 leaves 1 for opponent. Both give 1 to Chanek.
                // If N is 4, taking 1 leaves 3. Opponent takes 1, leaves 2. Chanek takes 1, leaves 1. Opponent takes 1. Chanek: 1+1=2.
                // If N is 4, taking N/2=2 leaves 2. Opponent takes 1, leaves 1. Chanek takes 1. Chanek: 2+1=3.
                // So for N=4, Chanek takes N/2.
                //
                // The strategy is: if N is even, and N/2 is odd, taking N/2 is good because it forces the opponent to take 1.
                // If N is even, and N/2 is even, taking N/2 might be bad if the opponent can also take N/4.
                //
                // Consider the case where N is a power of 2 (e.g., 2, 4, 8, 16, ...).
                // If N = 2^k:
                // Chanek takes N/2 = 2^(k-1). Remaining N = 2^(k-1).
                // Opponent takes N/2 = 2^(k-2). Remaining N = 2^(k-2).
                // This continues until N=2.
                // Chanek takes 2^(k-1) + 2^(k-3) + ...
                // Opponent takes 2^(k-2) + 2^(k-4) + ...
                //
                // If N is even and N/2 is odd (e.g., N=2, 6, 10, 14, ...):
                // Chanek takes N/2. N becomes N/2 (odd).
                // Opponent must take 1. N becomes N/2 - 1 (even).
                // This seems like a good move for Chanek.
                //
                // If N is even and N/2 is even (e.g., N=4, 8, 12, 16, ...):
                // Chanek takes N/2. N becomes N/2 (even).
                // Opponent can also take N/4.
