        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val; // Update a[i] for subsequent operations
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] divisible by n
    // This operation will not affect a[0]...a[n-2] if n > 1.
    std::cout << n << " " << n << "\n";
    long long remainder_n_minus_1 = a[n - 1] % n;
    long long add_val_n_minus_1 = (n - remainder_n_minus_1) % n;
    std::cout << add_val_n_minus_1 << "\n";
    a[n - 1] += add_val_n_minus_1; // Update a[n-1]

