#include <iostream>
#include <vector>
#include <string>
#include <array>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we track what happens to 0 and 1.
    // state[bit_idx][0] = final value if initial bit was 0
    // state[bit_idx][1] = final value if initial bit was 1
    // Initially, if bit was 0, it's 0. If bit was 1, it's 1.
    std::array<std::array<int, 2>, 10> bit_states;
    for (int i = 0; i < 10; ++i) {
        bit_states[i][0] = 0;
        bit_states[i][1] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) { // Iterate through each bit position
            int bit_val = (val >> i) & 1; // Get the i-th bit of the constant 'val'

            if (op_char == '&') {
                bit_states[i][0] &= bit_val;
                bit_states[i][1] &= bit_val;
            } else if (op_char == '|') {
                bit_states[i][0] |= bit_val;
                bit_states[i][1] |= bit_val;
            } else if (op_char == '^') {
                bit_states[i][0] ^= bit_val;
                bit_states[i][1] ^= bit_val;
            }
        }
    }

    // Now, reconstruct the equivalent operations.
    // We need to find A, B, C such that:
    // (x & A | B) ^ C = final_result_for_x
    // Or, more generally, a sequence of at most 5 operations.

    // Let's find the combined effect on 0 and 1 for each bit.
    // For each bit 'i':
    // If input bit is 0, output bit is bit_states[i][0]
    // If input bit is 1, output bit is bit_states[i][1]

    // We can represent the final transformation for each bit 'i' as:
    // (input_bit_i & A_i | B_i) ^ C_i
    // Or, more simply, as a function f_i(input_bit_i).
    // There are 4 possible functions for a single bit:
    // 1. f(x) = 0 (always 0)
    // 2. f(x) = 1 (always 1)
    // 3. f(x) = x (identity)
    // 4. f(x) = !x (negation)

    // Let's determine which of these 4 functions each bit 'i' corresponds to.
    // And build the constants for the simplified operations.
    int final_and_mask = 1023; // All bits 1
    int final_or_mask = 0;     // All bits 0
    int final_xor_mask = 0;    // All bits 0

    for (int i = 0; i < 10; ++i) {
        int val_if_0 = bit_states[i][0];
        int val_if_1 = bit_states[i][1];

        if (val_if_0 == 0 && val_if_1 == 0) {
            // f(x) = 0. This means the bit is forced to 0.
            // To achieve this with (x & A | B) ^ C:
            // If A_i=0, then (x & 0 | B_i) ^ C_i = B_i ^ C_i.
            // We need B_i ^ C_i = 0. E.g., B_i=0, C_i=0.
            // So, A_i=0, B_i=0, C_i=0.
            // This means final_and_mask should have 0 at bit i.
            final_and_mask &= ~(1 << i);
            // final_or_mask and final_xor_mask remain unchanged for this bit.
        } else if (val_if_0 == 1 && val_if_1 == 1) {
            // f(x) = 1. This means the bit is forced to 1.
            // To achieve this with (x & A | B) ^ C:
            // If A_i=0, then (x & 0 | B_i) ^ C_i = B_i ^ C_i.
            // We need B_i ^ C_i = 1. E.g., B_i=1, C_i=0.
            // So, A_i=0, B_i=1, C_i=0.
            // This means final_and_mask should have 0 at bit i.
            // final_or_mask should have 1 at bit i.
            final_and_mask &= ~(1 << i);
            final_or_mask |= (1 << i);
            // final_xor_mask remains unchanged for this bit.
        } else if (val_if_0 == 0 && val_if_1 == 1) {
            // f(x) = x. Identity.
            // To achieve this with (x & A | B) ^ C:
            // If A_i=1, B_i=0, C_i=0, then (x & 1 | 0) ^ 0 = x.
            // So, A_i=1, B_i=0, C_i=0.
            // This means final_and_mask should have 1 at bit i.
            // final_or_mask and final_xor_mask remain unchanged for this bit.
            // (final_and_mask already has 1 at bit i by default)
        } else if (val_if_0 == 1 && val_if_1 == 0) {
            // f(x) = !x. Negation.
            // To achieve this with (x & A | B) ^ C:
            // If A_i=1, B_i=0, C_i=1, then (x & 1 | 0) ^ 1 = x ^ 1 = !x.
            // So, A_i=1, B_i=0, C_i=1.
            // This means final_and_mask should have 1 at bit i.
            // final_xor_mask should have 1 at bit i.
            // (final_and_mask already has 1 at bit i by default)
            final_xor_mask |= (1 << i);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit is forced to 0 or identity/negation
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit is forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit is negated
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    long long total_substrings = n * (n + 1) / 2;

    // Number of zeros
    long long num_zeros = n - m;

    // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
    // This is achieved by distributing the '0's as evenly as possible into blocks.
    // The '1's act as separators for these blocks of '0's.
    // With m '1's, there can be at most m+1 blocks of '0's.
    // For example, "0010100" has m=2, n=7. Zeros: 2, 1, 2. Total 3 blocks.
    // The optimal strategy is to place '1's such that the blocks of '0's are as short as possible.
    // This means distributing the 'n-m' zeros among 'm+1' potential gaps created by 'm' ones.
    // However, the 'm' ones themselves can be adjacent, reducing the number of gaps.
    // The key insight is that to minimize zero-only substrings, we want to make the blocks of zeros as small as possible.
    // This means we want to make the '1's as spread out as possible.
    // The optimal configuration for '1's is to place them such that they break up the '0's into roughly equal segments.
    // This means we have 'm' ones, and 'n-m' zeros.
    // The 'm' ones divide the string into 'm+1' potential segments for zeros.
    // For example, _ 1 _ 1 _ ... _ 1 _
    // Let k be the number of zeros in each block.
    // We have num_zeros zeros to distribute into m+1 blocks.
    // The number of blocks of zeros is m+1.
    // Let q = num_zeros / (m + 1) be the base length of each zero block.
    // Let r = num_zeros % (m + 1) be the number of blocks that get an extra zero.
    // So, r blocks will have length q+1, and (m+1-r) blocks will have length q.

    long long q = num_zeros / (m + 1);
    long long r = num_zeros % (m + 1);

    long long sum_zero_substrings = 0;
    // r blocks of length q+1
    sum_zero_substrings += r * (q + 1) * (q + 2) / 2;
    // (m+1-r) blocks of length q
    sum_zero_substrings += (m + 1 - r) * q * (q + 1) / 2;

    return total_substrings - sum_zero_substrings;
}

