    int initial_total_balance = 0;
    for (int x : a) {
        initial_total_balance += (x == 1 ? 1 : -1);
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible balances of jars eaten from the left
    // `bal_L` is the balance of jars `1` to `k_L` (jars eaten from left)
    for (auto const& [bal_L, k_L] : left_diff_map) {
        // If `k_L` jars are eaten from the left, their balance is `bal_L`.
        // The remaining jars are `k_L+1` to `2n-k_R`.
        // The balance of the remaining jars should be 0.
        // This means `initial_total_balance - bal_L - bal_R = 0`
        // So, `bal_R = initial_total_balance - bal_L`.
        int target_bal_R = initial_total_balance - bal_L;

        if (right_diff_map.count(target_bal_R)) {
            int k_R = right_diff_map[target_bal_R];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

