#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // Convert to 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks vertices currently in the graph

    // Iterate through the removal steps in reverse order
    // This means we are effectively adding vertices one by one
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" back to the graph

        active[k] = true; // Mark this vertex as active

        // Update shortest paths using the newly added vertex 'k'
        // Floyd-Warshall style update: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This must be done for all pairs (i, j) that are currently active.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;

                // Update paths that go through k
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After adding k and updating paths involving k,
        // we also need to consider paths between i and j that might now
        // use k as an intermediate vertex, where i and j were already active.
        // This is the standard Floyd-Warshall triple loop, but only for active vertices.
        // The previous loop (i,j through k) handles paths where k is an endpoint.
        // This loop (k through i,j) handles paths where k is an intermediate.
        // Combining them:
        // For the newly added vertex 'k', it can be an intermediate vertex for any pair (i, j)
        // where i, j are already active.
        // It can also be an endpoint for paths from/to other active vertices.
        // The standard Floyd-Warshall update order is k as the intermediate.
        // So, for each active i and j, update dist[i][j] using k.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // The above two loops are actually equivalent to the standard Floyd-Warshall update
        // if we consider 'k' as the new intermediate vertex.
        // The correct way to integrate a new vertex 'k' into an existing APSP solution
        // is to first update all paths involving 'k' as an endpoint, and then
        // use 'k' as an intermediate vertex for all other pairs.
        // A simpler way to think about it is that after 'k' becomes active,
        // it can be used as an intermediate vertex for any pair (i, j) of active vertices.
        // So, for all active i, j: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]).
        // This is what the second loop does. The first loop is actually redundant if the second is done correctly.
        // Let's re-evaluate the Floyd-Warshall update for adding a vertex.
        // When vertex 'k' is added, it can improve paths in three ways:
        // 1. Path from 'k' to 'j' (for any active 'j'): dist[k][j] = min(dist[k][j], dist[k][i] + dist[i][j]) for active 'i'.
        // 2. Path from 'i' to 'k' (for any active 'i'): dist[i][k] = min(dist[i][k], dist[i][j] + dist[j][k]) for active 'j'.
        // 3. Path from 'i' to 'j' (for any active 'i', 'j'): dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]).

        // The standard Floyd-Warshall algorithm iterates k as the intermediate vertex.
        // So, when we "add" vertex k, we perform the update:
        // for all active i:
        //   for all active j:
        //     dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This single loop structure correctly incorporates k as an intermediate.
        // It also implicitly updates paths where k is an endpoint if i or j is k.
        // Example: if i=k, then dist[k][j] = min(dist[k][j], dist[k][k] + dist[k][j]) which is dist[k][j] = min(dist[k][j], 0 + dist[k][j]), no change.
        // This is correct because dist[k][k] is 0.
        // So, the second loop is the correct one to use after marking active[k]=true.

        // Calculate the sum of shortest paths for all active pairs
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, before x_2, ..., before x_n)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);
    std::vector<int> next_a(n);

    // Calculate L[i]: length of consecutive 0s or 1s ending at i
    // L[i] is 0 if a[i] is different from a[i-1]
    // L[i] is L[i-1] + 1 if a[i] is same as a[i-1]
    // This is not quite right. L[i] should be the length of the block of a[i] values ending at i.
    // Let's re-evaluate L and R.
    // L[i] = length of block of a[i] values ending at i.
    // R[i] = length of block of a[i] values starting at i.

    // Calculate L
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 1;
        }
    }

    // Calculate R
    R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == a[i + 1]) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 1;
        }
    }

    int max_steps = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Find 0-blocks
            if (i > 0 && a[i - 1] == 1) { // Start of a 0-block preceded by 1
                int j = i;
                while (j < n && a[j] == 0) {
                    j++;
                }
                // Block of 0s from i to j-1
                if (j < n && a[j] == 1) { // 0-block surrounded by 1s
                    int len = j - i;
                    max_steps = std::max(max_steps, (len + 1) / 2);
                }
                i = j - 1; // Continue loop from end of this block
            }
        } else { // Find 1-blocks
            if (i > 0 && a[i - 1] == 0) { // Start of a 1-block preceded by 0
                int j = i;
                while (j < n && a[j] == 1) {
                    j++;
                }
                // Block of 1s from i to j-1
                if (j < n && a[j] == 0) { // 1-block surrounded by 0s
                    int len = j - i;
                    max_steps = std::max(max_steps, (len + 1) / 2);
                }
                i = j - 1; // Continue loop from end of this block
            }
        }
    }

    // Apply smoothing max_steps times to get the final sequence
    for (int k = 0; k < max_steps; ++k) {
        next_a[0] = a[0];
        next_a[n - 1] = a[n - 1];
        for (int i = 1; i < n - 1; ++i) {
            if (a[i - 1] == a[i + 1]) {
                next_a[i] = a[i - 1];
            } else {
                next_a[i] = a[i];
            }
        }
        a = next_a;
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

