        // This is max(|n|, |m|) if only diagonal moves were allowed,
        // but since straight moves are also allowed, it's still max(|n|, |m|)
        // because we can always make |n| diagonal moves and then |m|-|n| straight moves.
        // For example, n diagonal moves to (n,n), then m-n straight moves to (n,m).
        // The minimum number of moves is m.
        // If k < m, it's impossible to reach (n, m).
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        // After m moves, we can reach (n, m) using n diagonal moves and m-n straight moves.
        // The remaining k - m moves must be "wasted" by moving back and forth.
        // Each "wasted" move must be paired with another move to cancel out its effect on the final position.
        // For example, (1,0) then (-1,0) or (1,1) then (-1,-1).
        // Each pair of such moves consumes 2 moves and results in no net change in position.
        // So, k - m must be an even number.
        // If (k - m) is odd, it's impossible to reach (n, m) in exactly k moves.
        if ((k - m) % 2 != 0) {
