    // We want to find the smallest r_0 for each l_0 such that s[l_0...r_0] contains a bad triplet.
    // Let min_r_with_triplet[l_0] be this value.
    // If no such r_0 exists, it can be n.
    // The number of valid pairs (l_0, r_0) for a given l_0 is (n - min_r_with_triplet[l_0] + 1).
    // The total number of valid pairs is sum over l_0 of (n - min_r_with_triplet[l_0] + 1).

    // Let's find the minimum rightmost index (0-indexed) for each starting index (0-indexed)
    // that forms a bad triplet.
    // min_bad_r[i] = minimum r_0 such that s[i...r_0] contains a bad triplet.
    // If no bad triplet starts at or after i, and ends at or before r_0, then min_bad_r[i] = n.
    std::vector<int> min_bad_r(n, n);

    // Iterate through all possible starting positions i (0-indexed)
    for (int i = 0; i < n; ++i) {
        // Iterate through all possible step sizes k
        // The condition is i + 2k < n
        // So 2k < n - i
        // k < (n - i) / 2
        // k can be at most (n - i - 1) / 2
        // k must be at least 1
        for (int k = 1; i + 2 * k < n; ++k) {
            if (s[i] == s[i + k] && s[i + k] == s[i + 2 * k]) {
                // Found a bad triplet starting at i with step k.
                // The rightmost index involved is i + 2k.
                // This means any substring s[l_0...r_0] where l_0 <= i and r_0 >= i + 2k
                // contains this bad triplet.
                // We want to find the minimum r_0 for each l_0.
                // For l_0 = i, the minimum r_0 is i + 2k.
                // For l_0 < i, the minimum r_0 is also i + 2k.
                // So, for all l_0 from 0 to i, we can update their min_bad_r.
                // However, we need to be careful.
                // min_bad_r[l_0] should be the minimum r_0 such that *some* bad triplet
                // (x, k_val) exists with l_0 <= x and r_0 >= x + 2*k_val.
                // This means min_bad_r[l_0] = min_{x >= l_0} (x + 2*k_val for some k_val).

                // A simpler approach:
                // Let `first_bad_r[i]` be the smallest `r` such that `s[i...r]` contains a bad triplet.
                // If `s[x] = s[x+k] = s[x+2k]`, then for any `l <= x`, the substring `s[l...x+2k]` contains this triplet.
                // So, for each `l` from `0` to `x`, `min_bad_r[l]` can be at most `x+2k`.
                // We want `min_bad_r[l] = min(min_bad_r[l], x+2k)`.
                // This update needs to be done for all `l` from `0` to `i`.
                // This is an O(N^3) approach if done naively.

                // Optimization:
                // The `min_bad_r` array will be non-decreasing.
                // `min_bad_r[l] <= min_bad_r[l+1]`.
                // If we find a triplet `(i, k)` ending at `i+2k`, then for all `j <= i`,
                // `min_bad_r[j]` can be updated to `min(min_bad_r[j], i+2k)`.
                // This means `min_bad_r[0] = min(min_bad_r[0], i+2k)`,
                // `min_bad_r[1] = min(min_bad_r[1], i+2k)`, ...,
                // `min_bad_r[i] = min(min_bad_r[i], i+2k)`.
                // Since `min_bad_r` is non-decreasing, if `min_bad_r[i]` is updated to `val`,
                // then `min_bad_r[i-1]` might also be updated to `val` if `min_bad_r[i-1] > val`.
                // This suggests iterating `l` downwards from `i`.

                int current_bad_r = i + 2 * k;
                for (int l = i; l >= 0; --l) {
                    if (min_bad_r[l] > current_bad_r) {
                        min_bad_r[l] = current_bad_r;
                    } else {
                        // Since min_bad_r is non-decreasing, if min_bad_r[l] <= current_bad_r,
                        // then min_bad_r[l-1] <= min_bad_r[l] <= current_bad_r,
                        // so no further updates are needed for smaller l.
                        break;
                    }
                }
            }
        }
    }

    // Calculate the total number of valid (l, r) pairs.
    // For each l_0 (0-indexed), the valid r_0 values are from min_bad_r[l_0] to n-1.
    // The number of such r_0 values is (n - 1) - min_bad_r[l_0] + 1 = n - min_bad_r[l_0].
    long long count = 0;
    for (int l = 0; l < n; ++l) {
        count += (n - min_bad_r[l]);
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks p
    int h_idx = 0; // Current index for heads h

    while (p_idx < m) {
        if (h_idx >= n) {
            return false; // No more heads to cover remaining tracks
        }

        // Find the first head that can potentially cover p[p_idx]
        // A head h[h_idx] can cover p[p_idx] if h[h_idx] is within [p[p_idx] - t, p[p_idx] + t]
        // Or, more precisely, if p[p_idx] is within [h[h_idx] - t, h[h_idx] + t]
        // This means abs(h[h_idx] - p[p_idx]) <= t
        // If h[h_idx] is too far to the left (h[h_idx] + t < p[p_idx]), this head cannot cover p[p_idx]
        // We need to advance h_idx until we find a head that can reach p[p_idx]
        // or a head that is to the right of p[p_idx] - t.
        while (h_idx < n && h[h_idx] + t < p[p_idx]) {
            h_idx++;
        }

        if (h_idx >= n) {
            return false; // No head can reach p[p_idx]
        }

        // Now h[h_idx] is the first head such that h[h_idx] + t >= p[p_idx].
        // This head can cover tracks up to h[h_idx] + t.
        // It can also cover tracks down to h[h_idx] - t.
        // We want to use this head to cover as many subsequent p_j tracks as possible.
        long long current_head_reach_left = h[h_idx] - t;
        long long current_head_reach_right = h[h_idx] + t;

        // If p[p_idx] is to the left of current_head_reach_left, this head cannot cover p[p_idx].
        // This should not happen if the previous while loop was correct, as h[h_idx] + t >= p[p_idx]
        // and h[h_idx] is increasing.
        // The only case is if p[p_idx] is too far left for *any* head.
        // But we already checked h[h_idx] + t < p[p_idx] for previous heads.
        // If p[p_idx] is not covered by h[h_idx], it means p[p_idx] < current_head_reach_left.
        // In this case, we need to move to the next head.
        if (p[p_idx] < current_head_reach_left) {
            h_idx++; // This head cannot cover p[p_idx], try next head
            continue; // Re-evaluate with the new h_idx
        }

        // This head h[h_idx] can cover p[p_idx].
        // Now, find how many subsequent p_j tracks this head can cover.
        // It can cover all p_k such that p_k <= current_head_reach_right.
        while (p_idx < m && p[p_idx] <= current_head_reach_right) {
            p_idx++;
        }
        h_idx++; // Move to the next head for the remaining tracks
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max p_i) - 1 (min h_i) + 10^10 (max t)
                                    // A safe upper bound is 2 * 10^10.
                                    // Max p_i is 10^10, min h_i is 1. Max diff is 10^10.
                                    // If n=1, m=1, h={1}, p={10^10}, t = 10^10 - 1.
                                    // If n=1, m=2, h={10^10/2}, p={1, 10^10}, t = 10^10/2.
                                    // A single head needs to cover a range of 10^10.
                                    // So t can be up to 10^10. 2 * 10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

