int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        std::sort(a.begin(), a.end());

        long long min_val = a[0];
        long long operations = 0;

        // We can only add a[0] to other piles a[j] where j > 0.
        // For each such pile a[j], we can add a[0] to it multiple times
        // until a[j] + a[0] > k.
        for (int i = 1; i < n; ++i) {
            // Calculate how many times a[0] can be added to a[i]
            // without exceeding k.
            // a[i] + count * a[0] <= k
            // count * a[0] <= k - a[i]
            // count <= (k - a[i]) / a[0]
            if (min_val > 0) { // To prevent division by zero, though problem constraints say a_i >= 1
                operations += (k - a[i]) / min_val;
            }
        }
        std::cout << operations << "\n";
    }
    return 0;
}

