    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for coal and crafting = k * y + k.
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks
        // using the first trade offer: 1 stick -> x sticks.
        // Each such trade effectively gives us (x - 1) new sticks.
        long long sticks_to_generate = total_sticks_required - 1;

        // Number of stick-generating trades needed:
        // (sticks_to_generate + (x - 1) - 1) / (x - 1)
        // This is equivalent to ceil(sticks_to_generate / (x - 1))
        long long num_stick_trades = (sticks_to_generate + (x - 1) - 1) / (x - 1);

        // Total trades = number of stick-generating trades + number of coal-buying trades.
        // Number of coal-buying trades is k (since we need k coal, and each trade gives 1 coal).
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

