        // The problem states "If there are multiple answers, print any of them."
        // So, the strategy of printing 2n+2, 2n+4, ..., 4n is correct and simple.

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (n + 1 + i) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

