        std::string s, t;
        std::cin >> s >> t;

        bool possible = false;
        // Iterate through all characters 'a' to 'z'
        // If any character 'c' exists in both s and t,
        // then it's possible to make both strings equal to 'c...c'
        // by propagating 'c' throughout s and t.
        // For example, if 'a' is in s and 'a' is in t:
        // Find first 'a' in s at index i. Propagate s[i] to s[i-1], s[i-2]...s[0].
        // Then propagate s[i] to s[i+1], s[i+2]...s[N-1].
        // Now s is all 'a's. Do the same for t.
        // Thus, s and t can both be transformed into a string of all 'a's.

        // A more direct check:
        // If there is at least one common character between s and t,
        // then it's possible.
        // Example: s="xabb", t="aabx"
        // 'a' is in s, 'a' is in t. YES.
        // s can become "aaaa", t can become "aaaa".

        // Example: s="a", t="z"
        // No common characters. NO.

        // The operation allows any character to propagate to its neighbors.
        // If a character 'c' exists anywhere in string S, S can be transformed into "ccc...c".
        // If a character 'c' exists anywhere in string T, T can be transformed into "ccc...c".
        // Therefore, if there is *any* character 'c' that exists in *both* S and T,
        // then S can be transformed into "ccc...c" and T can be transformed into "ccc...c".
        // Since they both become the same string, the answer is YES.
        // If there is no common character between S and T, then they cannot be made equal.
        // Why? Because any character that exists in S can be propagated throughout S.
        // Any character that exists in T can be propagated throughout T.
        // If S and T are to become equal, say to string X, then X must be composed of characters
        // that were originally present in S, and also originally present in T.
        // The simplest form of X would be a string of all identical characters, e.g., "aaaaa".
        // If S becomes "aaaaa", it means 'a' was present in S.
        // If T becomes "aaaaa", it means 'a' was present in T.
        // So, if they can be made equal, there must be at least one character common to both.

        std::vector<bool> s_chars(26, false);
        for (char c : s) {
            s_chars[c - 'a'] = true;
        }

        for (char c : t) {
            if (s_chars[c - 'a']) {
                possible = true;
                break;
            }
        }

        if (possible) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }
    return 0;
}

