void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position.
        // The flags has_one and has_minus_one are updated based on elements a[0]...a[i-1]
        // For the next iteration (i+1), we need to know if a 1 or -1 exists in a[0]...a[i]
        // The current logic correctly uses the flags based on elements *before* the current index i.
        // The flags `has_one` and `has_minus_one` are cumulative for elements a[0]...a[i-1].
        // This is correct because an element a_j can only be modified by a_i where i < j.
    }

    std::cout << "YES\n";
}

