#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from stdio and disables synchronization.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // Since we process from right to left, we can read into a vector
        // and then iterate backwards, or read into a vector and then
        // access elements from right to left.
        // Given n can be up to 150000, a vector is appropriate.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        int bad_prices_count = 0;
        if (n <= 1) {
            // If there's 0 or 1 day, no price can be "bad"
            // because there's no later day with a lower price.
            std::cout << 0 << "\n";
            continue;
        }

        // Initialize min_price_so_far with the price of the last day.
        // The last day's price can never be bad.
        int min_price_so_far = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // For each day i, we compare its price a[i] with the minimum price
        // encountered so far from days i+1 to n-1.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_price_so_far) {
                // If the current day's price is greater than the minimum
                // price found in any subsequent day, then this price is bad.
                bad_prices_count++;
            } else {
                // If the current day's price is not bad, it means it's
                // less than or equal to min_price_so_far.
                // This price might become the new minimum for days before it.
                min_price_so_far = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

