int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate differences up to k

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers
    // For example, if k=4, we want differences 4, 3, 2, 1.
    // We use numbers 1, 2, 3, 4, 5.
    // 1, 5 (diff 4)
    // 5, 2 (diff 3)
    // 2, 4 (diff 2)
    // 4, 3 (diff 1)
    // The sequence generated is 1, 5, 2, 4, 3.
    // The numbers used are 1 to k+1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers are k+2, k+3, ..., n.
    // To ensure no new distinct differences are introduced (or only 1 if k=0, but k>=1),
    // we append them in increasing order.
    // The difference |p_k - p_{k+1}| will be 1 if p_k is the last number from the alternating sequence
    // and p_{k+1} is the first number from the increasing sequence.
    // Example: n=5, k=2.
    // p[0]=1, left=2
    // p[1]=3, right=2
    // p[2]=2, left=3
    // Sequence so far: 1 3 2. Numbers used: 1, 2, 3.
    // Remaining numbers: 4, 5.
    // Append 4, 5.
    // Final sequence: 1 3 2 4 5.
    // Differences: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1.
    // Distinct differences: {1, 2}. Count = 2. This works.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

