void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1. min is 1, max is 1. So m=1 is always beautiful.
        if (m == 1) {
            result += '1';
            continue;
        }

        // For m > 1, we are considering adding 'm' to the current segment.
        // The number 'm' is at pos[m].
        // We need to expand the current segment [current_min_idx, current_max_idx]
        // to include pos[m].
        // The new segment will span from min(current_min_idx, pos[m])
        // to max(current_max_idx, pos[m]).
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // satisfies the conditions for 'm' to be beautiful.
        // 1. The length of the segment must be 'm'.
        //    Length = current_max_idx - current_min_idx + 1.
        // 2. The minimum value in the segment must be 1. (This is implicitly handled
        //    because we always expand from 1, and only consider values up to m).
        // 3. The maximum value in the segment must be 'm'. (This is also implicitly
        //    handled by our expansion strategy, as we are building up from 1 to m).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

