                                        // Specifically, if n_val is 2^32-1, then n_val * 2 + 1 will be 2^33-1, which is too large.
                                        // So, if n_val is 2^31-1, the next n_val will be 2^32-1. Its cost is fine.
                                        // If n_val is 2^32-1, the next n_val will be 2^33-1. Its cost will overflow.
                                        // So, we need to stop if n_val becomes 2^32-1.
                if (n_val == 4294967295LL) { // This is 2^32-1
                    // We just used this n_val. The next n_val would be 2^33-1.
                    // Its cost would overflow. So, we break.
                    break;
                }
            }
            current_cost = n_val * (n_val + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

