#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // The element at median_idx must become s.
    // This is the base cost.
    operations += std::abs(a[median_idx] - s);

    // For elements to the left of median_idx:
    // If a[i] > s, it must be decreased to s.
    // If a[i] <= s, it's fine (or already handled if a[median_idx] was decreased).
    // Since we want to minimize operations, we only change elements that violate the median property.
    // For i < median_idx, a[i] must be <= s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // For elements to the right of median_idx:
    // If a[i] < s, it must be increased to s.
    // If a[i] >= s, it's fine (or already handled if a[median_idx] was increased).
    // For i > median_idx, a[i] must be >= s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each x_i, advance right_ptr to find the farthest point x_k such that x_k - x_i <= d
        // Since x is sorted, x_k - x_i is increasing with k.
        // And x_i is increasing, so right_ptr only moves forward.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // After the loop, right_ptr points to the first element x_k such that x_k - x_i > d,
        // or right_ptr == n if all remaining elements satisfy the condition.
        // The valid indices for x_k are from i+1 up to right_ptr - 1.
        // The number of points in the range (x_i, x_{right_ptr-1}] is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m be the number of points available for x_j and x_k.
        // These points are x_{i+1}, x_{i+2}, ..., x_{right_ptr-1}.
        // The number of such points is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // If we choose x_i as the first point, we need to choose two more points from the range (i, right_ptr-1].
        // The number of points available for selection (excluding x_i) is (right_ptr - 1) - i.
        // Let this number be `num_available = (right_ptr - 1) - i`.
        // If `num_available` is less than 2, we cannot form a triplet.
        // Otherwise, we can choose any 2 points from these `num_available` points.
        // The number of ways to choose 2 points from `num_available` is `num_available * (num_available - 1) / 2`.

        long long num_available = (long long)(right_ptr - 1) - i;

        if (num_available >= 2) {
            count += num_available * (num_available - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Determine if the final product can be positive or negative.
    // The sign of the final product depends on the parity of negative numbers multiplied.
    // Each multiplication of two negative numbers results in a positive number.
    // Each multiplication of a negative and a positive number results in a negative number.
    // The total number of negative toys is A + B.
    // Each step reduces the total number of toys by 1.
    // The number of multiplications is total_toys - 1.
    // Let N_neg be the count of toys with negative values (from boxes 1 and 2).
    // Let N_pos be the count of toys with positive values (from boxes 3 and 4).
    // The final sign is negative if an odd number of negative values are involved in the final product.
    // This is equivalent to the parity of the initial count of negative toys (A+B).
    // If (A+B) is odd, the final product can be negative.
    // If (A+B) is even, the final product can be positive.
    // However, this is not entirely true. We can choose the order of operations.
    // For example, if we have -2, -0.5, 0.5, 2.
    // A=1, B=1, C=1, D=1. A+B=2 (even).
    // (-2 * -0.5) = 1 (pos)
    // (0.5 * 2) = 1 (pos)
    // (1 * 1) = 1 (pos) -> final positive.
    // But what if we do:
    // (-2 * 0.5) = -1 (neg)
    // (-0.5 * 2) = -1 (neg)
    // (-1 * -1) = 1 (pos) -> final positive.
    // The final sign is always positive if A+B is even.
    // The final sign is always negative if A+B is odd.
    // This is because each multiplication changes the total count of negative numbers by 0 or 2.
    // E.g., neg * neg -> pos (2 negs become 0 negs, change -2)
    //       neg * pos -> neg (1 neg becomes 1 neg, change 0)
    //       pos * pos -> pos (0 negs become 0 negs, change 0)
    // So the parity of negative numbers is invariant.
    // Thus, if (A+B) is odd, the final toy must be negative.
    // If (A+B) is even, the final toy must be positive.

    bool final_can_be_negative = ((a + b) % 2 != 0);
    bool final_can_be_positive = ((a + b) % 2 == 0);

    // Box 1: (-inf, -1]
    // Box 2: (-1, 0)
    // Box 3: (0, 1)
    // Box 4: [1, inf)

    // Can be Box 1 (negative, <= -1)
    // Requires final_can_be_negative.
    // To get <= -1, we need at least one toy with absolute value >= 1.
    // This means A+D > 0.
    // If A+D == 0, all initial toys have absolute value < 1.
    // Product of numbers with absolute value < 1 will always be < 1 (in absolute value).
    // So if A+D == 0, the final toy cannot be in Box 1 or Box 4.
    if (final_can_be_negative && (a + d > 0)) {
        ans1 = "Ya";
    }

    // Can be Box 2 (negative, > -1 and < 0)
    // Requires final_can_be_negative.
    // This is always possible if final_can_be_negative.
    // We can always construct values that result in (-1, 0).
    // E.g., if A+D > 0, we can multiply a large absolute value with a small absolute value.
    // If A+D == 0, all initial toys are in B or C. Their product will be in (-1, 1).
    // If A+D == 0 and final_can_be_negative (i.e., B is odd), then the product will be in (-1, 0).
    if (final_can_be_negative) {
        ans2 = "Ya";
    }

    // Can be Box 3 (positive, > 0 and < 1)
    // Requires final_can_be_positive.
    // This is always possible if final_can_be_positive.
    // Similar logic to Box 2.
    if (final_can_be_positive) {
        ans3 = "Ya";
    }

    // Can be Box 4 (positive, >= 1)
    // Requires final_can_be_positive.
    // To get >= 1, we need at least one toy with absolute value >= 1.
    // This means A+D > 0.
    if (final_can_be_positive && (a + d > 0)) {
        ans4 = "Ya";
    }

    // Special case: If all initial toys are in B and C (i.e., A=0, D=0).
    // All initial toys have absolute value < 1.
    // Any product of such toys will also have absolute value < 1.
    // So, the final toy cannot be in Box 1 or Box 4.
    if (a == 0 && d == 0) {
        ans1 = "Tidak";
        ans4 = "Tidak";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareA);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    // Create the result array A'
    // The i-th smallest B value (b_elements[i].value) should be paired with
    // the (m-1-i)-th smallest A value (a_elements[m-1-i].value)
    // The result needs to be stored such that A'[b_elements[i].original_index] = a_elements[m-1-i].value
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0
    }
    if (len > arr.size()) {
        return false;
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] < 1 || arr[i] > len) {
            return false;
        }
        if (seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    bool current_is_perm = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] < 1 || a[i] > n) { // Optimization: if a[i] is out of possible range for any permutation
            current_is_perm = false;
        }
        if (current_is_perm) {
            if (seen_prefix[a[i]]) {
                current_is_perm = false;
            } else {
                seen_prefix[a[i]] = true;
                if (a[i] > current_max) {
                    current_max = a[i];
                }
                if (current_max == i + 1) {
                    prefix_is_perm[i] = true;
                }
            }
        }
        prefix_max[i] = current_max;
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n, false);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix
    current_max = 0;
    current_is_perm = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < 1 || a[i] > n) { // Optimization: if a[i] is out of possible range for any permutation
            current_is_perm = false;
        }
        if (current_is_perm) {
            if (seen_prefix[a[i]]) {
                current_is_perm = false;
            } else {
                seen_prefix[a[i]] = true;
                if (a[i] > current_max) {
                    current_max = a[i];
                }
                if (current_max == (n - i)) {
                    suffix_is_perm[i] = true;
                }
            }
        }
        suffix_max[i] = current_max;
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be 1 to n-1
        int l2 = n - l1;
        if (l2 < 1) continue; // l2 must be 1 to n-1

        bool p1_ok = prefix_is_perm[l1 - 1];
        bool p2_ok = suffix_is_perm[l1];

        if (p1_ok && p2_ok) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <map>

// Using a map for memoization because N can be very large (up to 10^18)
// and we only visit states that are powers of 2 or N-1, N-2, etc.
// The number of distinct N values encountered will be small for a given N.
std::map<long long, long long> memo;

long long solve(long long n) {
    if (n == 0) {
        return 0;
    }
    if (memo.count(n)) {
        return memo[n];
    }

    long long res;
    if (n % 2 == 1) { // N is odd
        // Must take 1 coin. Opponent gets to play on N-1.
        // Current player gets 1 + (total coins taken from N-1 - opponent's score from N-1)
        // Total coins taken from N-1 is N-1.
        // Opponent's score from N-1 is solve(N-1).
        // So current player gets 1 + (N-1 - solve(N-1))
        res = 1 + (n - 1 - solve(n - 1));
    } else { // N is even
        // Option 1: Take 1 coin.
        // Current player gets 1 + (N-1 - solve(N-1))
        long long take_one = 1 + (n - 1 - solve(n - 1));

        // Option 2: Take N/2 coins.
        // Current player gets N/2 + (N/2 - solve(N/2))
        long long take_half = n / 2 + (n / 2 - solve(n / 2));

        res = std::max(take_one, take_half);
    }
    return memo[n] = res;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long N;
        std::cin >> N;
        memo.clear(); // Clear memoization for each test case
        std::cout << solve(N) << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    if (k >= n) { // Can change all games to W
        if (n == 0) { // Should not happen based on constraints (n >= 1)
            std::cout << 0 << std::endl;
        } else if (n == 1) {
            std::cout << 1 << std::endl;
        } else {
            std::cout << 1LL + 2LL * (n - 1) << std::endl;
        }
        return;
    }

    long long current_score = 0;
    int initial_wins = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            initial_wins++;
            if (i > 0 && s[i-1] == 'W') {
                current_score += 2;
            } else {
                current_score += 1;
            }
        }
    }

    if (initial_wins == 0) { // All L's initially
        if (k == 0) {
            std::cout << 0 << std::endl;
        } else { // Change k L's to W's. Best to make them contiguous.
            std::cout << 1LL + 2LL * (k - 1) << std::endl;
        }
        return;
    }

    // Collect lengths of L-segments between W's
    std::vector<int> l_segments;
    int first_w = -1;
    int last_w = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (first_w == -1) {
                first_w = i;
            }
            last_w = i;
        }
    }

    int current_l_count = 0;
    for (int i = first_w + 1; i < last_w; ++i) {
        if (s[i] == 'L') {
            current_l_count++;
        } else { // s[i] == 'W'
            if (current_l_count > 0) {
                l_segments.push_back(current_l_count);
            }
            current_l_count = 0;
        }
    }
    if (current_l_count > 0) {
        l_segments.push_back(current_l_count);
    }
    std::sort(l_segments.begin(), l_segments.end());

    // Fill L-segments between W's
    for (int segment_len : l_segments) {
        if (k >= segment_len) {
            k -= segment_len;
            current_score += 2 * segment_len; // Each L becomes W, connecting two Ws, adding 2 points per L
        } else {
            current_score += 2 * k; // Use remaining k to fill part of this segment
            k = 0;
            break;
        }
    }

    // Use remaining k to convert L's at ends
    if (k > 0) {
        int l_prefix_count = 0;
        for (int i = 0; i < first_w; ++i) {
            if (s[i] == 'L') {
                l_prefix_count++;
            }
        }

        int l_suffix_count = 0;
        for (int i = last_w + 1; i < n; ++i) {
            if (s[i] == 'L') {
                l_suffix_count++;
            }
        }

        // Prioritize suffix because it can connect to last_w and give 2 points
        // Prefix connects to first_w and gives 1 point
        // If we convert an L at the end, it adds 2 points if it connects to a W.
        // If we convert an L at the beginning, it adds 1 point if it connects to a W.
        // If we convert an L next to an existing W, it adds 2 points.
        // If we convert an L not next to an existing W, it adds 1 point.
        // The current_score already accounts for existing Ws.
        // When we convert an L to W, it adds 1 point if it's the first W in a new streak,
        // or 2 points if it extends an existing W streak.
        // The L-segments between Ws already handled.
        // Now we have Ls before first_w and after last_w.
        // Converting an L before first_w:
        //   If it's s[first_w-1], it connects to s[first_w] and adds 2 points.
        //   If it's s[first_w-2] and s[first_w-1] is now W, it adds 2 points.
        //   This means each L converted before first_w adds 2 points, except the very first one (s[0]) if it's not connected to anything.
        //   But since first_w is already W, converting s[first_w-1] makes it W-W, adding 2 points.
        //   Converting s[first_w-2] makes it W-W-W, adding 2 points.
        //   So each L converted before first_w adds 2 points.
        // Converting an L after last_w:
        //   Similar logic, each L converted after last_w adds 2 points.

        // The only exception is if first_w is 0, then there are no Ls before it.
        // Or if last_w is n-1, then there are no Ls after it.

        // We can convert up to k L's. Each conversion adds 2 points.
        // The total number of L's available at ends is l_prefix_count + l_suffix_count.
        long long changes_at_ends = std::min(k, (long long)l_prefix_count + l_suffix_count);
        current_score += 2 * changes_at_ends;
        k -= changes_at_ends;
    }

    std::cout << current_score << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

