        current_xor_sum ^= a;
    }

    // We want S_new = 2 * X_new
    // Let S_new = current_sum + b1 + b2 + ...
    // Let X_new = current_xor_sum ^ b1 ^ b2 ^ ...

    // Strategy: Append at most 3 elements.
    // It's always possible to make it good with at most 3 elements.
    // The simplest strategy is to append two elements: X and S+X.
    // Let's try to append two elements:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum
    //
    // New XOR sum: X_new = current_xor_sum ^ b1 ^ b2
    // X_new = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X_new = 0 ^ (current_sum + current_xor_sum)
    // X_new = current_sum + current_xor_sum
    //
    // New Sum: S_new = current_sum + b1 + b2
    // S_new = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // S_new = 2 * current_sum + 2 * current_xor_sum
