#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;
    int a_ptr_left = 0;
    int a_ptr_right = n - 1;

    // First, handle friends with w_i = 1.
    // These friends get 2 * largest available numbers.
    // Since w is sorted, w_i = 1 will be at the beginning.
    // We iterate w from largest to smallest to assign largest 'a' values first.
    // This means iterating w from k-1 down to 0.
    // Friends with w_i = 1 should get the largest remaining numbers.
    // Friends with w_i > 1 should get the largest remaining number as their max.

    // Distribute the largest numbers for the 'max' part of happiness.
    // Friends with w_i = 1 get their max and min from the same number, so they need 2x.
    // Friends with w_i > 1 get one largest number as their max.
    // To maximize sum, we give the largest available numbers to friends who need a 'max' value.
    // The friends with w_i = 1 are special: their min is also their max.
    // So, they effectively need two 'max' values.
    // It's optimal to give the largest available numbers to friends with w_i = 1.
    // And the next largest available numbers to friends with w_i > 1 as their max.

    // Sort w in descending order to process friends who need more numbers first,
    // or to prioritize friends with w_i=1 for largest numbers.
    // If w is sorted ascending, w[k-1] is the largest w_i, w[0] is the smallest w_i.
    // We want to give the largest 'a' values to friends who will use them as max.
    // Friends with w_i = 1 will use it as both max and min.
    // Friends with w_i > 1 will use it as max.

    // Strategy:
    // 1. Give the largest available numbers to friends with w_i = 1.
    //    Each such friend gets a_ptr_right, contributing 2 * a_ptr_right to happiness.
    //    Decrement a_ptr_right.
    // 2. For friends with w_i > 1:
    //    They get the next largest available number as their max.
    //    They get the smallest available number as their min.
    //    The remaining w_i - 2 numbers don't affect max/min, so we use the smallest available ones.

    // Sort w in descending order to process friends with w_i=1 first (if they exist)
    // and then friends with larger w_i.
    std::sort(w.rbegin(), w.rend());

    // Phase 1: Assign largest numbers to friends with w_i = 1
    // These friends contribute 2 * a_i to happiness.
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_right];
            a_ptr_right--;
        } else {
            // All w_i = 1 friends are processed. Break and move to Phase 2.
            // Since w is sorted descending, all remaining w[i] will be > 1.
            break;
        }
    }

    // Phase 2: Assign numbers to friends with w_i > 1
    // These friends get a_ptr_right as their max, and a_ptr_left as their min.
    // The remaining w_i - 2 numbers are taken from a_ptr_left onwards.
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_right]; // Max value
            a_ptr_right--;
            total_happiness += a[a_ptr_left]; // Min value
            a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest numbers (including the one used for min)
        }
    }

    std::cout << total_happiness << std::endl;
}

