    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // This 'a' needs to move past all 'b's to its right.
            // Each 'b' it moves past costs b_count steps.
            // After moving past all b_count 'b's, this 'a' will be at the end.
            // The operation "ab" -> "bba" effectively doubles the number of 'b's
            // that an 'a' will encounter if it's to the left of a 'b'.
            // When an 'a' moves past a 'b', it consumes 1 step.
            // The 'b' it moved past is still there, and a new 'b' is created.
            // So, the number of 'b's to its right effectively doubles for the next 'a' to its left.
            // The current 'a' needs to move past b_count 'b's.
            // This adds b_count to total_steps.
            total_steps = (total_steps + b_count) % mod;

            // After this 'a' moves past all b_count 'b's, it creates b_count new 'b's.
            // So, the effective number of 'b's for the 'a's further to the left doubles.
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

