#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[0][i + 1] = prefix_counts[0][i];
        prefix_counts[1][i + 1] = prefix_counts[1][i];
        prefix_counts[2][i + 1] = prefix_counts[2][i];
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    std::vector<long long> q_prime_factors;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            q_prime_factors.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        q_prime_factors.push_back(temp_q);
    }

    long long max_x = 0;

    for (long long factor : q_prime_factors) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= factor;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

