    std::cin >> d_str;
    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit value
        std::vector<int> colors(n);
        int last1 = -1; // last digit placed in color 1
        int first2 = -1; // first digit placed in color 2
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                colors[i] = 1;
                if (d[i] < last1) { // S1 must be non-decreasing
                    possible_p = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > p) {
                colors[i] = 2;
                if (first2 == -1) { // This is the first digit in S2
                    first2 = d[i];
                } else if (d[i] < first2) { // S2 must be non-decreasing
                    possible_p = false;
                    break;
                }
                first2 = d[i]; // Update last digit in S2 (which is first2 for now)
            } else { // d[i] == p
                // Try to put it in color 2 if possible, otherwise color 1
                if (d[i] >= last1) { // Can be placed in S1
                    colors[i] = 1;
                    last1 = d[i];
                } else { // Must be placed in S2
                    colors[i] = 2;
                    if (first2 == -1) { // This is the first digit in S2
                        first2 = d[i];
                    } else if (d[i] < first2) { // S2 must be non-decreasing
                        possible_p = false;
                        break;
                    }
                    first2 = d[i]; // Update last digit in S2
                }
            }
        }

        if (possible_p) {
            // Final check: last digit of S1 <= first digit of S2
            // This is implicitly handled by the logic for d[i] == p
            // If d[i] == p is put into S1, last1 becomes p.
            // If d[i] == p is put into S2, first2 becomes p.
            // The condition `d[i] >= last1` for putting p into S1 ensures that
            // any p put into S1 is >= previous S1 elements.
            // The condition `d[i] < first2` for putting p into S2 ensures that
            // any p put into S2 is >= previous S2 elements.
            // The critical part is that all elements < p are in S1, and all elements > p are in S2.
            // So, if S1 is non-empty and S2 is non-empty, last1 (which is <= p) must be <= first2 (which is >= p).
            // This is always true if last1 <= p and first2 >= p.
            // The only case where this might fail is if a 'p' is forced into S2 but it's smaller than a previous 'p' in S2.
            // But our logic for d[i] == p ensures S2 is non-decreasing.
            // And if a 'p' is forced into S1, it ensures S1 is non-decreasing.
            // The only remaining check is if last1 (from S1) > first2 (from S2).
            // This can only happen if last1 is a 'p' and first2 is a 'p', and last1 > first2, which is impossible.
            // Or if last1 is < p and first2 is > p, which is fine.
            // Or if last1 is p and first2 is > p, which is fine.
            // Or if last1 is < p and first2 is p, which is fine.
            // The logic seems to correctly maintain the non-decreasing property for S1 and S2,
            // and the split point p ensures last(S1) <= p <= first(S2).

            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
