    // The total number of dolls is `n`.
    // The number of dolls that are part of the `1->2->...->X` prefix is `X`.
    // The number of dolls that are NOT part of this prefix is `n - X`.

    // Each of these `n - X` dolls must be "freed" from any current nesting.
    // If a doll `d` is nested in `d+1` (and `d+1` is not part of the prefix), this is a "bad" nesting.
    // If a doll `d` is nested in `d+k` (k > 1), this is a "bad" nesting.

    // Let's count the number of "bad" nestings.
    // A nesting `a` in `b` is "bad" if `b != a+1` OR `a` is not part of the `1->...->X` prefix.
    // The total number of initial nestings is `n - k`. (Each chain of length `m_i` has `m_i-1` nestings. Sum of `m_i-1` over `k` chains is `(sum m_i) - k = n - k`).
    // The number of "good" nestings is `consecutive_pairs_in_target - 1`.
    // So, the number of "bad" nestings is `(n - k) - (consecutive_pairs_in_target - 1)`.
    // Each "bad" nesting requires one "get out" operation.
    // So, `(n - k) - (consecutive_pairs_in_target - 1)` "get out" operations.

    // The number of "put in" operations needed is `n - consecutive_pairs_in_target`.
    // This is because we need to put `X` into `X+1`, `X+1` into `X+2`, ..., `n-1` into `n`.
    // This is `(n-1) - (X-1)` operations, which is `n-X`.

    // Total operations = (number of "get out" operations) + (number of "put in" operations)
    // Total operations = `((n - k) - (consecutive_pairs_in_target - 1))` + `(n - consecutive_pairs_in_target)`
    // Total operations = `n - k - consecutive_pairs_in_target + 1 + n - consecutive_pairs_in_target`
    // Total operations = `2*n - k - 2*consecutive_pairs_in_target + 1`

    // Let's test this formula with Example 1: n=3, k=2. consecutive_pairs_in_target = 2.
    // Total operations = `2*3 - 2 - 2*2 + 1`
    // = `6 - 2 - 4 + 1`
    // = `4 - 4 + 1`
    // = `1`. This matches the example output!

    // Let's test with Example 2: n=7, k=3.
    // Chains: (1,3,7), (2,5), (4,6)
    // consecutive_pairs_in_target:
    // Chain (1,3,7): chain[0]=1, current_expected=1. counts 1. current_expected=2.
    //                chain[1]=3, current_expected=2. Not 2. Break.
    //                consecutive_pairs_in_target = 1.
    // Chain (2,5): chain[0]=2, current_expected=1. Not 1. Break.
    // Chain (4,6): chain[0]=4, current_expected=1. Not 1. Break.
    // Final consecutive_pairs_in_target = 1. (Only doll 1 is part of the prefix 1->...->X)

    // Total operations = `2*n - k - 2*consecutive_pairs_in_target + 1`
    // = `2*7 - 3 - 2*1 + 1`
    // = `14 - 3 - 2 + 1`
    // = `11 - 2 + 1`
    // = `9 + 1`
    // = `10`. This matches the example output!

    // The formula seems correct.
    // `consecutive_pairs_in_target` is the length of the longest prefix `1, 2, ..., X` that is already correctly formed and nested.
    // If `consecutive_pairs_in_target` is 0, it means doll 1 is not the first element of any chain, or there are no chains.
    // If `consecutive_pairs_in_target` is 1, it means doll 1 is the first element of some chain, but doll 2 is not nested in it.

    // The number of "get out" operations:
    // We have `n` dolls. `k` chains. Total `n-k` existing direct nestings.
    // `consecutive_pairs_in_target - 1` of these are "good" nestings (e.g., 1 in 2, 2 in 3, ..., X-1 in X).
    // The remaining `(n-k) - (consecutive_pairs_in_target - 1)` nestings must be broken. Each takes 1 second.
    // This is the number of "get out" operations.

    // The number of "put in" operations:
    // We need to form `n-1` direct nestings in the final chain (1 in 2, 2 in 3, ..., n-1 in n).
    // `consecutive_pairs_in_target - 1` of these are already formed.
    // So, we need to perform `(n-1) - (consecutive_pairs_in_target - 1)` new "put in" operations.
    // This simplifies to `n - consecutive_pairs_in_target` "put in" operations.

    // Total operations = `((n - k) - (consecutive_pairs_in_target - 1))` + `(n - consecutive_pairs_in_target)`
    // = `n - k - consecutive_pairs_in_target + 1 + n - consecutive_pairs_in_target`
    // = `2*n - k - 2*consecutive_pairs_in_target + 1`

    // This formula holds.

    total_operations = (long long)2 * n - k - (long long)2 * consecutive_pairs_in_target + 1;

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> d(n);
    std::deque<int> q;

    // Calculate d_i for left-to-right pass
    for (int i = 0; i < n; ++i) {
        while (!q.empty() && h[q.back()] >= h[i]) {
            q.pop_back();
        }
        long long prev_d = (q.empty() ? 0 : d[q.back()]);
        d[i] = prev_d + 1;
        q.push_back(i);
    }

    q.clear();
    // Calculate d_i for right-to-left pass and take minimum
    for (int i = n - 1; i >= 0; --i) {
        while (!q.empty() && h[q.back()] >= h[i]) {
            q.pop_back();
        }
        long long prev_d = (q.empty() ? 0 : d[q.back()]);
        d[i] = std::min(d[i], prev_d + 1);
        q.push_back(i);
    }

    long long max_d = 0;
    for (int i = 0; i < n; ++i) {
        max_d = std::max(max_d, std::min(h[i], d[i]));
    }

    std::cout << max_d << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << "1\n";
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int start_block_val = std::max(1, current_val - k + 1);
        for (int j = 0; j < k && (i + j) < n; ++j) {
            p[i + j] = start_block_val + (k - 1 - j);
        }
        current_val -= k;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: [1, 1], add -a[0]
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operation 2: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        // Operation 3: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // Segment [1, n-1] (0-indexed: [0, n-2])
    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n;
        long long to_add = remainder * (n - 1); // (n-1) is the length of the segment
        a[i] += to_add;
        std::cout << to_add << (i == n - 2 ? "" : " ");
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] divisible by n
    // Segment [n, n] (0-indexed: [n-1, n-1])
    std::cout << n << " " << n << "\n";
    long long remainder_n_minus_1 = (a[n - 1] % n + n) % n;
    long long to_add_n_minus_1 = remainder_n_minus_1 * n; // n is the length of the segment
    a[n - 1] += to_add_n_minus_1;
    std::cout << to_add_n_minus_1 << "\n";

    // Operation 3: Make all elements zero
    // Segment [1, n] (0-indexed: [0, n-1])
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        // At this point, a[i] is a multiple of n for all i.
        // So, -a[i] is also a multiple of n.
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current_val_if_0 and current_val_if_1 for each bit
    // current_val_if_0[j] stores the j-th bit of the result if input j-th bit is 0
    // current_val_if_1[j] stores the j-th bit of the result if input j-th bit is 1
    // Initially, if input j-th bit is 0, result j-th bit is 0.
    // If input j-th bit is 1, result j-th bit is 1.
    std::vector<int> current_val_if_0(10, 0); // All bits are 0
    std::vector<int> current_val_if_1(10, 1); // All bits are 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int j = 0; j < 10; ++j) {
            int bit_val = (val >> j) & 1;
            if (op_char == '&') {
                current_val_if_0[j] &= bit_val;
                current_val_if_1[j] &= bit_val;
            } else if (op_char == '|') {
                current_val_if_0[j] |= bit_val;
                current_val_if_1[j] |= bit_val;
            } else if (op_char == '^') {
                current_val_if_0[j] ^= bit_val;
                current_val_if_1[j] ^= bit_val;
            }
        }
    }

    // Determine the final operations
    int final_and_mask = 1023; // All bits 1
    int final_or_mask = 0;     // All bits 0
    int final_xor_mask = 0;    // All bits 0

    for (int j = 0; j < 10; ++j) {
        if (current_val_if_0[j] == 0 && current_val_if_1[j] == 0) {
            // Both 0 and 1 map to 0. This means the j-th bit is always 0.
            // To achieve this:
            // AND with 0: final_and_mask &= 0
            // OR with 0: final_or_mask |= 0 (no change)
            // XOR with 0: final_xor_mask ^= 0 (no change)
            final_and_mask &= ~(1 << j); // Set j-th bit of final_and_mask to 0
        } else if (current_val_if_0[j] == 1 && current_val_if_1[j] == 1) {
            // Both 0 and 1 map to 1. This means the j-th bit is always 1.
            // To achieve this:
            // AND with 1: final_and_mask &= 1 (no change)
            // OR with 1: final_or_mask |= 1
            // XOR with 0: final_xor_mask ^= 0 (no change)
            final_or_mask |= (1 << j); // Set j-th bit of final_or_mask to 1
        } else if (current_val_if_0[j] == 0 && current_val_if_1[j] == 1) {
            // 0 maps to 0, 1 maps to 1. This means the j-th bit is unchanged.
            // To achieve this:
            // AND with 1: final_and_mask &= 1 (no change)
            // OR with 0: final_or_mask |= 0 (no change)
            // XOR with 0: final_xor_mask ^= 0 (no change)
            // No specific action needed for this bit in the masks.
        } else if (current_val_if_0[j] == 1 && current_val_if_1[j] == 0) {
            // 0 maps to 1, 1 maps to 0. This means the j-th bit is flipped.
            // To achieve this:
            // AND with 1: final_and_mask &= 1 (no change)
            // OR with 0: final_or_mask |= 0 (no change)
            // XOR with 1: final_xor_mask ^= 1
            final_xor_mask |= (1 << j); // Set j-th bit of final_xor_mask to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit of final_and_mask is 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit of final_or_mask is 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit of final_xor_mask is 1
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << '\n';
    for (const auto& op : result_ops) {
        std::cout << op.first << ' ' << op.second << '\n';
    }

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        long long num_zeros = n - m;

        // To minimize substrings of all zeros, distribute zeros as evenly as possible.
        // There are m '1's, which can divide the string into m+1 potential blocks of zeros.
        // For example, _1_1_1_ (3 ones, 4 blocks of zeros)
        // The number of blocks of zeros is m+1.
        // We want to distribute num_zeros into these m+1 blocks.
        // Let k be the number of zeros in each block.
        // Some blocks will have floor(num_zeros / (m+1)) zeros.
        // Some blocks will have ceil(num_zeros / (m+1)) zeros.

        long long num_blocks = m + 1;

        long long k_floor = num_zeros / num_blocks;
        long long k_ceil = k_floor + 1;

        long long count_k_ceil_blocks = num_zeros % num_blocks;
        long long count_k_floor_blocks = num_blocks - count_k_ceil_blocks;

        long long substrings_from_zeros = 0;

        // Substrings from blocks of size k_floor
        substrings_from_zeros += count_k_floor_blocks * (k_floor * (k_floor + 1) / 2);

        // Substrings from blocks of size k_ceil
        substrings_from_zeros += count_k_ceil_blocks * (k_ceil * (k_ceil + 1) / 2);

        long long max_f_s = total_substrings - substrings_from_zeros;

        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back

        active_vertices[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step for the newly added vertex k
        // For all pairs (i, j) of currently active vertices,
        // check if path i -> k -> j is shorter than current i -> j
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;

                // Update paths involving k as an intermediate vertex
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After adding k and updating all paths through k,
        // we also need to consider paths where k is an endpoint
        // and other active vertices are intermediates.
        // This is implicitly handled by the standard Floyd-Warshall triple loop structure.
        // The above loop updates dist[i][j] using k as an intermediate.
        // The following two loops update dist[i][k] and dist[k][j] using other active vertices as intermediates.
        // This is essentially the full Floyd-Warshall step for vertex k.
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;

                // Update paths from i to k
                if (dist[i][j] + dist[j][k] < dist[i][k]) {
                    dist[i][k] = dist[i][j] + dist[j][k];
                }
                // Update paths from k to j
                if (dist[k][i] + dist[i][j] < dist[k][j]) {
                    dist[k][j] = dist[k][i] + dist[i][j];
                }
            }
        }

        // The above two sets of loops are equivalent to the standard Floyd-Warshall
        // where k is the "pivot" vertex.
        // The order of loops for Floyd-Warshall is usually:
        // for k:
        //   for i:
        //     for j:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //
        // Here, we are adding k, so k becomes the new pivot.
        // We need to ensure all paths involving k (as intermediate or endpoint) are updated.
        // The most robust way is to apply the standard Floyd-Warshall update for k:
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (forward removal order)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_left[i] = (count of 1s) - (count of 2s) in jars 1 to i
    // We are interested in the balance of jars 1 to n-k
    // This means we remove k jars from the left.
    // The balance for jars 1 to n-k is stored at diff_left[n-k-1]
    // Or, more simply, diff_left[i] is the balance of jars 1 to i+1.
    // So diff_left[k] is the balance of jars 1 to k+1.
    // We want to find the balance of jars from index 0 to index n-1-k_left
    // This is equivalent to finding the balance of jars from index k_left to index n-1.
    // Let's define balance_left[k] as the balance of jars from index k to n-1.
    // This is (count of 1s) - (count of 2s) in a[k...n-1].
    // We can compute this by iterating from n-1 down to 0.

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_right[i] = (count of 1s) - (count of 2s) in jars i to 2n
    // We are interested in the balance of jars n+k+1 to 2n
    // This means we remove k jars from the right.
    // The balance for jars n+k+1 to 2n is stored at diff_right[n+k]
    // Or, more simply, diff_right[i] is the balance of jars i+1 to 2n.
    // So diff_right[k] is the balance of jars k+1 to 2n.
    // We want to find the balance of jars from index n+k_right to 2n-1.
    // This is equivalent to finding the balance of jars from index n to index 2n-1-k_right.
    // Let's define balance_right[k] as the balance of jars from index n to 2n-1-k.
    // This is (count of 1s) - (count of 2s) in a[n...2n-1-k].
    // We can compute this by iterating from n up to 2n-1.

    // Let's re-evaluate the definition of balance for clarity.
    // We are interested in the balance of the *remaining* jars.
    // Suppose we remove `k_left` jars from the left (jars 0 to k_left-1)
    // and `k_right` jars from the right (jars 2n-k_right to 2n-1).
    // The remaining jars are from index `k_left` to `2n-1-k_right`.
    // The total number of removed jars is `k_left + k_right`.
    // We want to minimize this sum.

    // Let `balance_prefix[i]` be the balance of jars `a[0...i-1]`.
    // `balance_prefix[0] = 0`.
    // `balance_prefix[i] = balance_prefix[i-1] + (a[i-1] == 1 ? 1 : -1)`.
    // This means `balance_prefix[i]` is the balance of the first `i` jars.

    // Let `balance_suffix[i]` be the balance of jars `a[i...2n-1]`.
    // `balance_suffix[2n] = 0`.
    // `balance_suffix[i] = balance_suffix[i+1] + (a[i] == 1 ? 1 : -1)`.
    // This means `balance_suffix[i]` is the balance of the last `2n-i` jars.

    // The total balance of all jars is `balance_prefix[2n]`.
    // Let `target_diff = balance_prefix[2n]`.
    // We want to find `k_left` and `k_right` such that
    // `balance_prefix[k_left]` (balance of removed left jars)
    // minus `balance_suffix[2n-k_right]` (balance of removed right jars)
    // equals `target_diff`.
    // This is not quite right. The problem states "the amount of full strawberry and blueberry jam jars should become the same".
    // This means the balance of the *remaining* jars should be 0.

    // Let `bal_left[k]` be the balance of jars `a[0...n-1-k]`.
    // This means we remove `k` jars from the left side of Karlsson's initial position.
    // `k` ranges from `0` to `n`.
    // `bal_left[k]` is the balance of jars `a[0]` through `a[n-1-k]`.
    // If `k=0`, `bal_left[0]` is balance of `a[0...n-1]`.
    // If `k=n`, `bal_left[n]` is balance of `a[0...-1]` (empty, so 0).
    std::vector<int> bal_left(n + 1);
    int current_bal = 0;
    for (int i = n - 1; i >= 0; --i) {
        current_bal += (a[i] == 1 ? 1 : -1);
        bal_left[n - 1 - i] = current_bal;
    }
    bal_left[n] = 0; // If all n jars on left are removed

    // Let `bal_right[k]` be the balance of jars `a[n+k...2n-1]`.
    // This means we remove `k` jars from the right side of Karlsson's initial position.
    // `k` ranges from `0` to `n`.
    // `bal_right[k]` is the balance of jars `a[n+k]` through `a[2n-1]`.
    // If `k=0`, `bal_right[0]` is balance of `a[n...2n-1]`.
    // If `k=n`, `bal_right[n]` is balance of `a[2n...2n-1]` (empty, so 0).
    std::vector<int> bal_right(n + 1);
    current_bal = 0;
    for (int i = n; i < 2 * n; ++i) {
        current_bal += (a[i] == 1 ? 1 : -1);
        bal_right[i - n] = current_bal;
    }
    bal_right[n] = 0; // If all n jars on right are removed

    // We need to find `k_left` (jars removed from left side of n)
    // and `k_right` (jars removed from right side of n+1)
    // such that the balance of remaining jars is 0.
    // The remaining jars are `a[k_left ... n-1]` and `a[n ... 2n-1-k_right]`.
    // The balance of `a[k_left ... n-1]` is `bal_left[k_left]`.
    // The balance of `a[n ... 2n-1-k_right]` is `bal_right[k_right]`.
    // We want `bal_left[k_left] + bal_right[k_right] == 0`.
    // This means `bal_left[k_left] == -bal_right[k_right]`.

    // Store the minimum `k_right` for each `bal_right` value.
    std::map<int, int> min_k_right_for_balance;
    for (int k_right = 0; k_right <= n; ++k_right) {
        int balance = bal_right[k_right];
        if (min_k_right_for_balance.find(balance) == min_k_right_for_balance.end()) {
            min_k_right_for_balance[balance] = k_right;
        } else {
            min_k_right_for_balance[balance] = std::min(min_k_right_for_balance[balance], k_right);
        }
    }

    int min_removed_jars = 2 * n; // Max possible value

    for (int k_left = 0; k_left <= n; ++k_left) {
        int required_bal_right = -bal_left[k_left];
        if (min_k_right_for_balance.count(required_bal_right)) {
            int k_right = min_k_right_for_balance[required_bal_right];
            min_removed_jars = std::min(min_removed_jars, k_left + k_right);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

