#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        // Child i goes to the office
        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long d_chain_cry = 0; // Accumulates d_j cries from children leaving due to low confidence

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_chain_cry
            children[j].p -= d_chain_cry;

            // Apply current_v_cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves the line
            if (children[j].p < 0) {
                children[j].in_line = false;
                d_chain_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_i to a very large value (effectively infinity)
    // b_i represents the maximum possible initial value for A_i
    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    // Calculate the total delta for each element up to each operation
    // This is needed to determine the value of a_j(k-1) based on A_j
    std::vector<std::vector<long long>> delta_prefix_sum(m + 1, std::vector<long long>(n, 0));

    for (int k = 0; k < m; ++k) {
        for (int j = 0; j < n; ++j) {
            delta_prefix_sum[k + 1][j] = delta_prefix_sum[k][j];
        }
        if (ops[k].type == 1) {
            for (int j = ops[k].l; j <= ops[k].r; ++j) {
                delta_prefix_sum[k + 1][j] += ops[k].val;
            }
        }
    }

    // Process type 2 operations to constrain b_i
    for (int k = 0; k < m; ++k) {
        if (ops[k].type == 2) {
            long long m_k = ops[k].val;
            int l_k = ops[k].l;
            int r_k = ops[k].r;

            for (int j = l_k; j <= r_k; ++j) {
                // A_j + delta_j(k) <= m_k
                // A_j <= m_k - delta_j(k)
                b[j] = std::min(b[j], m_k - delta_prefix_sum[k][j]);
            }
        }
    }

    // Construct the initial array A using the calculated b_i values
    // A_i = b_i is a valid choice because it maximizes A_i while satisfying A_i <= m_k - delta_j(k)
    // for all relevant type 2 operations.
    std::vector<long long> A = b;

    // Verify the constructed array A
    // Simulate all operations with the initial array A
    std::vector<long long> current_a = A;
    for (int k = 0; k < m; ++k) {
        if (ops[k].type == 1) {
            for (int j = ops[k].l; j <= ops[k].r; ++j) {
                current_a[j] += ops[k].val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[k].l; j <= ops[k].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[k].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the array A
    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << A[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

