        int num_segments_in_this_step = alternating_segments.size();

        // Process segments from left to right
        for (int k = 0; k < num_segments_in_this_step; ++k) {
            auto [start_idx, length] = alternating_segments.front();
            alternating_segments.pop_front();

            if (length < 3) { // Segments of length 1 or 2 don't change in the middle
                // They might merge with neighbors if they become alternating.
                // But for now, they are stable within themselves.
                continue;
            }

            int changes_per_side = (length - 1) / 2;
            int new_start_idx = start_idx + changes_per_side;
            int new_length = length - 2 * changes_per_side;

            // Apply changes to current_a
            int val_at_start = current_a[start_idx];
            for (int i = 0; i < changes_per_side; ++i) {
                current_a[start_idx + 1 + 2 * i] = val_at_start;
            }
            int val_at_end = current_a[start_idx + length - 1];
            for (int i = 0; i < changes_per_side; ++i) {
                current_a[start_idx + length - 2 - 2 * i] = val_at_end;
            }

            if (new_length >= 3) {
                alternating_segments.push_back({new_start_idx, new_length});
            }
        }

        // After processing all segments for this step, we need to re-evaluate
        // the alternating segments because they might have merged or new ones formed.
        // This is the tricky part. Instead of re-evaluating all, we can just
        // check if the sequence is stable. If not, find new segments.
        // A simpler approach: just apply the median filter to the whole array.
        // This is O(N) per step. Max steps can be O(N). Total O(N^2).
        // N=500,000, N^2 is too slow.

        // The problem states that the sequence stops changing.
        // The number of steps is related to the length of the longest alternating segment.
        // A segment of length L takes floor((L-1)/2) steps to stabilize.
        // The maximum number of steps is max(floor((L-1)/2)) over all initial alternating segments.
        // The final sequence is obtained by applying these changes.

        // Let's re-think the stabilization process.
        // An alternating segment `X Y X Y ... Z` of length `L`.
        // In one step, `Y`s become `X`s from the left, and `Y`s become `Z`s from the right.
        // E.g., `0 1 0 1 0` (L=5). `0` is `X`, `1` is `Y`. `0` is `Z`.
        // Step 1: `0 0 0 0 0`. The middle `1` becomes `0`.
        // E.g., `0 1 0 1` (L=4). `0` is `X`, `1` is `Y`.
        // Step 1: `0 0 0 1`. The middle `1` becomes `0`.
        // The number of steps for a segment of length `L` is `ceil((L-1)/2)`.
        // No, it's `floor((L-1)/2)` for the number of elements that change from each side.
        // The number of steps is `(L-1)/2` if L is odd, and `(L-2)/2` if L is even.
        // This is `floor((L-1)/2)`.
        // Example: 01010 (L=5). floor((5-1)/2) = 2.
        // 01010 -> 00100 -> 00000. Takes 2 steps.
        // Example: 0101 (L=4). floor((4-1)/2) = 1.
        // 0101 -> 0001. Takes 1 step.
        // Example: 010 (L=3). floor((3-1)/2) = 1.
        // 010 -> 000. Takes 1 step.

        // So, the maximum number of steps is `max(floor((L-1)/2))` over all initial alternating segments.
        // The final sequence is obtained by applying these changes.
        // For each alternating segment `a[s...s+L-1]`:
        // The first `k = floor((L-1)/2)` elements from the left `a[s+1], a[s+3], ...` become `a[s]`.
        // The last `k = floor((L-1)/2)` elements from the right `a[s+L-2], a[s+L-4], ...` become `a[s+L-1]`.
        // The middle part `a[s+k ... s+L-1-k]` remains alternating if `L-2k >= 2`.
        // If `L-2k` is 1, it's a single element `a[s+k]`. It remains `a[s+k]`.
        // If `L-2k` is 0, the segment is fully smoothed.

        // This means the final state of `a[i]` is determined by the nearest stable block.
        // If `a[i]` is part of an alternating segment, it will eventually become the value of the nearest stable block.
        // If `a[i]` is `0` and `a[i-1]` is `0`, then `a[i]` is stable from left.
        // If `a[i]` is `0` and `a[i+1]` is `0`, then `a[i]` is stable from right.
        // If `a[i]` is `1` and `a[i-1]` is `1`, then `a[i]` is stable from left.
        // If `a[i]` is `1` and `a[i+1]` is `1`, then `a[i]` is stable from right.

        // Let's find the "stable blocks" (contiguous sequences of same values).
        // For each `i`, find `left_stable[i]` = index of the first element to the left of `i` (inclusive)
        // that is part of a stable block (i.e., `a[k] == a[k+1]`).
        // And `right_stable[i]` = index of the first element to the right of `i` (inclusive)
        // that is part of a stable block (i.e., `a[k] == a[k-1]`).

        std::vector<int> left_stable_idx(n, -1);
        std::vector<int> right_stable_idx(n, -1);

        for (int i = 0; i < n - 1; ++i) {
            if (a[i] == a[i+1]) {
                left_stable_idx[i] = i;
                left_stable_idx[i+1] = i+1;
            }
        }
        for (int i = 1; i < n; ++i) {
            if (left_stable_idx[i] == -1) { // If not stable with i-1 or i+1
                left_stable_idx[i] = left_stable_idx[i-1];
            }
        }

        for (int i = n - 1; i > 0; --i) {
            if (a[i] == a[i-1]) {
                right_stable_idx[i] = i;
                right_stable_idx[i-1] = i-1;
            }
        }
        for (int i = n - 2; i >= 0; --i) {
            if (right_stable_idx[i] == -1) {
                right_stable_idx[i] = right_stable_idx[i+1];
            }
        }

        // The first and last elements are always stable.
        left_stable_idx[0] = 0;
        right_stable_idx[n-1] = n-1;

        // Now, for each `i`, if `left_stable_idx[i]` is valid and `right_stable_idx[i]` is valid,
        // then `a[i]` is part of an alternating segment between two stable blocks.
        // The distance to the left stable block is `i - left_stable_idx[i]`.
        // The distance to the right stable block is `right_stable_idx[i] - i`.
        // The value `a[i]` will eventually become `a[left_stable_idx[i]]` if `i - left_stable_idx[i] <= right_stable_idx[i] - i`.
        // The value `a[i]` will eventually become `a[right_stable_idx[i]]` if `i - left_stable_idx[i] > right_stable_idx[i] - i`.
        // The number of steps for `a[i]` to stabilize is `min(i - left_stable_idx[i], right_stable_idx[i] - i)`.

        int max_stabilization_steps = 0;
        std::vector<int> final_a = a;

        for (int i = 0; i < n; ++i) {
            if (left_stable_idx[i] == -1 && right_stable_idx[i] == -1) {
                // This should not happen for n >= 3, as first and last elements are stable.
                // If n=1 or n=2, it's already handled.
                // If n >= 3, left_stable_idx[0]=0 and right_stable_idx[n-1]=n-1.
                // So every element must have at least one stable neighbor (possibly itself).
                // This means left_stable_idx[i] or right_stable_idx[i] must be valid.
                // If left_stable_idx[i] is -1, it means all elements to its left are alternating.
                // But left_stable_idx[0] is 0. So this implies i=0.
                // If right_stable_idx[i] is -1, it means all elements to its right are alternating.
                // But right_stable_idx[n-1] is n-1. So this implies i=n-1.
                // So, if i is not 0 and not n-1, both must be valid.
                // If i=0, left_stable_idx[0]=0. If right_stable_idx[0]=-1, then 010101...
                // If i=n-1, right_stable_idx[n-1]=n-1. If left_stable_idx[n-1]=-1, then ...01010.
                // This means the entire sequence is alternating.
                // Example: 01010. left_stable_idx = [0,0,0,0,0]. right_stable_idx = [4,4,4,4,4].
                // This is correct.
            }

            int dist_left = (left_stable_idx[i] != -1) ? (i - left_stable_idx[i]) : n; // Use n as "infinity"
            int dist_right = (right_stable_idx[i] != -1) ? (right_stable_idx[i] - i) : n;

            if (dist_left == n && dist_right == n) {
                // This means the sequence is entirely alternating, e.g., 01010.
                // In this case, left_stable_idx[i] will be 0 for all i, and right_stable_idx[i] will be n-1 for all i.
                // So this branch is not taken.
            }

            int current_steps = std::min(dist_left, dist_right);
            max_stabilization_steps = std::max(max_stabilization_steps, current_steps);

            if (dist_left <= dist_right) {
                final_a[i] = a[left_stable_idx[i]];
            } else {
                final_a[i] = a[right_stable_idx[i]];
            }
        }

        std::cout << max_stabilization_steps << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << final_a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;

        return 0;
    }

    return 0; // Should not be reached
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> p(n); // Partition array for the sorted elements

    // Case 1: All elements in one subsequence (e.g., all 1s)
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n);
    for (int i = 0; i < n; ++i) {
        partition1[elements[i].original_index] = 1;
    }

    // Case 2: Try to put a_1 in S1 and a_2, ..., a_n in S2
    // Or a_1, ..., a_{n-1} in S1 and a_n in S2
    // This is equivalent to having elements in different subsequences.
    // The smallest sum is a_1 + a_2.
    // The largest sum is a_{n-1} + a_n.
    // If a_1 and a_n are in different subsequences, then a_1 + a_n + h is a value.
    // If a_1 and a_2 are in the same subsequence, then a_1 + a_2 is a value.
    // If a_{n-1} and a_n are in the same subsequence, then a_{n-1} + a_n is a value.

    // Consider a partition where elements[0] is in S1 and elements[1]...elements[n-1] are in S2.
    // min_f:
    //   - elements[1].value + elements[2].value (if n >= 3, both in S2)
    //   - elements[0].value + elements[1].value + h (elements[0] in S1, elements[1] in S2)
    //   min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h) if n >= 3
    //   min_f = elements[0].value + elements[1].value + h if n == 2
    // max_f:
    //   - elements[n-2].value + elements[n-1].value (both in S2)
    //   - elements[0].value + elements[n-1].value + h (elements[0] in S1, elements[n-1] in S2)
    //   max_f = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)

    // Let's analyze the specific partition: elements[0] in S1, elements[1...n-1] in S2.
    // Values within S1: None (if S1 has only one element)
    // Values within S2: elements[i].value + elements[j].value for 1 <= i < j <= n-1
    // Values between S1 and S2: elements[0].value + elements[j].value + h for 1 <= j <= n-1

    // Minimum possible f value:
    // If n >= 3, the smallest sum within S2 is elements[1].value + elements[2].value.
    // The smallest sum between S1 and S2 is elements[0].value + elements[1].value + h.
    // So, min_f_val = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h) if n >= 3
    // If n == 2, min_f_val = elements[0].value + elements[1].value + h.
    long long min_f_val_case2;
    if (n >= 3) {
        min_f_val_case2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    } else { // n == 2
        min_f_val_case2 = elements[0].value + elements[1].value + h;
    }

    // Maximum possible f value:
    // The largest sum within S2 is elements[n-2].value + elements[n-1].value.
    // The largest sum between S1 and S2 is elements[0].value + elements[n-1].value + h.
    long long max_f_val_case2 = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] will store the largest j < i such that s[j]...s[i-1] contains no bad pattern.
    // Or, more precisely, dp[i] is the smallest starting index 'l' such that the substring s[l...i-1]
    // does not contain any bad pattern.
    // If s[i-1] is the rightmost character of a bad pattern, then dp[i] must be greater than
    // the leftmost character of that bad pattern.
    // So, dp[i] = max(dp[i-1], max_l_for_bad_pattern_ending_at_i-1 + 1)
    // where max_l_for_bad_pattern_ending_at_i-1 is the largest 'x' (0-indexed)
    // such that x, x+k, x+2k are indices and x+2k = i-1 and s_x = s_{x+k} = s_{x+2k}.

    // Let's define dp[i] as the smallest 'l' (0-indexed) such that the substring s[l...i-1]
    // contains no bad pattern.
    // For a fixed 'r' (0-indexed), the number of valid 'l's (0-indexed) is r - dp[r] + 1.
    // The total number of bad pairs is sum_{r=0 to n-1} (r - dp[r] + 1).
    // This is equivalent to counting pairs (l, r) such that s[l...r] contains no bad pattern.

    // Let's use `last_bad_start[i]` to store the maximum `x` (0-indexed) such that
    // `s_x = s_{x+k} = s_{x+2k}` for some `k >= 1` and `x+2k = i`.
    // If no such pattern ends at `i`, `last_bad_start[i]` can be -1.
    // We need to find the smallest `l` such that `s[l...r]` contains no bad pattern.
    // This means `l` must be greater than `last_bad_start[j]` for all `j` in `[l+2, r]`.
    // This is equivalent to `l > max(last_bad_start[j])` for `j` in `[l+2, r]`.

    // Let's define `last_valid_start[i]` as the largest `l` (0-indexed) such that
    // the substring `s[l...i]` contains no bad pattern.
    // For a fixed `r` (0-indexed), we want to count `l` such that `0 <= l <= r` and `s[l...r]`
    // contains no bad pattern.
    // Let `max_x_for_r[r]` be the maximum `x` (0-indexed) such that `s_x = s_{x+k} = s_{x+2k}`
    // for some `k >= 1` and `x+2k <= r`.
    // If no such pattern exists up to `r`, `max_x_for_r[r]` is -1.
    // Then, for a given `r`, any `l` such that `l > max_x_for_r[r]` will form a valid pair `(l, r)`.
    // The number of such `l`'s is `r - (max_x_for_r[r] + 1) + 1 = r - max_x_for_r[r]`.
    // This is `r - max_x_for_r[r]` if `max_x_for_r[r]` is not -1.
    // If `max_x_for_r[r]` is -1, then all `l` from `0` to `r` are valid, so `r+1` pairs.
    // This can be unified as `r - std::max(-1, max_x_for_r[r])`.

    // Let `max_x_ending_at_r[r]` be the maximum `x` such that `s_x = s_{x+k} = s_{x+2k}`
    // for some `k >= 1` and `x+2k = r`. If no such pattern ends at `r`, it's -1.
    // Then `max_x_for_r[r] = std::max(max_x_for_r[r-1], max_x_ending_at_r[r])`.
    // Base case: `max_x_for_r[-1]` is -1.

    std::vector<int> max_x_for_r(n, -1); // max_x_for_r[i] stores max x for patterns ending at or before index i

    for (int r = 0; r < n; ++r) {
        if (r > 0) {
            max_x_for_r[r] = max_x_for_r[r - 1];
        }

        // Check for patterns ending at r
        // k=1: x = r-2. Pattern: s[r-2], s[r-1], s[r].
        if (r >= 2 && s[r - 2] == s[r - 1] && s[r - 1] == s[r]) {
            max_x_for_r[r] = std::max(max_x_for_r[r], r - 2);
        }
        // k=2: x = r-4. Pattern: s[r-4], s[r-2], s[r].
        if (r >= 4 && s[r - 4] == s[r - 2] && s[r - 2] == s[r]) {
            max_x_for_r[r] = std::max(max_x_for_r[r], r - 4);
        }
        // k=3: x = r-6. Pattern: s[r-6], s[r-3], s[r].
        if (r >= 6 && s[r - 6] == s[r - 3] && s[r - 3] == s[r]) {
            max_x_for_r[r] = std::max(max_x_for_r[r], r - 6);
        }
    }

    for (int r = 0; r < n; ++r) {
        // For each r, the number of valid l's (0-indexed) is (r - (max_x_for_r[r] + 1) + 1)
        // which simplifies to (r - max_x_for_r[r]).
        // If max_x_for_r[r] is -1, it means no bad pattern exists up to r.
        // In this case, all l from 0 to r are valid, so r+1 pairs.
        // The formula r - max_x_for_r[r] gives r - (-1) = r+1. So it works.
        bad_pairs += (r - max_x_for_r[r]);
    }

    std::cout << bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long head_reach_left = current_h - T;
        long long head_reach_right = current_h + T;

        // Find the first target track that this head can potentially cover
        // It must be within [head_reach_left, head_reach_right]
        // And it must be greater than or equal to the current p[p_idx]

        // If current_h is already to the right of p[p_idx] + T, this head is too far right for p[p_idx]
        // and potentially for many subsequent p's.
        // We need to find the first p[k] such that p[k] <= head_reach_right.
        // And then check if it can be covered.

        // If p[p_idx] is already to the right of head_reach_right, this head cannot cover p[p_idx]
        // and cannot cover any subsequent p's. So this head is useless for current p_idx.
        // We need to find a head that can cover p[p_idx].
        // The current head can only cover tracks in [current_h - T, current_h + T].
        // If p[p_idx] > current_h + T, this head cannot cover p[p_idx].
        // If p[p_idx] < current_h - T, this head cannot cover p[p_idx].

        // The strategy is: for each head, cover as many *uncovered* tracks as possible, starting from the leftmost uncovered track.
        // If the current head h[h_idx] cannot cover p[p_idx], we move to the next head.
        // If it can, we use it to cover p[p_idx] and all subsequent tracks it can reach.

        if (p[p_idx] > head_reach_right) {
            // This head is too far left to cover p[p_idx]
            // It means current_h + T < p[p_idx].
            // This head cannot cover p[p_idx] or any tracks to its right.
            // So we continue to the next head.
            continue;
        }

        // At this point, p[p_idx] <= head_reach_right.
        // This head *might* be able to cover p[p_idx].
        // We need to determine the effective range this head can cover, considering p[p_idx].

        long long effective_left_bound;
        long long effective_right_bound;

        if (current_h >= p[p_idx]) {
            // Head is at or to the right of p[p_idx].
            // It can move left to cover p[p_idx].
            // The leftmost track it can cover is max(p[p_idx], current_h - T).
            // The rightmost track it can cover is current_h + T.
            // The time taken to reach p[p_idx] is current_h - p[p_idx].
            // Remaining time for rightward movement is T - (current_h - p[p_idx]).
            // So it can cover up to p[p_idx] + (T - (current_h - p[p_idx])) = 2*p[p_idx] - current_h + T.
            // This is equivalent to saying it covers [p[p_idx], p[p_idx] + (T - (current_h - p[p_idx]))]
            // The rightmost point it can reach is p[p_idx] + (T - (current_h - p[p_idx]))
            // This is equivalent to current_h + T - 2*(current_h - p[p_idx]) if it moves left to p[p_idx] and then right.
            // No, this is simpler: if it covers p[p_idx], it can cover any track in [p[p_idx], p[p_idx] + (T - (current_h - p[p_idx]))].
            // The rightmost track it can cover is p[p_idx] + (T - (current_h - p[p_idx])).
            // This is the maximum rightward reach *after* covering p[p_idx].
            effective_right_bound = p[p_idx] + (T - (current_h - p[p_idx]));
        } else { // current_h < p[p_idx]
            // Head is to the left of p[p_idx].
            // It can move right to cover p[p_idx].
            // The time taken to reach p[p_idx] is p[p_idx] - current_h.
            // Remaining time for leftward movement is T - (p[p_idx] - current_h).
            // So it can cover down to p[p_idx] - (T - (p[p_idx] - current_h)) = 2*p[p_idx] - current_h - T.
            // This is equivalent to saying it covers [p[p_idx] - (T - (p[p_idx] - current_h)), p[p_idx]].
            // The rightmost point it can reach is current_h + T.
            effective_right_bound = current_h + T;
        }

        // Now, advance p_idx as long as p[p_idx] is within the effective_right_bound
        while (p_idx < m && p[p_idx] <= effective_right_bound) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p and h is 10^10.
                                    // Max T could be 10^10.
                                    // If p[0] = 1, h[0] = 10^10, T = 10^10 - 1.
                                    // If p[m-1] = 10^10, h[n-1] = 1, T = 10^10 - 1.
                                    // Max value for p_i or h_i is 10^10.
                                    // So max T could be around 10^10.
                                    // 2 * 10^10 is a safe upper bound.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: One cut, two pieces.
    // s = s_left s_right
    // New string s' = s_right s_left
    // We need s' to be a palindrome and s' != s.
    // Iterate through all possible cut positions (n-1 positions).
    for (int i = 1; i < n; ++i) { // Cut after index i-1, so s_left = s[0...i-1], s_right = s[i...n-1]
        std::string s_left = s.substr(0, i);
        std::string s_right = s.substr(i);
        std::string s_prime = s_right + s_left;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts, three pieces.
    // s = s_1 s_2 s_3
    // The problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then any rearrangement of pieces
    // will result in the same string "aaaa".
    // For example, "qqqq", s_left = "q", s_mid = "q", s_right = "qq".
    // Any permutation of these pieces will still be "qqqq".
    // In this case, it's impossible to form a new string.
    // We need to check if all characters are the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 must work.
    // Why k=2 always works if not all characters are the same?
    // Consider the string s. Since s is a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    // Also, since s is a palindrome, s[0] == s[n-1], s[1] == s[n-2], etc.
    // If n is odd, the middle character s[n/2] is unique.
    // If n is even, there is no unique middle character.
    //
    // Let's consider the first half of the string: s[0 ... n/2 - 1].
    // If all characters in this first half are the same (e.g., "aaabaaa", first half "aaa"),
    // then s must be of the form "aaa...a" + 'b' + "aaa...a".
    // Since s is a palindrome, if s[0...n/2-1] consists of only one character, say 'a',
    // and s is not entirely 'a's, then there must be some character 'b' != 'a' in the middle.
    // Example: "aaabaaa".
    // Cut 1: "aa" | "abaaa" -> "abaaaaa" (not palindrome)
    // Cut 2: "aaa" | "baaa" -> "baaabaaa" (not palindrome)
    //
    // The strategy for k=2:
    // Cut the string into three pieces:
    // s_1 = s[0]
    // s_2 = s[1 ... n-2]
    // s_3 = s[n-1]
    // Since s is a palindrome, s[0] == s[n-1]. So s_1 == s_3.
    // The original string is s_1 s_2 s_3.
    // Consider the rearrangement s_1 s_3 s_2. This would be s[0] s[n-1] s[1...n-2].
    // Since s[0] == s[n-1], this is s[0] s[0] s[1...n-2]. This is not necessarily a palindrome.
    //
    // A simpler strategy for k=2:
    // Take the first character s[0] and the last character s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // If we cut s into s[0] | s[1...n-2] | s[n-1], we have three pieces.
    // Let p1 = s[0], p2 = s[1...n-2], p3 = s[n-1].
    // We know p1 == p3.
    // The original string is p1 p2 p3.
    // Consider the string p3 p2 p1. This is s[n-1] s[1...n-2] s[0].
    // Since s[n-1] == s[0], this is s[0] s[1...n-2] s[0].
    // This is a palindrome if s[1...n-2] is a palindrome.
    // Since s is a palindrome, s[1...n-2] is also a palindrome.
    // So s[0] s[1...n-2] s[0] is always a palindrome.
    // Is s[0] s[1...n-2] s[0] different from s?
    // s = s[0] s[1...n-2] s[n-1]
    // s' = s[0] s[1...n-2] s[0]
    // These are identical. This doesn't help.
    //
    // The problem states "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string."
    //
    // Let's re-evaluate the condition for k=2.
    // If s is a palindrome and not all characters are the same, then there must be at least one character in s[0...n/2-1] that is different from s[0].
    // (Otherwise, if all s[0...n/2-1] are the same as s[0], and s is a palindrome, then s[n/2+1...n-1] are also the same as s[0].
    // This would mean s consists of only s[0] repeated, unless n is odd and s[n/2] is different.
    // But if s[n/2] is different, e.g., "aaabaaa", then s[0...n/2-1] are all 'a's.
    // In this case, s[0] is 'a', s[1] is 'a', s[2] is 'a', s[3] is 'b'.
    //
    // Consider the string s. If it's not all same characters, then there exists some `i` such that `s[i] != s[0]`.
    // Since `s` is a palindrome, `s[i] == s[n-1-i]`.
    //
    // Let's try to construct a new palindrome with 2 cuts.
    // Cut `s` into `s[0...j-1]`, `s[j...k-1]`, `s[k...n-1]`.
    //
    // The simplest way to get a new palindrome if `s` is not all same characters:
    // Take `s_prefix = s.substr(0, n/2)`.
    // If `s_prefix` is not a palindrome, then `s_prefix` itself can be used to form a new palindrome.
    // Example: "nolon", n=5. n/2 = 2. s_prefix = "no".
    // s_prefix is not a palindrome.
    //
    // The problem statement implies that if k=1 doesn't work, and the string is not all same characters, then k=2 is the answer.
    // This is a common pattern in competitive programming problems: if a simpler case doesn't work, a slightly more complex one is guaranteed.
    //
    // Let's verify this.
    // If `s` is a palindrome and not all characters are the same.
    // This means there exists at least one character `c` in `s` such that `c != s[0]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    //
    // Consider the string `s_half = s.substr(0, n/2)`.
    // If `s_half` is not a palindrome, then we can make a cut at `n/2`.
    // `s_left = s.substr(0, n/2)`
    // `s_right = s.substr(n/2)`
    // `s_prime = s_right + s_left`.
    // This is the k=1 case. If `s_prime` is a palindrome and `s_prime != s`, then k=1.
    //
    // What if `s_half` IS a palindrome?
    // Example: "abacaba", n=7. s_half = "aba". This is a palindrome.
    // s_left = "aba", s_right = "caba".
    // s_prime = "cabaaba". Not a palindrome.
    //
    // Example: "otto", n=4. s_half = "ot". Not a palindrome.
    // s_left = "ot", s_right = "to".
    // s_prime = "toot". Palindrome. "toot" != "otto". So k=1.
    //
    // Example: "nolon", n=5. s_half = "no". Not a palindrome.
    // s_left = "no", s_right = "lon".
    // s_prime = "lonno". Not a palindrome.
    //
    // The problem statement for "nolon" says k=2.
    // "no|l|on, and then unite them as follows on|l|no."
    // This is s[0...1] | s[2] | s[3...4].
    // Pieces: "no", "l", "on".
    // Rearrangement: "on" + "l" + "no" = "onlno".
    // "onlno" is a palindrome. "onlno" != "nolon".
    // This uses 2 cuts.
    //
    // This specific rearrangement is `s_3 s_2 s_1` where `s_1 = s[0...1]`, `s_2 = s[2]`, `s_3 = s[3...4]`.
    // This is `s[n-2...n-1]` + `s[n/2]` + `s[0...1]`.
    //
    // The logic for k=2:
    // If `s` is a palindrome and not all characters are the same, then it's always possible to find a new palindrome with 2 cuts.
    // The example "nolon" shows this.
    // The example "kinnikkinnik" shows k=1.
    // s = "kinnikkinnik", n=12.
    // s_left = "kinnikkinn", s_right = "ik".
    // s_prime = "ikkinnikkinn". This is a palindrome. "ikkinnikkinn" != "kinnikkinnik". So k=1.
    //
    // The only case where it's impossible is when all characters are the same.
    // If all characters are the same, any permutation of pieces will result in the same string.
    // E.g., "qqqq". Pieces "q", "q", "qq". Any order gives "qqqq".
    //
    // So the logic is:
    // 1. Check for k=1. Iterate all `n-1` possible cut points. If `s_right + s_left` is a palindrome and `!= s`, output 1.
    // 2. If no k=1 solution, check if all characters in `s` are the same. If yes, output "Impossible".
    // 3. Otherwise (no k=1 solution, but not all characters are the same), output 2.

    // The logic seems sound. The problem guarantees `s` is a palindrome.
    // The only remaining case is when `s` is a palindrome, not all characters are the same, and no k=1 solution exists.
    // In this case, the answer is 2.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    long long min_val = std::numeric_limits<long long>::max();
    int min_idx = -1;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long total_spells = 0;
    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each pile a[i] (that is not the smallest pile),
        // we can add min_val to it until it exceeds k.
        // The number of times we can add min_val to a[i] is (k - a[i]) / min_val.
        // Note: k - a[i] must be non-negative for any additions to be possible.
        // Since a[i] <= k initially, k - a[i] >= 0.
        // If min_val is 0, this would be division by zero, but problem constraints state 1 <= a_i.
        total_spells += (k - a[i]) / min_val;
    }
    std::cout << total_spells << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

