    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To maximize the binary number, we want as many '1's as possible,
    // followed by '0's.
    // Each '1' uses 'o', 'n', 'e'.
    // Each '0' uses 'z', 'e', 'r', 'o'.

    // The number of '1's is limited by the count of 'n'.
    // If we form `k` ones, we use `k` 'n's, `k` 'o's, `k` 'e's.
    // The remaining letters will be used for '0's.
    // The number of '0's is limited by the count of 'z'.

    int num_ones = count_n; // Each 'one' requires one 'n'
    int num_zeros = count_z; // Each 'zero' requires one 'z'

    // Print '1's first
    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    // Print '0's next
    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

