int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick n numbers starting from 2*n and going downwards,
        // skipping multiples of 3.
        // This ensures all chosen numbers are even, so gcd(a,b) >= 2.
        // Also, by picking numbers in a specific range and skipping multiples of 3,
        // we avoid divisibility issues.
        // For n=1, 2*1 = 2. Output 2.
        // For n=2, 2*2 = 4. Output 4, 6.
        // For n=3, 2*3 = 6. Output 4, 6, 10.
        // For n=4, 2*4 = 8. Output 8, 10, 12, 14.
        // The pattern seems to be: start from 2*n, and pick n numbers,
        // incrementing by 2, but ensuring they are not multiples of 3.
        // A simpler pattern that works:
        // For n kids, pick n numbers: 2*n + 2, 2*n + 4, ..., 2*n + 2*n = 4*n.
        // This is n numbers, all even.
        // Example: n=2. Chairs 1 to 8.
        // 2*2+2 = 6, 2*2+4 = 8. Output: 6 8.
        // gcd(6,8)=2. 6 does not divide 8, 8 does not divide 6. This works.
        // Example: n=3. Chairs 1 to 12.
        // 2*3+2 = 8, 2*3+4 = 10, 2*3+6 = 12. Output: 8 10 12.
        // gcd(8,10)=2, gcd(8,12)=4, gcd(10,12)=2. No divisibility. This works.
        // Example: n=4. Chairs 1 to 16.
        // 2*4+2 = 10, 2*4+4 = 12, 2*4+6 = 14, 2*4+8 = 16. Output: 10 12 14 16.
        // This strategy seems to work for all examples.
        // All numbers are even, so gcd(a,b) is always >= 2.
        // The numbers are of the form 2*(n+1), 2*(n+2), ..., 2*(2n).
        // Let a = 2*(n+i) and b = 2*(n+j) where 1 <= i < j <= n.
        // If a divides b, then 2*(n+i) divides 2*(n+j), which means (n+i) divides (n+j).
        // Since i < j, n+i < n+j.
        // If (n+i) divides (n+j), then (n+i) must be a factor of (n+j).
        // But n+j = (n+i) + (j-i).
        // For (n+i) to divide (n+j), (n+i) must divide (j-i).
        // However, 1 <= i < j <= n.
        // So 1 <= j-i <= n-1.
        // And n+1 <= n+i <= 2n-1.
        // It's impossible for a number n+i (which is >= n+1) to divide j-i (which is <= n-1),
        // unless j-i is 0, which is not possible as i < j.
        // Thus, no number in the sequence 2*(n+1), ..., 2*(2n) divides another.
        // This strategy is correct.

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (n + 1 + i) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

