int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks needed: k for crafting + k*y for buying k coal
        long long total_sticks_needed = k * y + k;

        // We start with 1 stick.
        // Each stick trade (1 stick -> x sticks) effectively increases our stick count by (x - 1).
        // We need to reach total_sticks_needed sticks.
        // We already have 1 stick. So we need to gain (total_sticks_needed - 1) more sticks
        // using the stick trade.

        // Number of stick trades needed:
        // (total_sticks_needed - 1) / (x - 1)
        // Since we need to gain at least (total_sticks_needed - 1) sticks,
        // we use ceiling division: ((total_sticks_needed - 1) + (x - 1) - 1) / (x - 1)
        // which simplifies to (total_sticks_needed - 2 + x) / (x - 1)
        // Or, more simply, (total_sticks_needed - 1) / (x - 1) and if there's a remainder, add 1.
        // This is equivalent to (total_sticks_needed - 1 + (x - 1) - 1) / (x - 1) if x-1 > 0
        // which is (total_sticks_needed - 2 + x) / (x - 1)

        // Let's use a more direct approach for ceiling division:
        // num_stick_trades = (total_sticks_needed - 1 + (x - 1) - 1) / (x - 1)
        // This is equivalent to (total_sticks_needed - 1 + (x - 2)) / (x - 1)
        // if x-1 is positive.
        // Since x >= 2, x-1 >= 1, so x-1 is always positive.

        long long num_stick_trades = (total_sticks_needed - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = num_stick_trades (to get enough sticks) + k (to get k coal)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

