        }
    }

    int free_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_taken[j]) {
            free_cols++;
        }
    }

    int moves_possible = std::min(free_rows, free_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

