        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic works because if p[i] is n, then min(n, p[j]) = p[j] for all j.
        // The maximum of these p[j] (for j != i) would be n-1 (since n is taken by p[i]).
        // So, if max_val_in_row is n-1, p[i] must be n.
        // In all other cases, p[i] is simply max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
