int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point (cell 0)

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos.
                // The gap is (i+1) - (last_r_pos + 1) + 1 = i - last_r_pos.
                // This is the distance from the previous 'R' cell (or 0) to the current 'R' cell.
                // Example: s = "LRL", n=3
                // i=0, s[0]='L'. last_r_pos = -1.
                // i=1, s[1]='R'. current cell is 2. last_r_pos = -1.
                // Gap is 2 - (-1) = 3. max_gap = max(0, 3) = 3. last_r_pos = 1.
                // i=2, s[2]='L'.
                // After loop, last_r_pos = 1.
                // Final gap to n+1: (n+1) - (last_r_pos + 1) = (3+1) - (1+1) = 4 - 2 = 2.
                // max_gap = max(3, 2) = 3.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After the loop, consider the jump from the last 'R' (or 0 if no 'R's) to n+1.
        // The last 'R' was at index last_r_pos (0-indexed string).
        // This corresponds to cell (last_r_pos + 1).
        // The target is cell (n + 1).
        // The distance is (n + 1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, n - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

