int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order to generate only '1' as a difference.
    // The last number used from the alternating sequence is either 'left-1' or 'right+1'.
    // The next number to append should be 'k+2'.
    // The difference will be |(left-1) - (k+2)| or |(right+1) - (k+2)|.
    // If we just append k+2, k+3, ..., n, the differences will be 1.
    // This ensures no new distinct differences are introduced.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
