}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;

    std::vector<long long> nice_staircase_costs;
    long long current_n = 1;
    long long current_cost = 1;
    nice_staircase_costs.push_back(current_cost);

    // Precompute costs of nice staircases
    // A nice staircase with n stairs has n = 2^k - 1 for some k >= 1.
    // The cost is (2^k - 1) * (2^k) / 2.
    // Or, more simply, the cost of a nice staircase with 2^k - 1 stairs
    // is the sum of costs of all nice staircases with 2^j - 1 stairs for j=1 to k.
    // Cost(k) = Cost(k-1) + (2^(k-1))^2
    // Cost(k) = (2^k - 1) * (2^k) / 2
    // Let's use the recursive definition based on the problem's structure:
    // Cost(k) = 2 * Cost(k-1) + (2^(k-1))^2
    // Cost(1) = 1 (for n=1)
    // Cost(2) = 2 * Cost(1) + (2^1)^2 = 2*1 + 4 = 6 (for n=3)
    // Cost(3) = 2 * Cost(2) + (2^2)^2 = 2*6 + 16 = 12 + 16 = 28 (for n=7)
    // Cost(4) = 2 * Cost(3) + (2^3)^2 = 2*28 + 64 = 56 + 64 = 120 (for n=15)
    // This sequence is 1, 6, 28, 120, 496, 2016, ...
    // The formula for the cost of a nice staircase with n = 2^k - 1 stairs is:
    // C(k) = (2^k - 1) * 2^(k-1) * (2^k + 1) / 3
    // No, this is not correct.
    // The cost of a staircase with n stairs is n*(n+1)/2.
    // For n = 2^k - 1, the cost is (2^k - 1) * (2^k) / 2.
    // Let's re-derive the costs based on the problem's image and logic.
    // A nice staircase with n stairs is formed by a square of size (n+1)/2 * (n+1)/2
    // and two smaller nice staircases of size (n-1)/2 stairs.
    // This implies n must be of the form 2^k - 1.
    // Let N_k be the number of stairs for the k-th nice staircase (N_k = 2^k - 1).
    // Let C_k be the total cells for the k-th nice staircase.
    // C_1 (for N_1=1): 1*(1+1)/2 = 1.
    // C_2 (for N_2=3): 3*(3+1)/2 = 6.
    // C_3 (for N_3=7): 7*(7+1)/2 = 28.
    // C_4 (for N_4=15): 15*(15+1)/2 = 120.
    // C_5 (for N_5=31): 31*(31+1)/2 = 496.
    // This is the sequence of costs.
    // We need to generate these costs until they exceed 10^18.

    long long current_stairs_n = 1; // n for the current nice staircase
    while (true) {
        long long cost = current_stairs_n * (current_stairs_n + 1) / 2;
        if (cost > 2000000000000000000LL) { // A bit more than 10^18 to be safe
            break;
        }
        nice_staircase_costs.push_back(cost);

        // Next nice staircase has 2*current_stairs_n + 1 stairs
        // This is equivalent to 2^(k+1) - 1 if current_stairs_n = 2^k - 1
        current_stairs_n = 2 * current_stairs_n + 1;
    }

    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        // Iterate through the precomputed costs in descending order
        // This is a greedy approach. Always try to build the largest possible nice staircase.
        // This works because the costs are C_k = (2^k - 1) * 2^(k-1).
        // If we have enough cells for C_k, we can build it.
        // If we instead build two C_{k-1} staircases, their total cost is 2 * C_{k-1}.
        // C_k = (2^k - 1) * 2^(k-1)
        // C_{k-1} = (2^(k-1) - 1) * 2^(k-2)
        // 2 * C_{k-1} = (2^(k-1) - 1) * 2^(k-1)
        // Since (2^k - 1) > (2^(k-1) - 1) for k > 1, C_k > 2 * C_{k-1}.
        // This means building one larger staircase uses more cells than two smaller ones.
        // The greedy strategy of picking the largest possible staircase first is optimal.
        // Example: x=8. Costs: 1, 6, 28...
        // Try 6: x=8 >= 6. Build it. x = 8-6 = 2. count = 1.
        // Try 1: x=2 >= 1. Build it. x = 2-1 = 1. count = 2.
        // Result: 2. Correct for example.
        // Example: x=6. Costs: 1, 6, 28...
        // Try 6: x=6 >= 6. Build it. x = 6-6 = 0. count = 1.
        // Result: 1. Correct for example.

        for (int i = nice_staircase_costs.size() - 1; i >= 0; --i) {
            if (x >= nice_staircase_costs[i]) {
                x -= nice_staircase_costs[i];
                count++;
            }
        }
        std::cout << count << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            // If we still need open brackets and adding one won't exceed k/2
            // and we can still potentially form a valid sequence (balance < k/2 - open_count)
            // The condition `open_count < k / 2` is sufficient for picking open brackets.
            // The balance check `balance < k/2 - open_count` is implicitly handled by `open_count < k/2`
            // because balance can't exceed open_count.
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // If we have an open bracket to close (balance > 0)
            // and we still need close brackets (close_count < k/2)
            // and adding this close bracket won't make the total length exceed k
            // (open_count + close_count < k)
            if (balance > 0 && close_count < k / 2) {
                result += c;
                close_count++;
                balance--;
            }
        }
        // If we have collected k characters, we are done.
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

