            // And a `std::vector<int> unused_values;` to store available values for filling.
            // When `q_i > q_{i-1}`, `p_i = q_i`. Mark `q_i` as used.
            // When `q_i == q_{i-1}`, we need to find an unused `x < q_i`.
            // The `unused_values` can be populated with numbers not equal to any `q_j` where `q_j > q_{j-1}`.
            // Then sort `unused_values` in descending order.
            // For each `q_i == q_{i-1}`, pick the largest from `unused_values` that is less than `q_i`.

            // Let's try the simpler approach:
            // 1. Initialize `p` with `q_i` for all `i` where `q_i > q_{i-1}` (and `p_0 = q_0`).
            // 2. Keep track of used numbers in a `std::set<int> used_fixed_values`.
            // 3. Collect all numbers from 1 to `n` that are NOT in `used_fixed_values` into a `std::vector<int> remaining_values`.
            // 4. Sort `remaining_values` in descending order.
            // 5. Iterate through `p`. If `p_i` is not yet set (i.e., `q_i == q_{i-1}`), assign `p_i` the next value from `remaining_values`.
            // 6. Check validity: `p_i` must be `< q_i`.

            std::vector<bool> is_fixed(n, false); // true if p[i] is determined by q[i] > q[i-1]
            std::vector<bool> is_used_num(n + 1, false); // true if number j is used in p

            p[0] = q[0];
            is_fixed[0] = true;
            is_used_num[q[0]] = true;

            for (int i = 1; i < n; ++i) {
                if (q[i] > q[i-1]) {
                    p[i] = q[i];
                    is_fixed[i] = true;
                    if (is_used_num[q[i]]) { // Should not happen for valid q
                        possible = false;
                        break;
                    }
                    is_used_num[q[i]] = true;
                }
            }

            if (!possible) {
                std::cout << -1 << "\n";
                return;
            }

            std::vector<int> available_fill_values;
            for (int j = 1; j <= n; ++j) {
                if (!is_used_num[j]) {
