                }
            }
            std::sort(available_fill_values.rbegin(), available_fill_values.rend()); // Descending order

            int fill_idx = 0;
            for (int i = 0; i < n; ++i) {
                if (!is_fixed[i]) { // This means q[i] == q[i-1] (or i=0 and q[0] was already handled)
                    if (fill_idx >= available_fill_values.size()) {
                        possible = false; // Not enough numbers to fill
                        break;
                    }
                    int val_to_assign = available_fill_values[fill_idx];
                    if (val_to_assign >= q[i]) { // p_i must be < q_i
                        possible = false;
                        break;
                    }
                    p[i] = val_to_assign;
                    fill_idx++;
                }
            }

            if (!possible) {
                std::cout << -1 << "\n";
                return;
            }

            // Final check for validity (all p_i distinct, 1 <= p_i <= n, and prefix max property)
            // The construction ensures p_i are distinct and 1 <= p_i <= n.
            // We need to verify the prefix max property.
            // For fixed p_i (where q_i > q_{i-1}), p_i = q_i, so max(..., p_i) = q_i is satisfied.
            // For non-fixed p_i (where q_i == q_{i-1}), we assigned p_i < q_i.
            // So max(q_{i-1}, p_i) = q_{i-1} = q_i. This is also satisfied.
            // So the construction is valid if `possible` remains true.

            for (int i = 0; i < n; ++i) {
                std::cout << p[i] << (i == n - 1 ? "" : " ");
            }
            std::cout << "\n";
        }

    }


