void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    result.reserve(n);

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we extend the segment that contained {1, ..., m-1}
        // to include m.
        // The new segment must span from min(current_min_idx, pos[m])
        // to max(current_max_idx, pos[m]).

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // The length of the segment [current_min_idx, current_max_idx]
        // is (current_max_idx - current_min_idx + 1).
        // For m to be beautiful, this length must be exactly m.
        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

