    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int i = 0;
    while (i < n) {
        if (a[i] != b[i]) {
            // Found a differing bit at index i
            // Check if the next bit also differs and forms a '01' vs '10' or '10' vs '01' pattern
            // i.e., a[i] != b[i] AND a[i+1] != b[i+1] AND a[i] == b[i+1] AND a[i+1] == b[i]
            // This means a[i] and a[i+1] are swapped relative to b[i] and b[i+1]
            // Example: a = "01", b = "10" (a[i]=0, b[i]=1, a[i+1]=1, b[i+1]=0)
            // Here a[i] == b[i+1] ('0' == '0') and a[i+1] == b[i] ('1' == '1')
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] == b[i+1] && a[i+1] == b[i]) {
                // This is a swap candidate
                cost += 1; // Cost of swapping adjacent bits is |(i+1) - i| = 1
                i += 2;    // Both bits are now fixed, move past them
            } else {
                // Cannot swap with adjacent bit to fix both, or no such adjacent bit
                // Must flip this bit
                cost += 1; // Cost of flipping is 1
                i += 1;    // This bit is fixed, move to the next
            }
        } else {
            // Bits are already the same, move to the next
            i += 1;
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

