// Function to determine if Box 1 can be the special box
// Box 1: (-inf, -1]
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // To end up in Box 1, the final product must be negative and <= -1.
    // This requires an odd number of negative factors.
    // The magnitude must be >= 1.

    // Case 1: Final product is negative.
    // This means the total count of negative numbers (initial A + initial B)
    // must be odd.
    if ((A + B) % 2 == 0) { // Even number of negatives, final product is positive or zero (not possible)
        return false;
    }

    // Now we know the final product is negative. We need its magnitude to be >= 1.
    // The magnitude of the product is |prod(all fun values)|.
    // If there's at least one toy in Box 1 or Box 4, we can always make the magnitude >= 1.
    // If all toys are in Box 2 or Box 3, the magnitude will be < 1.
    // So, if A+D > 0, we can achieve magnitude >= 1.
    if (A + D > 0) {
        return true;
    } else {
        // All toys are in Box 2 or Box 3.
        // The product of numbers in (-1, 0) and (0, 1) will always be in (-1, 1).
        // So, it cannot be <= -1.
        return false;
    }
}

// Function to determine if Box 2 can be the special box
// Box 2: (-1, 0)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // To end up in Box 2, the final product must be negative and between -1 and 0.
    // This requires an odd number of negative factors.
    // The magnitude must be < 1.

    // Case 1: Final product is negative.
    // This means the total count of negative numbers (initial A + initial B)
    // must be odd.
    if ((A + B) % 2 == 0) { // Even number of negatives, final product is positive or zero (not possible)
        return false;
    }

    // Now we know the final product is negative. We need its magnitude to be < 1.
    // The magnitude of the product is |prod(all fun values)|.
    // If all toys are in Box 2 or Box 3, the magnitude will be < 1.
    // If there's at least one toy in Box 1 or Box 4, we can potentially make the magnitude >= 1.
    // However, we can always choose values such that the product is < 1.
    // For example, if we have a toy with value 2 (from Box 4) and a toy with value -0.1 (from Box 2),
    // we can choose other values to make the product small.
    // The only way to guarantee magnitude < 1 is if all initial toys are in Box 2 or Box 3.
    // But the question is "can be", not "must be".
    // If A+D > 0, can we still make the magnitude < 1?
    // Yes, if we have at least one toy in Box 2 or Box 3.
    // For example, if we have {2, -0.1, 0.5}. Product is -0.1. Box 2.
    // If we have {2, -3, 0.1}. Product is -0.6. Box 2.
    // The only way we *cannot* make the magnitude < 1 is if all toys are in Box 1 or Box 4,
    // AND the number of toys is 1.
    // If A+D > 0 and B+C > 0, we can always pick values such that the product is < 1.
    // For example, if we have a toy in Box 1/4 (value X) and a toy in Box 2/3 (value Y).
    // We can pick Y very close to 0, so X*Y is close to 0.
    // If all toys are in Box 1 or Box 4 (B=0, C=0):
    //   If A+D == 1, then the single toy is either in Box 1 or Box 4.
    //     If it's in Box 1, it's <= -1. Not Box 2.
    //     If it's in Box 4, it's >= 1. Not Box 2.
    //   If A+D > 1, and B=0, C=0:
    //     All products will have magnitude >= 1.
    //     Example: {-2, -3, 2}. Product is 12.
    //     Example: {-2, 3}. Product is -6.
    //     So if B=0 and C=0, and A+D > 0, it cannot be Box 2.

    if (B == 0 && C == 0) { // All toys are in Box 1 or Box 4
        return false; // Product magnitude will always be >= 1
    }

    // If there's at least one toy in Box 2 or Box 3 (B+C > 0),
    // and (A+B) is odd, then we can always choose values such that the final product is in (-1, 0).
    // We can make the product arbitrarily close to 0 by picking one value very close to 0.
    return true;
}

// Function to determine if Box 3 can be the special box
// Box 3: (0, 1)
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // To end up in Box 3, the final product must be positive and between 0 and 1.
    // This requires an even number of negative factors.
    // The magnitude must be < 1.

    // Case 1: Final product is positive.
    // This means the total count of negative numbers (initial A + initial B)
    // must be even.
    if ((A + B) % 2 != 0) { // Odd number of negatives, final product is negative
        return false;
    }

    // Now we know the final product is positive. We need its magnitude to be < 1.
    // Similar logic to Box 2.
    if (B == 0 && C == 0) { // All toys are in Box 1 or Box 4
        return false; // Product magnitude will always be >= 1
    }

    // If there's at least one toy in Box 2 or Box 3 (B+C > 0),
    // and (A+B) is even, then we can always choose values such that the final product is in (0, 1).
    return true;
}

// Function to determine if Box 4 can be the special box
// Box 4: [1, inf)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // To end up in Box 4, the final product must be positive and >= 1.
    // This requires an even number of negative factors.
    // The magnitude must be >= 1.

    // Case 1: Final product is positive.
    // This means the total count of negative numbers (initial A + initial B)
    // must be even.
    if ((A + B) % 2 != 0) { // Odd number of negatives, final product is negative
        return false;
    }

    // Now we know the final product is positive. We need its magnitude to be >= 1.
    // If there's at least one toy in Box 1 or Box 4, we can always make the magnitude >= 1.
    // If all toys are in Box 2 or Box 3, the magnitude will be < 1.
    // So, if A+D > 0, we can achieve magnitude >= 1.
    if (A + D > 0) {
        return true;
    } else {
        // All toys are in Box 2 or Box 3.
        // The product of numbers in (-1, 0) and (0, 1) will always be in (0, 1).
        // So, it cannot be >= 1.
        return false;
    }
}


