#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each x[i] as the leftmost point of a triplet,
        // find the maximum index 'right_ptr' such that x[right_ptr] - x[i] <= d.
        // Since x is sorted, we can advance right_ptr monotonically.
        // The condition for right_ptr is x[right_ptr] <= x[i] + d.
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }
        // At this point, all points from x[i] to x[right_ptr - 1] satisfy the condition
        // x[k] - x[i] <= d.
        // We need to choose two distinct points x[j] and x[k] such that i < j < k.
        // These two points must be chosen from the range (x[i], x[right_ptr - 1]].
        // The number of points available for j and k is (right_ptr - 1) - i.
        // Let m = (right_ptr - 1) - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        // The number of points available for j and k is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let num_available_for_jk = (right_ptr - 1) - i.
        // This is the count of points from index i+1 up to right_ptr-1.
        // If num_available_for_jk < 2, we cannot form a triplet, so we add 0.
        long long num_available_for_jk = (long long)(right_ptr - 1) - i;
        if (num_available_for_jk >= 2) {
            count += num_available_for_jk * (num_available_for_jk - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
