int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median (a[0]...a[median_idx-1])
    // must be <= s. If any a[i] > s, we must decrease it to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median (a[median_idx+1]...a[n-1])
    // must be >= s. If any a[i] < s, we must increase it to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Calculate is_prefix_perm
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    int distinct_count_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > i + 1) { // Element value cannot exceed current length
            break;
        }
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            distinct_count_prefix++;
        }
        max_val_prefix = std::max(max_val_prefix, a[i]);
        if (distinct_count_prefix == i + 1 && max_val_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Calculate is_suffix_perm
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    int distinct_count_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] > current_len) { // Element value cannot exceed current length
            break;
        }
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            distinct_count_suffix++;
        }
        max_val_suffix = std::max(max_val_suffix, a[i]);
        if (distinct_count_suffix == current_len && max_val_suffix == current_len) {
            is_suffix_perm[current_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

