int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Create pairs (B_i, original_index_of_B_i) and sort them by B_i in ascending order
    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_indexed[i] = {b[i], i};
    }
    std::sort(b_indexed.begin(), b_indexed.end());

    // The strategy is to assign the largest A_i to the B_i that results in the largest F(A_i, B_i).
    // F(n, k) = (n+1) / (k+1).
    // To maximize F(A_i, B_i), we want to maximize (A_i+1) / (B_i+1).
    // This means we want to assign large A_i to small B_i.
    // So, sort A in ascending order.
    // Sort B in ascending order.
    // Assign A[i] to B[m-1-i] (i.e., smallest A to largest B, largest A to smallest B).
    // This maximizes the sum.

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // b_indexed[i] contains the i-th smallest B value and its original index.
        // We want to assign the (m-1-i)-th largest A value to this B value.
        // The (m-1-i)-th largest A value is a[m-1-i] because 'a' is sorted ascending.
        result_a_prime[b_indexed[i].second] = a[m - 1 - i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    long long opponent_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_score += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1
                // Remaining N-1. Opponent gets (N-1)/2 if N-1 is odd, or (N-1)/2 if N-1 is even.
                // This is complex. Let's analyze the optimal strategy.

                // If N is even, Chanek has two choices: take 1 or take N/2.
                // Chanek wants to maximize his score.
                // Opponent wants to maximize their score.

                // Case 1: N is a power of 2 (N = 2^k, k >= 1)
                // If Chanek takes 1: N-1 coins left. N-1 is odd.
                //   Opponent takes 1. N-2 coins left.
                //   Chanek takes 1. N-3 coins left.
                //   ... This continues until N becomes 0.
                //   Effectively, if N is a power of 2, and Chanek takes 1,
                //   the remaining N-1 coins will be split 1 by 1.
                //   Chanek gets 1 + (N-1)/2 coins.
                //   Opponent gets (N-1)/2 coins.
                // If Chanek takes N/2: N/2 coins left. N/2 is also a power of 2 (2^(k-1)).
                //   The game continues with N/2 coins.
                //   This is a recursive structure.
                //   Let f(x) be the score Chanek gets if he starts with x coins.
                //   If x is a power of 2:
                //     f(x) = max(1 + (x-1)/2, x/2 + (x/2 - f(x/2)))
                //     This is not quite right because f(x/2) is the score of the player who starts with x/2.
                //     Let's use the greedy strategy derived from observation.

                // The greedy strategy for even N:
                // If N is even, and not a power of 2, Chanek should take N/2.
                // If N is a power of 2, Chanek should take 1.

                // How to check if N is a power of 2?
                // N > 0 && (N & (N - 1)) == 0
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    chanek_score += 1;
                    n -= 1;
                } else { // N is even, but not a power of 2
                    chanek_score += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            // Opponent also plays optimally to maximize their score.
            // The logic for the opponent is symmetric to Chanek's.
            if (n % 2 != 0) { // N is odd
                opponent_score += 1;
                n -= 1;
            } else { // N is even
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    opponent_score += 1;
                    n -= 1;
                } else { // N is even, but not a power of 2
                    opponent_score += n / 2;
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_score;
}

