int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        long long current_score = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (i == 0 || s[i - 1] == 'L') {
                    current_score += 1;
                } else { // s[i-1] == 'W'
                    current_score += 2;
                }
            }
        }

        std::vector<int> gaps;
        int first_W = -1;
        int last_W = -1;

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        if (first_W == -1) { // All 'L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // Change k 'L's to 'W's.
                // If k >= n, all become 'W's. Score: 1 + 2*(n-1) = 2*n - 1
                // If k < n, change k 'L's to 'W's. Best to make them consecutive.
                // Score: 1 + 2*(k-1) = 2*k - 1.
                // This is equivalent to 2*k - 1 if k > 0, else 0.
                // If k=1, score is 1.
                // If k=0, score is 0.
                std::cout << std::max(0LL, 2 * k - 1) << "\n";
            }
            continue;
        }

        // Fill 'L's before the first 'W'
        long long l_before_first_W = first_W;
        long long l_after_last_W = n - 1 - last_W;

        // Collect gaps between 'W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        // Process gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len; // Each 'L' in a gap becomes 'W', connecting two 'W's, adding 2 points per 'L'
            } else {
                break; // Cannot fill this gap or any larger ones
            }
        }

        // Fill 'L's after the last 'W'
        if (k >= l_after_last_W) {
            k -= l_after_last_W;
            current_score += 2 * l_after_last_W; // Each 'L' becomes 'W', extending the last 'W' streak
        } else {
            current_score += 2 * k;
            k = 0;
        }

        // Fill 'L's before the first 'W'
        if (k > 0) {
            if (k >= l_before_first_W) {
                k -= l_before_first_W;
                current_score += 2 * l_before_first_W; // Each 'L' becomes 'W', extending the first 'W' streak
            } else {
                current_score += 2 * k;
                k = 0;
            }
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

