#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        // We need to append elements x1, x2, ... such that:
        // (current_sum + sum(x_i)) = 2 * (current_xor_sum ^ xor_sum(x_i))

        // Strategy: Append two elements.
        // Let the two elements be X and Y.
        // We want (current_sum + X + Y) = 2 * (current_xor_sum ^ X ^ Y)

        // Let's try to make the XOR sum equal to current_xor_sum.
        // If we append X = current_xor_sum, then new_xor_sum = current_xor_sum ^ current_xor_sum = 0.
        // Then we need (current_sum + current_xor_sum + Y) = 2 * 0 = 0.
        // This would require current_sum + current_xor_sum + Y = 0, which is impossible for non-negative Y.

        // Let's try to make the XOR sum equal to some value K.
        // We need current_sum + X + Y = 2K.
        // And current_xor_sum ^ X ^ Y = K.

        // Consider appending two elements: current_xor_sum and current_sum + current_xor_sum.
        // Let X = current_xor_sum.
        // Let Y = current_sum + current_xor_sum.
        // This is not quite right. The problem states we can append at most 3 elements.
        // A common strategy for these problems is to append 2 elements:
        // 1. The current XOR sum (X_orig).
        // 2. A value that makes the sum equal to twice the new XOR sum.

        // Let's append two elements:
        // b1 = current_xor_sum
        // b2 = current_sum + current_xor_sum

        // New XOR sum: X_new = current_xor_sum ^ b1 ^ b2
        // X_new = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X_new = 0 ^ (current_sum + current_xor_sum)
        // X_new = current_sum + current_xor_sum

        // New sum: S_new = current_sum + b1 + b2
        // S_new = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S_new = 2 * (current_sum + current_xor_sum)

        // Check condition: S_new == 2 * X_new
        // 2 * (current_sum + current_xor_sum) == 2 * (current_sum + current_xor_sum)
        // This holds true!

        // So, we can always append two elements:
        // b1 = current_xor_sum
        // b2 = current_sum + current_xor_sum

        // These values are non-negative since all initial a_i are non-negative.
        // current_sum can be up to 10^5 * 10^9 = 10^14.
        // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
        // So b2 can be up to 10^14 + 10^9, which fits in long long.

        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

