#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long correct_nestings = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        if (m == 0) continue; // Should not happen based on constraints (m_i >= 1)

        int prev_doll;
        std::cin >> prev_doll; // Read a_i1

        for (int j = 1; j < m; ++j) {
            int current_doll;
            std::cin >> current_doll; // Read a_i(j+1)
            if (prev_doll + 1 == current_doll) {
                correct_nestings++;
            }
            prev_doll = current_doll;
        }
    }

    // Total operations needed for the final chain: n-1 nestings.
    // Each correct_nesting saves one "put in" operation.
    // So, (n-1) - correct_nestings "put in" operations are needed.
    //
    // Each initial chain requires one "put in" operation to connect it to the main chain,
    // unless it's the chain starting with 1 and continuing correctly.
    // The number of chains that need to be "put in" is k.
    // However, if a chain starts with 1 and continues correctly, it doesn't need an initial "put in" operation.
    // The problem states "assemble them into a single large chain (1 -> 2 -> ... -> n)".
    // This implies that the first doll '1' is the base.
    //
    // Let's re-evaluate the operations:
    // Total operations to build 1->2->...->n from individual dolls is n-1.
    // If we have 'correct_nestings' already, we save 'correct_nestings' "put in" operations.
    // So, we need (n-1) - correct_nestings "put in" operations.
    //
    // To achieve these "put in" operations, we might need "get out" operations.
    //
    // Consider the total number of dolls that are NOT part of a correct sequence 1->2->...->N.
    // Each doll that is not part of such a sequence must be taken out and put back in.
    //
    // The number of dolls that are part of a correct sequence 1->2->...->N is (correct_nestings + 1).
    // For example, if we have 1->2->3, correct_nestings = 2, dolls = 3.
    //
    // The number of dolls that are NOT part of the correct sequence 1->2->...->N is n - (correct_nestings + 1).
    // Each of these dolls needs to be taken out. This costs n - (correct_nestings + 1) seconds.
    //
    // After taking them out, we have k chains and n - (correct_nestings + 1) individual dolls.
    // We need to assemble the final chain.
    //
    // The total number of "put in" operations required for the final chain is n-1.
    // We already have 'correct_nestings' of these.
    // So, we need to perform (n-1) - correct_nestings new "put in" operations.
    //
    // The total time is the sum of "get out" operations and "put in" operations.
    //
    // Number of "get out" operations:
    // Each doll that is nested but not part of the final 1->2->...->N sequence needs to be taken out.
    // This is equivalent to saying: for each existing nesting `a -> b` where `b != a+1`, we need to take `a` out of `b`.
    // The total number of existing nestings is `n - k`.
    // The number of correct existing nestings is `correct_nestings`.
    // So, the number of "incorrect" existing nestings is `(n - k) - correct_nestings`.
    // Each of these requires one "get out" operation.
    //
    // Number of "put in" operations:
    // We need `n-1` total nestings in the final configuration.
    // We already have `correct_nestings` of these.
    // So, we need `(n-1) - correct_nestings` new "put in" operations.
    //
    // Total time = (number of "get out" operations) + (number of "put in" operations)
    // Total time = ((n - k) - correct_nestings) + ((n - 1) - correct_nestings)
    // Total time = n - k - correct_nestings + n - 1 - correct_nestings
    // Total time = 2*n - k - 1 - 2*correct_nestings
    //
    // Let's re-check with examples.
    // Example 1:
    // n=3, k=2
    // Chain 1: 2 1 2
    // Chain 2: 1 3
    //
    // correct_nestings:
    // 1->2 is correct. (1)
    // Total correct_nestings = 1.
    //
    // Formula: 2*n - k - 1 - 2*correct_nestings
    // = 2*3 - 2 - 1 - 2*1
    // = 6 - 2 - 1 - 2
    // = 1. Correct.
    //
    // Example 2:
    // n=7, k=3
    // Chain 1: 3 1 3 7
    // Chain 2: 2 2 5
    // Chain 3: 2 4 6
    //
    // correct_nestings:
    // Chain 1: 1->3 (incorrect), 3->7 (incorrect)
    // Chain 2: 2->5 (incorrect)
    // Chain 3: 4->6 (incorrect)
    // Total correct_nestings = 0.
    //
    // Formula: 2*n - k - 1 - 2*correct_nestings
    // = 2*7 - 3 - 1 - 2*0
    // = 14 - 3 - 1 - 0
    // = 10. Correct.

    long long total_time = (long long)2 * n - k - 1 - (long long)2 * correct_nestings;

    std::cout << total_time << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    // p is divisible by q. We need to find the largest divisor x of p such that x is not divisible by q.
    // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
    // If x is divisible by q, then x must be divisible by f_i^a_i for all i.
    // To make x not divisible by q, we need to remove enough factors from p such that x is no longer divisible by at least one f_i^a_i.
    // Specifically, for some prime factor f_i of q, the power of f_i in x must be less than the power of f_i in q.

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_q_factor_power = 1;
            while (temp_q % i == 0) {
                current_q_factor_power *= i;
                temp_q /= i;
            }

            // Now current_q_factor_power holds i^a_i for this prime i.
            // We need to find the largest x that divides p such that x is not divisible by q.
            // Consider p' = p / (i^k) such that p' is not divisible by q.
            // To make p' not divisible by q, we must ensure that for this prime factor i,
            // the power of i in p' is less than the power of i in q.
            // The simplest way to achieve this is to divide p by i until it's no longer divisible by current_q_factor_power.
            // Or, more precisely, divide p by i until the power of i in p is less than the power of i in q.

            long long current_p = p;
            while (current_p % current_q_factor_power == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);
        }
    }

    // If temp_q is still greater than 1, it means temp_q itself is a prime factor.
    if (temp_q > 1) {
        long long current_q_factor_power = temp_q; // This is the prime factor itself
        long long current_p = p;
        while (current_p % current_q_factor_power == 0) {
            current_p /= temp_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

