int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // First, handle friends with w_i = 1.
        // They should get the largest remaining numbers, each as their only number.
        // Their happiness will be 2 * number.
        // Since w is sorted, these are at the beginning of w.
        for (int i = 0; i < k; ++i) {
            if (w[i] == 1) {
                total_happiness += 2 * a[a_ptr_right];
                a_ptr_right--;
            } else {
                // All subsequent w_i will be > 1 because w is sorted.
                // Break and handle them in the next loop.
                // This also means we process w_i=1 from smallest w_i to largest w_i,
                // which corresponds to smallest w_i values in the sorted w array.
                // These friends get the largest available numbers.
                // The largest numbers are at a_ptr_right.
                // So, we assign a[a_ptr_right] to the friend with w[i]=1.
                // This is correct.
                break;
            }
        }

        // Now, handle friends with w_i > 1.
        // These friends need a max and a min.
        // To maximize sum of happiness, we give the largest remaining numbers as max_val
        // and the smallest remaining numbers as min_val.
        // The friends with larger w_i values need more numbers, so they will consume more
        // of the 'middle' numbers.
        // The friends with smaller w_i values (but > 1) should get the smallest available numbers
        // as their min_val, and the largest available numbers as their max_val.
        // Since w is sorted, w[0]...w[k-1] are sorted.
        // We already processed w_i=1.
        // The remaining w_i are all > 1.
        // We iterate through w from largest w_i to smallest w_i (excluding w_i=1).
        // This means iterating from k-1 down to the first w_i > 1.
        // The friends with larger w_i values will consume more numbers.
        // To maximize happiness, we want to give the largest available number to each friend as their max_val.
        // And the smallest available number to each friend as their min_val.
        // The largest available numbers are at a_ptr_right.
        // The smallest available numbers are at a_ptr_left.

        // Iterate w from largest to smallest (excluding w_i=1, which were handled).
        // The largest w_i values are at the end of the sorted w array.
        // The smallest w_i values (that are > 1) are at the beginning of the remaining w array.
        // We want to pair the largest remaining 'a' values with the largest 'w' values (for max_val)
        // and the smallest remaining 'a' values with the smallest 'w' values (for min_val).
        // This is tricky. Let's re-evaluate.

        // Each friend with w_i > 1 needs a max and a min.
        // There are `k_prime` such friends.
        // They will consume `k_prime` largest numbers for their max_val.
        // They will consume `k_prime` smallest numbers for their min_val.
        // The remaining numbers `w_i - 2` for each friend will be "middle" numbers.
        // These middle numbers don't affect happiness.
        // So, we should give the largest `k_prime` numbers from `a` to these `k_prime` friends as their max_val.
        // And the smallest `k_prime` numbers from `a` to these `k_prime` friends as their min_val.

        // Let's re-sort w in descending order to process friends who need more numbers first.
        // No, the current sort of w (ascending) is fine.
        // The friends with w_i = 1 were handled first, taking the largest available numbers.
        // Now, for friends with w_i > 1:
        // They will each get one of the remaining largest numbers as their max_val.
        // They will each get one of the remaining smallest numbers as their min_val.
        // The remaining w_i - 2 numbers they need will be taken from the 'middle' of the remaining `a` array.

        // The friends with w_i > 1 are at indices `i` where `w[i] > 1`.
        // Let's iterate from the end of `w` array backwards.
        // These are the friends who need the most numbers.
        // They will consume `w_i - 1` numbers from the `a_ptr_left` side.
        // And one number from `a_ptr_right` side.
        // This is the correct strategy:
        // For friends with w_i > 1:
        //   Give them `a[a_ptr_right]` as their max_val.
        //   Give them `a[a_ptr_left]` as their min_val.
        //   Then, they need `w_i - 2` more numbers. These numbers don't affect happiness.
        //   To save the largest/smallest numbers for other friends, these `w_i - 2` numbers
        //   should be taken from the `a_ptr_left` side, effectively moving `a_ptr_left` forward.

        // Iterate from the end of sorted `w` array backwards.
        // These are friends with largest `w_i` values.
        // They will consume `w_i - 1` numbers from the `a_ptr_left` side.
        // And one number from `a_ptr_right` side.
        // This is wrong. The largest `w_i` values should consume the most 'middle' numbers.
        // The smallest `w_i` values (that are > 1) should consume the fewest 'middle' numbers.

        // Correct approach for w_i > 1:
        // Each of these friends will get one of the remaining largest numbers as their max_val.
        // Each of these friends will get one of the remaining smallest numbers as their min_val.
        // The remaining `w_i - 2` numbers for each friend will be taken from the `a_ptr_left` side.
        // To maximize the sum of happiness, we want to give the largest available `a[a_ptr_right]`
        // to each friend as their max_val.
        // And the smallest available `a[a_ptr_left]` to each friend as their min_val.

        // The friends with `w_i > 1` are those for which `w[i]` is not 1.
        // Let's iterate through `w` from `k-1` down to `0`.
        // If `w[i] == 1`, we already handled it.
        // If `w[i] > 1`:
        //   This friend gets `a[a_ptr_right]` as max_val.
        //   This friend gets `a[a_ptr_left]` as min_val.
        //   `a_ptr_right` decreases by 1.
        //   `a_ptr_left` increases by 1.
        //   This friend needs `w[i] - 2` more numbers. These numbers are taken from `a_ptr_left` side.
        //   So, `a_ptr_left` increases by `w[i] - 2`.

        // This means we iterate `w` from `k-1` down to `0`.
        // If `w[i] == 1`, we skip it (already handled).
        // If `w[i] > 1`:
        //   `total_happiness += a[a_ptr_right] + a[a_ptr_left];`
        //   `a_ptr_right--;`
        //   `a_ptr_left += (w[i] - 1);` // This friend takes `a_ptr_left` and `w[i]-1` more from left.
        // This is the correct logic. The `w[i]-1` is because they take `a[a_ptr_left]` and then `w[i]-1` more.
        // So total `w[i]` numbers are taken from the left side.
        // No, `w[i]-1` is wrong. They take `a[a_ptr_left]` and `w[i]-2` more from the left.
        // So `a_ptr_left` advances by `1 + (w[i]-2) = w[i]-1`. This is correct.

        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                // Already handled in the first loop
                // The first loop processed w_i=1 from smallest w_i to largest w_i.
                // This means it processed w[0], w[1], ... as long as they were 1.
                // So, if w[i] is 1 here, it means it was already processed.
                // We can break if w[i] is 1, because all w[j] for j < i will also be 1.
                break;
            }
            // w[i] > 1
            total_happiness += a[a_ptr_right]; // Max value for this friend
            a_ptr_right--;
            total_happiness += a[a_ptr_left]; // Min value for this friend
            a_ptr_left += (w[i] - 1); // This friend consumes w[i]-1 more numbers from the left side
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

