#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each remainder i % k

    // Step 1: Propagate known characters and check for conflicts within each k-group
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int remainder = i % k;
            if (fixed_chars[remainder] == '?') {
                fixed_chars[remainder] = s[i];
            } else if (fixed_chars[remainder] != s[i]) {
                // Conflict: s[i] is '0' but fixed_chars[i%k] is '1', or vice versa
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Count '0's and '1's among the fixed characters in the first k positions
    int count0 = 0;
    int count1 = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        }
    }

    // Step 3: Check if it's possible to fill '?'s to satisfy k/2 balance
    // We need k/2 zeros and k/2 ones in total for the first k positions.
    // The remaining '?'s must be filled such that the total counts are k/2.
    // If count0 already exceeds k/2, or count1 already exceeds k/2, it's impossible.
    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we reach here, it means:
    // 1. No direct conflicts (e.g., s[i] = '0', s[i+k] = '1').
    // 2. The number of '0's and '1's determined for the first k positions
    //    does not exceed k/2 for either character.
    // We can always fill the remaining '?'s in fixed_chars to satisfy the k/2 condition.
    // For example, fill (k/2 - count0) '?'s with '0' and (k/2 - count1) '?'s with '1'.
    // The number of '?'s is k - count0 - count1.
    // (k/2 - count0) + (k/2 - count1) = k - count0 - count1.
    // This is exactly the number of '?'s, so it's always possible.

    std::cout << "YES\n";
}

