    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    for (int x = 0; x <= 9; ++x) {
        std::string colors(n, ' ');
        char last1 = '0' - 1; // Represents a value smaller than any digit
        char last2 = '0' - 1; // Represents a value smaller than any digit
        bool possible_x = true;

        // First pass: assign digits based on x
        // Digits < x go to color 1
        // Digits > x go to color 2
        // Digits == x are temporarily unassigned
        for (int i = 0; i < n; ++i) {
            if (d_str[i] < (char)('0' + x)) {
                colors[i] = '1';
                if (d_str[i] < last1) {
                    possible_x = false;
                    break;
                }
                last1 = d_str[i];
            } else if (d_str[i] > (char)('0' + x)) {
                colors[i] = '2';
                if (d_str[i] < last2) {
                    possible_x = false;
                    break;
                }
                last2 = d_str[i];
            }
        }

        if (!possible_x) {
            continue;
        }

        // Second pass: assign digits == x
        // Digits == x that are >= last1 go to color 1
        // Digits == x that are < last1 go to color 2
        // This is the tricky part. We want to put as many 'x's into color 1 as possible,
        // but only if they maintain the non-decreasing property of S1.
        // All 'x's that go to color 1 must be >= last1.
        // All 'x's that go to color 2 must be >= last2.
        // And if S1 is not empty, its last element must be <= first element of S2.

        // Let's refine the strategy for digits equal to x:
        // All digits d_i < x must be color 1.
        // All digits d_i > x must be color 2.
        // For digits d_i == x:
        //   If d_i appears before the first d_j > x, it can be color 1.
        //   If d_i appears after the last d_j < x, it can be color 2.
        // This is equivalent to finding the first occurrence of 'x' that we want to assign to color 2.
        // All 'x's before that point go to color 1, all 'x's from that point onwards go to color 2.

        // Let's try a simpler approach for 'x':
        // Find the first 'x' that we want to assign to color 2.
        // All 'x's before this point go to color 1.
        // All 'x's from this point onwards go to color 2.
        // This means we need to find a split point among the 'x's.
        // Let's try to find the *first* 'x' that we assign to color 2.
        // All 'x's before it are color 1, all 'x's from it are color 2.

        // Reset last1 and last2 for the actual check
        last1 = '0' - 1;
        last2 = '0' - 1;
        possible_x = true;

        // Find the split point for 'x's.
        // All 'x's before `split_idx` go to color 1.
        // All 'x's from `split_idx` onwards go to color 2.
        // If `split_idx` is `n`, all 'x's go to color 1.
        // If `split_idx` is `0`, all 'x's go to color 2.
        int split_idx = n; // Default: all 'x's go to color 1

        // Find the first 'x' that is *not* greater than or equal to the current `last1`
        // if we were to assign it to color 1.
        // This is not quite right. We need to find the first 'x' that we *must* assign to color 2
        // to maintain the sorted property of S1.
        // Or, more simply, we can iterate through all possible split points for 'x's.
        // This is equivalent to trying all `x` values from 0 to 9.
        // For each `x`, we try all possible positions `k` (from 0 to n) where the split for `x` occurs.
        // All `d_i = x` for `i < k` are color 1.
        // All `d_i = x` for `i >= k` are color 2.
        // This is too slow (N * 10 * N).

        // The correct logic for 'x' is:
        // All digits < x are color 1.
        // All digits > x are color 2.
        // For digits == x:
        //   We want to put as many as possible into color 1, then the rest into color 2.
        //   The transition point for 'x's is crucial.
        //   All 'x's before the transition point go to color 1.
        //   All 'x's from the transition point onwards go to color 2.
        //   The transition point is the first 'x' that is *less than* the `last1` seen so far.
        //   No, this is not right. `last1` is for digits < x.
        //   The `last1` for digits == x should be `x`.
        //   The `last2` for digits == x should be `x`.

        // Let's try to find the first index `k` such that `d_str[k] == '0' + x` and we assign it to color 2.
        // All `d_str[i] == '0' + x` for `i < k` are assigned to color 1.
        // All `d_str[i] == '0' + x` for `i >= k` are assigned to color 2.
        // If no such `k` exists, all `d_str[i] == '0' + x` are assigned to color 1.
        // If `k=0`, all `d_str[i] == '0' + x` are assigned to color 2.

        // We need to find the largest `last1_val` among digits assigned to color 1.
        // And the smallest `first2_val` among digits assigned to color 2.
        // And `last1_val <= first2_val`.

        // Let's try to find the split point for 'x's.
        // All digits `d_i < x` are color 1.
        // All digits `d_i > x` are color 2.
        // For `d_i == x`:
        //   If `d_i` is encountered and `d_i < last1` (where `last1` is the last digit assigned to color 1 so far),
        //   then this `d_i` *must* be color 2.
        //   If `d_i` is encountered and `d_i < last2` (where `last2` is the last digit assigned to color 2 so far),
        //   then this `d_i` *cannot* be color 2. This implies it must be color 1.
        //   This is a greedy approach.

        std::string current_colors(n, ' ');
        char current_last1 = '0' - 1;
        char current_last2 = '0' - 1;
        bool possible_current_x = true;

        for (int i = 0; i < n; ++i) {
            if (d_str[i] < (char)('0' + x)) {
                if (d_str[i] < current_last1) {
                    possible_current_x = false;
                    break;
                }
                current_colors[i] = '1';
                current_last1 = d_str[i];
            } else if (d_str[i] > (char)('0' + x)) {
                if (d_str[i] < current_last2) {
                    possible_current_x = false;
                    break;
                }
                current_colors[i] = '2';
                current_last2 = d_str[i];
            } else { // d_str[i] == '0' + x
                // Try to assign to color 1
                if (d_str[i] >= current_last1) {
                    current_colors[i] = '1';
                    current_last1 = d_str[i];
                } else { // Must assign to color 2
                    if (d_str[i] < current_last2) {
                        possible_current_x = false;
                        break;
                    }
                    current_colors[i] = '2';
                    current_last2 = d_str[i];
                }
            }
        }

        if (possible_current_x) {
            // Final check: last of S1 <= first of S2
            char final_last1 = '0' - 1;
            char final_first2 = '9' + 1;

            for (int i = 0; i < n; ++i) {
                if (current_colors[i] == '1') {
                    final_last1 = d_str[i];
                }
            }
            for (int i = 0; i < n; ++i) {
                if (current_colors[i] == '2') {
                    final_first2 = d_str[i];
                    break;
                }
            }

            if (final_last1 <= final_first2) {
                std::cout << current_colors << "\n";
                return;
            }
        }
    }

    std::cout << "-\n";
}

