#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

long long solve() {
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        return 0;
    }
    if (n == 1) {
        return (h[0] + 1) / 2;
    }

    std::vector<long long> L(n), R(n);

    // Calculate L[i]: minimum operations to destroy blocks up to height h[i]
    // considering only towers to the left (and current tower)
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        L[i] = 1; // At least 1 operation for the top block
        if (h[i] > h[i-1]) {
            L[i] = L[i-1] + 1;
        } else { // h[i] <= h[i-1]
            L[i] = h[i];
        }
        L[i] = std::min(L[i], h[i]); // Cannot take more operations than tower height
    }

    // Calculate R[i]: minimum operations to destroy blocks up to height h[i]
    // considering only towers to the right (and current tower)
    R[n-1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        R[i] = 1; // At least 1 operation for the top block
        if (h[i] > h[i+1]) {
            R[i] = R[i+1] + 1;
        } else { // h[i] <= h[i+1]
            R[i] = h[i];
        }
        R[i] = std::min(R[i], h[i]); // Cannot take more operations than tower height
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    return max_ops;
}

