    std::cout << solve() << std::endl;
    return 0;
}

#include <iostream>

long long sum_up_to(long long k) {
    if (k <= 0) {
        return 0;
    }
    return k * (k + 1) / 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = sum_up_to(n);

        long long num_zeros = n - m;

        // To minimize substrings of all zeros, we want to distribute
        // the zeros as evenly as possible among the m+1 possible blocks.
        // This means making the lengths of zero blocks as close as possible.
        // The m '1's create m+1 potential segments for '0's.
        long long num_blocks = m + 1;

        long long k = num_zeros / num_blocks; // Base length for most zero blocks
        long long r = num_zeros % num_blocks; // Number of blocks that get an extra zero

        // r blocks will have length k+1
        // (num_blocks - r) blocks will have length k

        long long substrings_from_zeros = r * sum_up_to(k + 1) + (num_blocks - r) * sum_up_to(k);

        long long max_f_s = total_substrings - substrings_from_zeros;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

