    } else {
        // Operation 1: Handle n-1 elements (a[0] to a[n-2])
        // For each a[i], we want to add x_i such that (a[i] + x_i) % n == 0.
        // We can choose x_i = (n - (a[i] % n)) % n * n.
        // This makes a[i] + x_i a multiple of n.
        // The length of the segment is n.
        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = (a[i] % n + n) % n; // Ensure positive remainder
            long long add_val = remainder * (n - 1); // This is (n - remainder) * (n-1) if remainder is 0, it's 0.
                                                      // No, this is (n - remainder) * (n-1) if remainder is not 0.
                                                      // We want a[i] + x_i to be a multiple of n.
                                                      // We want a[i] + x_i = k * n.
                                                      // x_i must be a multiple of (n-1).
                                                      // So, a[i] + m*(n-1) = k*n.
                                                      // a[i] + m*n - m = k*n.
                                                      // a[i] - m = (k-m)*n.
                                                      // So, a[i] - m must be a multiple of n.
                                                      // This means m % n == a[i] % n.
                                                      // We need to find m such that m % n == a[i] % n and m is a multiple of (n-1).
                                                      // Let m = k' * (n-1).
                                                      // k' * (n-1) % n == a[i] % n.
                                                      // k' * (-1) % n == a[i] % n.
                                                      // -k' % n == a[i] % n.
                                                      // k' % n == (-a[i] % n + n) % n.
                                                      // Let target_k_prime = (-a[i] % n + n) % n.
                                                      // We can choose k' = target_k_prime.
