#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left part (jars 0 to n-1)
    // s_left[i] = (count of 1s) - (count of 2s) in jars 0 to i-1
    // s_left[0] = 0
    // s_left[1] = (a[0]==1 ? 1 : -1)
    // ...
    // s_left[n] = (count of 1s) - (count of 2s) in jars 0 to n-1
    std::vector<int> s_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_left[i + 1] = s_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right part (jars n to 2n-1)
    // s_right[i] = (count of 1s) - (count of 2s) in jars i to 2n-1
    // s_right[2n] = 0
    // s_right[2n-1] = (a[2n-1]==1 ? 1 : -1)
    // ...
    // s_right[n] = (count of 1s) - (count of 2s) in jars n to 2n-1
    std::vector<int> s_right(2 * n + 1, 0);
    for (int i = 2 * n - 1; i >= n; --i) {
        s_right[i] = s_right[i + 1] + (a[i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the right to achieve a certain balance
    // map: balance_value -> min_jars_removed_from_right
    std::map<int, int> right_balance_to_removed_count;
    for (int i = n; i <= 2 * n; ++i) { // i is the index of the first jar kept on the right
                                       // or 2n if all right jars are removed
        int jars_removed_from_right = i - n;
        int current_balance = s_right[i];
        if (right_balance_to_removed_count.find(current_balance) == right_balance_to_removed_count.end()) {
            right_balance_to_removed_count[current_balance] = jars_removed_from_right;
        } else {
            right_balance_to_removed_count[current_balance] = std::min(right_balance_to_removed_count[current_balance], jars_removed_from_right);
        }
    }

    int min_total_removed = 2 * n; // Initialize with maximum possible removals

    // Iterate through all possible numbers of jars removed from the left
    for (int i = 0; i <= n; ++i) { // i is the index of the first jar kept on the left
                                   // or 0 if all left jars are removed
        int jars_removed_from_left = n - i;
        int current_balance_left = s_left[i]; // Balance of jars 0 to i-1

        // We need the balance of remaining jars to be 0.
        // So, current_balance_left + current_balance_right = 0
        // current_balance_right = -current_balance_left
        int target_balance_right = -current_balance_left;

        if (right_balance_to_removed_count.count(target_balance_right)) {
            int jars_removed_from_right = right_balance_to_removed_count[target_balance_right];
            min_total_removed = std::min(min_total_removed, jars_removed_from_left + jars_removed_from_right);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

