int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits are 1
    int current_or_mask = 0;    // All bits are 0
    int current_xor_mask = 0;   // All bits are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    // Now we have the final state for 0, 1, and x.
    // Let x_0 be the result for input 0.
    // Let x_1 be the result for input 1.
    // For any input X, the i-th bit of the result is:
    // if (i-th bit of X is 0) then (i-th bit of x_0)
    // if (i-th bit of X is 1) then (i-th bit of x_1)

    // x_0 = (0 & current_and_mask) | current_or_mask ^ current_xor_mask
    // x_0 = 0 | current_or_mask ^ current_xor_mask
    // x_0 = current_or_mask ^ current_xor_mask

    // x_1 = (1 & current_and_mask) | current_or_mask ^ current_xor_mask
    // x_1 = current_and_mask | current_or_mask ^ current_xor_mask

    // Let's find the simplified operations.
    // We need to find A, O, X such that for any input `x`:
    // ((x & A) | O) ^ X == final_result(x)

    // Consider the effect on a single bit `b`:
    // If `b` is 0, it becomes `(0 & A) | O ^ X = O ^ X`.
    // This must be equal to `current_or_mask ^ current_xor_mask` (the result for input 0).
    // So, `O ^ X = current_or_mask ^ current_xor_mask`.

    // If `b` is 1, it becomes `(1 & A) | O ^ X = A | O ^ X`.
    // This must be equal to `current_and_mask | current_or_mask ^ current_xor_mask` (the result for input 1).
    // So, `A | O ^ X = current_and_mask | current_or_mask ^ current_xor_mask`.

    // Let `target_or_xor = current_or_mask ^ current_xor_mask`.
    // So, `O ^ X = target_or_xor`.

    // And `A | target_or_xor = current_and_mask | target_or_xor`.

    // We can choose `O` and `X` to satisfy `O ^ X = target_or_xor`.
    // A simple choice is `O = target_or_xor` and `X = 0`.
    // Or `O = 0` and `X = target_or_xor`.
    // Or `O = target_or_xor` and `X = 0`.
    // Or `O = target_or_xor & ~X` and `X = target_or_xor & X`.

    // Let's try to construct the final A, O, X.
    // For each bit position `j` from 0 to 9:
    // Let `b_0 = (current_or_mask >> j) & 1;`
    // Let `b_1 = ((current_and_mask | current_or_mask) >> j) & 1;`
    // Let `b_x = (current_xor_mask >> j) & 1;`

    // The final state of bit `j` for input `0` is `b_0 ^ b_x`.
    // The final state of bit `j` for input `1` is `b_1 ^ b_x`.

    // We want to find `A_j, O_j, X_j` such that:
    // `(0 & A_j) | O_j ^ X_j = b_0 ^ b_x`  => `O_j ^ X_j = b_0 ^ b_x`
    // `(1 & A_j) | O_j ^ X_j = b_1 ^ b_x`  => `A_j | O_j ^ X_j = b_1 ^ b_x`

    // Let `val_0_j = b_0 ^ b_x`.
    // Let `val_1_j = b_1 ^ b_x`.

    // We need `O_j ^ X_j = val_0_j`.
    // We need `A_j | val_0_j = val_1_j`.

    // From `A_j | val_0_j = val_1_j`:
    // If `val_0_j` is 0: `A_j | 0 = val_1_j` => `A_j = val_1_j`.
    // If `val_0_j` is 1: `A_j | 1 = val_1_j`. This implies `val_1_j` must be 1.
    // If `val_0_j` is 1 and `val_1_j` is 0, it's impossible to satisfy `A_j | 1 = 0`.
    // This case `val_0_j=1, val_1_j=0` means:
    // Input 0 -> 1
    // Input 1 -> 0
    // This is equivalent to `^ 1` for this bit.
    // So, `A_j` must be 1, `O_j` must be 0, `X_j` must be 1.
    // `(x & 1) | 0 ^ 1 = x ^ 1`.
    // If `x=0`, `0^1=1`. If `x=1`, `1^1=0`. This works.

    // Let's define the final A, O, X values.
    int final_A = 0;
    int final_O = 0;
    int final_X = 0;

    for (int j = 0; j < 10; ++j) {
        int bit_0_val = ((current_or_mask >> j) & 1) ^ ((current_xor_mask >> j) & 1);
        int bit_1_val = (((current_and_mask | current_or_mask) >> j) & 1) ^ ((current_xor_mask >> j) & 1);

        // Case 1: 0 -> 0, 1 -> 0
        // This means the bit is always 0, regardless of input.
        // We need `(x & A_j) | O_j ^ X_j = 0`.
        // Simplest: `& 0`. So `A_j=0, O_j=0, X_j=0`.
        if (bit_0_val == 0 && bit_1_val == 0) {
            // A_j = 0, O_j = 0, X_j = 0
            // This means `final_A` gets 0, `final_O` gets 0, `final_X` gets 0 for this bit.
        }
        // Case 2: 0 -> 0, 1 -> 1
        // This means the bit is always equal to the input bit.
        // We need `(x & A_j) | O_j ^ X_j = x`.
        // Simplest: `& 1`. So `A_j=1, O_j=0, X_j=0`.
        else if (bit_0_val == 0 && bit_1_val == 1) {
            final_A |= (1 << j);
        }
        // Case 3: 0 -> 1, 1 -> 0
        // This means the bit is always the inverse of the input bit.
        // We need `(x & A_j) | O_j ^ X_j = ~x`.
        // Simplest: `^ 1`. So `A_j=1, O_j=0, X_j=1`.
        else if (bit_0_val == 1 && bit_1_val == 0) {
            final_A |= (1 << j);
            final_X |= (1 << j);
        }
        // Case 4: 0 -> 1, 1 -> 1
        // This means the bit is always 1, regardless of input.
        // We need `(x & A_j) | O_j ^ X_j = 1`.
        // Simplest: `| 1`. So `A_j=0, O_j=1, X_j=0`.
        else if (bit_0_val == 1 && bit_1_val == 1) {
            final_O |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If not all bits are 1 for AND, then we need an AND operation
        result_ops.push_back({'&', final_A});
    }
    if (final_O != 0) { // If not all bits are 0 for OR, then we need an OR operation
        result_ops.push_back({'|', final_O});
    }
    if (final_X != 0) { // If not all bits are 0 for XOR, then we need an XOR operation
        result_ops.push_back({'^', final_X});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false); // Tracks vertices currently in the graph

    // Process removals in reverse order
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = removal_order[k_idx]; // The vertex being added back to the graph

        active_vertices[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // This is the Floyd-Warshall update step
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue; // Only consider active vertices
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After updating paths using k, we also need to consider paths
        // that might now be shorter because k itself is a source or destination.
        // The previous loop already covers paths i->k->j.
        // We need to ensure all pairs (i,j) among active vertices are updated.
        // The standard Floyd-Warshall structure is k-outer, i-middle, j-inner.
        // Here, k is the vertex just added.
        // So, for all active i, j, we check if path i -> k -> j is shorter.
        // This is already done by the triple loop above.
        // The key is that `dist[i][j]` already holds the shortest path
        // considering all vertices `0...k_prev` (where `k_prev` was the last added vertex).
        // When `k` is added, we update `dist[i][j]` using `k`.
        // The triple loop structure correctly updates all pairs `(i,j)`
        // using `k` as an intermediate.

        // Calculate the sum of shortest paths for all currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before first removal, before second, etc.)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

