                            // (0,0) -> (1,0): straight (dx=1, dy=0). S=1, D=0. (x+y) changes from 0 to 1.
                            // (1,0) -> (1,1): straight (dx=0, dy=1). S=2, D=0. (x+y) changes from 1 to 2.
                            // (1,1) -> (2,2): diagonal (dx=1, dy=1). S=2, D=1. (x+y) changes from 2 to 4.
                            // Total moves = 3. Total straight = 2. Total diagonal = 1.
                            // Final (N,M) = (2,2). (N+M) = 4.
                            // S = 2. (N+M)%2 = 0. S%2 = 0. This matches.
                            // K = 3.
                            //
                            // So, the condition (N+M)%2 == K%2 is NOT correct.
                            // The condition is (N+M)%2 == S%2.
                            // We want to maximize D, so minimize S.
                            //
                            // Minimum S:
                            // We need to reach (N,M) in K moves.
                            // The minimum number of moves to reach (N,M) is max_coord.
                            // This path uses min_coord diagonal moves and (max_coord - min_coord) straight moves.
                            // So, S_base = max_coord - min_coord.
                            // D_base = min_coord.
                            //
                            // We have K - max_coord "extra" moves.
                            // These extra moves can be used to increase D or S.
                            // Each pair of extra moves can be:
                            // 1. Two diagonal moves: (x,y) -> (x+1,y+1) -> (x,y). Net change in S=0, D=2.
                            // 2. Two straight moves: (x,y) -> (x+1,y) -> (x,y). Net change in S=2, D=0.
                            // 3. One straight, one diagonal: (x,y) -> (x+1,y) -> (x+1,y+1). Net change in S=1, D=1.
                            // This is getting complicated.
                            //
                            // Let's consider the parity of K and max_coord.
                            // If K and max_coord have the same parity:
                            //   We can reach (N,M) in max_coord moves.
                            //   We have K - max_coord remaining moves, which is an even number.
                            //   We can use these as pairs of diagonal moves (e.g., (x,y) -> (x+1,y+1) -> (x,y)).
                            //   This means we can make K diagonal moves.
                            //   This is valid if (N+M)%2 == (K - K)%2 == 0.
                            //   No, this is not right.
                            //
                            // The key insight is that we can always make a move and then immediately reverse it.
                            // (x,y) -> (x+1,y+1) -> (x,y) uses 2 diagonal moves, 2 total moves, 0 net displacement.
                            // (x,y) -> (x+1,y) -> (x,y) uses 0 diagonal moves, 2 total moves, 0 net displacement.
                            //
                            // We need to reach (N,M) in K moves.
                            // The minimum number of moves is max_coord.
                            // If K < max_coord, impossible.
                            //
                            // If K >= max_coord:
                            // We can always reach (N,M) in max_coord moves.
                            // Let's say we are at (N,M) after max_coord moves.
                            // We have K - max_coord moves left.
                            //
                            // If (K - max_coord) is even:
                            //   We can use all these remaining moves as pairs of diagonal moves.
                            //   (x,y) -> (x+1,y+1) -> (x,y). This adds 2 diagonal moves.
                            //   So, the total number of diagonal moves would be min_coord + (K - max_coord).
                            //   This is the maximum possible.
                            //   Example (4,3,7): N=4, M=3, K=7. max_coord=4. min_coord=3.
                            //   K - max_coord = 3 (odd). This case doesn't apply.
                            //   Example (2,2,4): N=2, M=2, K=4. max_coord=2. min_coord=2.
                            //   K - max_coord = 2 (even).
                            //   Diagonal moves = min_coord + (K - max_coord) = 2 + (4-2) = 4.
                            //   Path: (0,0)->(1,1)->(2,2)->(3,3)->(2,2). 4 diagonal moves. This works.
                            //
                            // If (K - max_coord) is odd:
                            //   We have an odd number of remaining moves.
                            //   We can use (K - max_coord - 1) of them as pairs of diagonal moves.
                            //   This leaves 1 move.
                            //   We are at (N,M). We need to make 1 move and end up at (N,M). Impossible.
                            //   This means we cannot simply add pairs of diagonal moves.
                            //   We need to adjust the path taken to reach (N,M) in the first place.
                            //
                            // Let's consider the parity of (N+M) and K.
                            // If (N+M) % 2 != K % 2:
                            //   This means we need an odd number of straight moves if K is odd, or an even number if K is even.
                            //   The parity of (N+M) must match the parity of the number of straight moves.
                            //   If (N+M) % 2 != K % 2, it means we cannot reach (N,M) in K moves if we only use diagonal moves.
                            //   We must use at least one straight move.
                            //   If we use one straight move, then K-1 moves are diagonal.
                            //   If K-1 is even, then we can use K-1 diagonal moves.
                            //   If K-1 is odd, then K is even.
                            //   This is the case where (N+M)%2 != K%2.
                            //   Example (2,2,3): N=2, M=2, K=3. max_coord=2.
                            //   (N+M)%2 = 0. K%2 = 1. Parity mismatch.
                            //   Output is 1.
                            //   Path: (0,0) -> (1,0) -> (1,1) -> (2,2).
                            //   This path has 2 straight moves and 1 diagonal move.
                            //   S=2, D=1. K=3.
                            //   (N+M)%2 = 0. S%2 = 0. This matches.
                            //   So, if (N+M)%2 != K%2, we must have S be odd. Minimum S=1.
                            //   If (N+M)%2 == K%2, we must have S be even. Minimum S=0.
                            //
                            // Let's try this:
                            // 1. If K < max_coord, impossible (-1).
                            // 2. Calculate the "base" number of diagonal moves: D_base = min_coord.
                            // 3. Calculate the "base" number of straight moves: S_base

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Represents A_i + C_i <= M_i

    // Process operations in reverse to find initial_a constraints
    // For each type 2 operation (2 l r m), we need to find the maximum possible value for A_j
    // such that A_j + current_delta_j <= m.
    // This means A_j <= m - current_delta_j.
    // We want to find the largest possible A_j, so we take the minimum of all such upper bounds.
    // current_delta_j is the sum of all d_k for type 1 operations that affect j and occur *before* the current type 2 operation.
    // When processing in reverse, current_delta_j is the sum of all d_k for type 1 operations that affect j and occur *after* the current type 2 operation.
    // Let's call this `suffix_delta_j`.
    // So, A_j <= m - (total_delta_j - suffix_delta_j).
    // This is equivalent to A_j + (total_delta_j - suffix_delta_j) <= m.
    // Let's define `current_delta_j` as the sum of `d` values for type 1 operations that affect index `j` and occur *before* the current operation.
    // When we process operations in reverse, we are effectively calculating `current_delta_j` for the *original* forward pass.
    // Let `delta_sum[j]` be the sum of `d` values for type 1 operations that affect index `j` and occur *after* the current operation in the original sequence.
    // So, for a type 2 operation `2 l r m` at index `k` in the original sequence:
    // For any `j` in `[l, r]`, `A_j + (sum of d's before k for j) <= m`.
    // Let `D_j` be the total sum of `d` values for type 1 operations affecting `j` throughout all `m` operations.
    // Let `D_j_after_k` be the sum of `d` values for type 1 operations affecting `j` that occur *after* operation `k`.
    // Then `sum of d's before k for j` = `D_j - D_j_after_k`.
    // So, `A_j + D_j - D_j_after_k <= m`.
    // This means `A_j <= m - D_j + D_j_after_k`.
    // We want to maximize `A_j`, so `A_j` should be `min(m - D_j + D_j_after_k)` over all type 2 operations.
    // Let `initial_a[j]` store `m - D_j + D_j_after_k`. We take the minimum of these.
    // Initialize `initial_a[j]` to a very large value.

    std::vector<long long> current_delta_suffix(n, 0); // Sum of d's for type 1 ops *after* current op (in original order)
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta_suffix[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta_suffix[j]);
            }
        }
    }

    // If initial_a[j] is still LLONG_MAX, it means there were no type 2 constraints on A_j.
    // In this case, we can set A_j to 0 (or any value within bounds).
    // The problem states |a_i| <= 10^9. Setting to 0 is safe.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Now, verify the solution by simulating operations forward
    std::vector<long long> a = initial_a;
    std::vector<long long> current_delta_prefix(n, 0); // Sum of d's for type 1 ops *before* current op (in original order)

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta_prefix[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, initial_a[j] + current_delta_prefix[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial_a
    for (int i = 0; i < n; ++i) {
        if (std::abs(initial_a[i]) > 1000000000LL) {
            // This case should ideally not be reached if the problem guarantees a solution within bounds
            // or if the constraints are tight enough.
            // However, if initial_a[i] was set to LLONG_MAX and then 0, it's fine.
            // If it was constrained to a value outside 10^9, then it's an issue.
            // The problem statement implies that if a solution exists, it's within 10^9.
            // Our logic for initial_a[j] = min(m - current_delta_suffix[j]) should naturally keep it within bounds
            // if such a solution exists.
            // If m is large and current_delta_suffix[j] is small, initial_a[j] could be large.
            // If m is small and current_delta_suffix[j] is large, initial_a[j] could be small (negative).
            // The maximum possible value for m is 5*10^7.
            // The maximum possible sum of d's is 5000 * 10^4 = 5*10^7.
            // So m - current_delta_suffix[j] can range from roughly -10^8 to 10^8.
            // This is well within 10^9. So this check is technically not strictly necessary for correctness
            // given the problem constraints, but good for robustness.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
