// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise (stable)
bool apply_median_smoothing(const std::vector<int>& current_seq, std::vector<int>& next_seq) {
    int n = current_seq.size();
    bool changed = false;

    next_seq[0] = current_seq[0];
    next_seq[n - 1] = current_seq[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        int sum = current_seq[i - 1] + current_seq[i] + current_seq[i + 1];
        int median_val = (sum >= 2) ? 1 : 0;
        next_seq[i] = median_val;
        if (next_seq[i] != current_seq[i]) {
            changed = true;
        }
    }
    return changed;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> current_seq = a;
    std::vector<int> next_seq(n);

    // Find the first 0-1 block and 1-0 block
    // A 0-1 block is a sequence like 0, 0, ..., 0, 1, 1, ..., 1
    // A 1-0 block is a sequence like 1, 1, ..., 1, 0, 0, ..., 0
    // These are the only patterns that can "shrink" or "grow"

    // Find first 0-1 transition (0 followed by 1)
    int first_01 = -1;
    for (int i = 0; i < n - 1; ++i) {
        if (current_seq[i] == 0 && current_seq[i+1] == 1) {
            first_01 = i;
            break;
        }
    }

    // Find first 1-0 transition (1 followed by 0)
    int first_10 = -1;
    for (int i = 0; i < n - 1; ++i) {
        if (current_seq[i] == 1 && current_seq[i+1] == 0) {
            first_10 = i;
            break;
        }
    }

    if (first_01 == -1 && first_10 == -1) { // Sequence is already stable (all 0s or all 1s)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // If there's only one type of transition, it will stabilize
    // e.g., 000111, 111000
    if (first_01 == -1 || first_10 == -1) {
        int steps = 0;
        while (apply_median_smoothing(current_seq, next_seq)) {
            current_seq = next_seq;
            steps++;
        }
        std::cout << steps << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // If both 0-1 and 1-0 transitions exist, we need to check for non-stabilizing patterns
    // A non-stabilizing pattern is 010101... or 101010...
    // This happens if the first 0-1 transition is to the left of the first 1-0 transition,
    // AND the distance between them is odd.
    // Example: 0 1 0 1 0 (first_01=0, first_10=1, distance 1 is odd)
    // Example: 0 0 1 0 0 (first_01=1, first_10=2, distance 1 is odd)
    // Example: 0 0 1 1 0 0 (first_01=1, first_10=3, distance 2 is even) -> stabilizes

    // The critical condition for non-stabilization is when a 010 or 101 pattern
    // is "trapped" and cannot resolve.
    // Specifically, if we have a 0 followed by a 1, and then a 1 followed by a 0,
    // and the distance between the '1' of the 01 and the '1' of the 10 is odd,
    // it means we have an alternating pattern of odd length.
    // E.g., 0 1 0 1 0. first_01=0 (0->1), first_10=1 (1->0).
    // The '1' at index 1 is the '1' of 01. The '1' at index 1 is also the '1' of 10.
    // The distance between the '1' of the first 01 and the '0' of the first 10 is (first_10 - (first_01+1)).
    // If this distance is 0, it means 010.
    // If first_01 < first_10, it means we have 0...1...0.
    // The '1' at first_01+1 and the '0' at first_10+1 are the critical points.
    // The segment from first_01+1 to first_10 is the "alternating" part.
    // Its length is first_10 - (first_01+1) + 1 = first_10 - first_01.
    // If this length is odd, it will not stabilize.
    // Example: 0 1 0 1 0
    // first_01 = 0 (a[0]=0, a[1]=1)
    // first_10 = 1 (a[1]=1, a[2]=0)
    // first_10 - first_01 = 1 (odd) -> non-stabilizing
    // Example: 0 0 1 0 0
    // first_01 = 1 (a[1]=0, a[2]=1)
    // first_10 = 2 (a[2]=1, a[3]=0)
    // first_10 - first_01 = 1 (odd) -> non-stabilizing
    // Example: 0 0 1 1 0 0
    // first_01 = 1 (a[1]=0, a[2]=1)
    // first_10 = 3 (a[3]=1, a[4]=0)
    // first_10 - first_01 = 2 (even) -> stabilizing

    if (first_01 < first_10 && (first_10 - first_01) % 2 != 0) {
        std::cout << -1 << std::endl;
        return 0;
    }

    // If it reaches here, it must stabilize.
    // The number of steps is determined by the "half-width" of the alternating pattern.
    // For 00100, first_01=1, first_10=2. (first_10 - first_01) = 1.
    // The '1' at index 2 will become '0' in one step.
    // The number of steps is (first_10 - first_01 + 1) / 2.
    // For 001100, first_01=1, first_10=3. (first_10 - first_01) = 2.
    // The '1' at index 2 and '1' at index 3.
    // In one step: 001100 -> 001100 (no change for 1s)
    // This logic is tricky. Let's re-evaluate the number of steps.
    // The number of steps is the maximum of the "half-width" of all 0...1...0 and 1...0...1 patterns.
    // A 0...1...0 pattern: 0 at `i`, 1 at `j`, 0 at `k`.
    // The '1' at `j` will propagate outwards.
    // The number of steps for a 0...1...0 pattern is `ceil((j-i)/2)` and `ceil((k-j)/2)`.
    // The number of steps for a 1...0...1 pattern is `ceil((j-i)/2)` and `ceil((k-j)/2)`.

    // Let's find all 0-1 and 1-0 transitions.
    std::vector<int> zero_indices;
    std::vector<int> one_indices;
    for (int i = 0; i < n; ++i) {
        if (current_seq[i] == 0) zero_indices.push_back(i);
        else one_indices.push_back(i);
    }

    int max_steps = 0;

    // Case 1: 0...1...0 patterns
    // Find the maximum distance from a '1' to its nearest '0' on either side.
    // For each '1' at index `i`:
    //   Find nearest '0' to its left (index `l_zero`)
    //   Find nearest '0' to its right (index `r_zero`)
    //   If both exist, the '1' will eventually become '0'.
    //   The number of steps for this '1' to become '0' is `std::min(i - l_zero, r_zero - i)`.
    //   This is not quite right. It's `std::min(i - l_zero, r_zero - i)` steps for the '1' to be "eaten".
    //   The actual number of steps is `std::min(i - l_zero, r_zero - i)`.
    //   Example: 0 0 1 0 0. i=2. l_zero=1, r_zero=3. min(2-1, 3-2) = 1. Steps = 1.
    //   Example: 0 0 0 1 0 0 0. i=3. l_zero=2, r_zero=4. min(3-2, 4-3) = 1. Steps = 1.
    //   Example: 0 0 1 1 0 0. i=2. l_zero=1, r_zero=4. min(2-1, 4-2) = 1.
    //                       i=3. l_zero=1, r_zero=4. min(3-1, 4-3) = 1.
    //   The number of steps for a block of 1s surrounded by 0s to become all 0s is `ceil(length_of_1s_block / 2)`.
    //   No, it's `(length_of_1s_block + 1) / 2`.
    //   010 -> 000 (1 step). Length 1. (1+1)/2 = 1.
    //   0110 -> 0110 (1 step). Length 2. (2+1)/2 = 1.
    //   01110 -> 00100 (1 step) -> 00000 (2 steps). Length 3. (3+1)/2 = 2.
    //   011110 -> 001100 (1 step) -> 000000 (2 steps). Length 4. (4+1)/2 = 2.
    //   This is for a contiguous block of 1s.

    // Let's find contiguous blocks of 1s surrounded by 0s.
    // And contiguous blocks of 0s surrounded by 1s.

    // Iterate through the sequence to find blocks
    int current_block_start = 0;
    for (int i = 0; i < n; ++i) {
        if (i == n - 1 || current_seq[i] != current_seq[i+1]) {
            // Block ends at i
            int block_len = i - current_block_start + 1;
            int block_val = current_seq[current_block_start];

            if (block_val == 1) { // Block of 1s
                // Check if it's surrounded by 0s
                bool left_zero = (current_block_start == 0) ? false : (current_seq[current_block_start - 1] == 0);
                bool right_zero = (i == n - 1) ? false : (current_seq[i + 1] == 0);

                if (left_zero && right_zero) {
                    max_steps = std::max(max_steps, (block_len + 1) / 2);
                }
            } else { // Block of 0s
                // Check if it's surrounded by 1s
                bool left_one = (current_block_start == 0) ? false : (current_seq[current_block_start - 1] == 1);
                bool right_one = (i == n - 1) ? false : (current_seq[i + 1] == 1);

                if (left_one && right_one) {
                    max_steps = std::max(max_steps, (block_len + 1) / 2);
                }
            }
            current_block_start = i + 1;
        }
    }

    // Apply smoothing max_steps times
    for (int s = 0; s < max_steps; ++s) {
        apply_median_smoothing(current_seq, next_seq);
        current_seq = next_seq;
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply d_effect from previous children who cried and left
            if (total_d_effect > 0) {
                children[j].p -= total_d_effect;
            }

            // Apply v_effect from current child going to dentist
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--; // v_effect decreases by 1 for each subsequent child
            }

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect += children[j].d; // Accumulate d_effect
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;
    long long second_min_a = elements[1].value;
    long long second_max_a = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., S1 is empty or S2 is empty)
    // All f(a_i, a_j) = a_i + a_j
    // min_f = min_a + second_min_a
    // max_f = max_a + second_max_a
    // goodness = (max_a + second_max_a) - (min_a + second_min_a)
    long long goodness1 = (max_a + second_max_a) - (min_a + second_min_a);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences
    // This case is only potentially better if h is large.
    // The optimal strategy for this case is to put min_a in one subsequence (e.g., S1)
    // and all other elements in the other subsequence (S2).
    // This minimizes the number of pairs with +h, and specifically ensures min_a is only paired with +h.
    //
    // S1 = {min_a}
    // S2 = {a_1, a_2, ..., a_{n-1}} (excluding min_a, sorted)
    //
    // Possible f values:
    // 1. Pairs within S2: a_i + a_j (where a_i, a_j are from S2)
    //    min_f_S2 = second_min_a + elements[2].value (if n > 2)
    //    max_f_S2 = max_a + second_max_a
    // 2. Pairs between S1 and S2: min_a + a_j + h (where a_j is from S2)
    //    min_f_S1S2 = min_a + second_min_a + h
    //    max_f_S1S2 = min_a + max_a + h

    long long min_f_val_case2;
    long long max_f_val_case2;

    if (n == 2) {
        // S1 = {elements[0]}, S2 = {elements[1]}
        // Only one pair: elements[0] + elements[1] + h
        // min_f_val_case2 = max_f_val_case2 = elements[0].value + elements[1].value + h
        // goodness = 0
        // This is covered by the general logic below, but good to note.
        min_f_val_case2 = elements[0].value + elements[1].value + h;
        max_f_val_case2 = elements[0].value + elements[1].value + h;
    } else { // n > 2
        // min_f_val_case2 is the minimum of:
        //   - min_a + second_min_a + h (from S1-S2 pairs)
        //   - second_min_a + elements[2].value (from S2-S2 pairs)
        min_f_val_case2 = std::min(min_a + second_min_a + h, second_min_a + elements[2].value);

        // max_f_val_case2 is the maximum of:
        //   - min_a + max_a + h (from S1-S2 pairs)
        //   - max_a + second_max_a (from S2-S2 pairs)
        max_f_val_case2 = std::max(min_a + max_a + h, max_a + second_max_a);
    }

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1; // min_a in S1
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2; // others in S2
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

