// Function to check if all target tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // dp[i] stores the minimum index j such that p[0...j] can be covered using i heads.
    // If dp[i] == m, it means all tracks p[0...m-1] can be covered using i heads.
    std::vector<int> dp(n + 1, -1); // -1 indicates not reachable
    dp[0] = -1; // Base case: 0 heads can cover up to index -1 (no tracks)

    // Iterate through each head
    for (int i = 0; i < n; ++i) {
        // For each head h[i], we try to extend coverage from previous states
        // dp_next will store the updated dp values for using up to i+1 heads
        std::vector<int> dp_next = dp;

        // Iterate through possible previous states (number of heads used so far)
        for (int j = 0; j <= i; ++j) {
            if (dp[j] == -1) continue; // If this state is not reachable, skip

            // current_p_idx is the first track that needs to be covered by the current head
            int current_p_idx = dp[j] + 1;

            if (current_p_idx >= m) {
                // All tracks are already covered by j heads, so i+1 heads can also cover all.
                dp_next[j + 1] = std::max(dp_next[j + 1], m - 1);
                continue;
            }

            // Find the leftmost track p[current_p_idx] that can be covered by h[i]
            // A head at h[i] can cover tracks in range [h[i] - T, h[i] + T]
            // So, p[current_p_idx] must be <= h[i] + T
            if (p[current_p_idx] > h[i] + T) {
                continue; // This head cannot even reach the first uncovered track
            }

            // Binary search for the rightmost track p[k] that can be covered by h[i]
            // such that p[k] is covered by h[i] and the segment [p[current_p_idx], p[k]]
            // can be covered by a single head h[i] within time T.
            // This means:
            // 1. p[k] <= h[i] + T
            // 2. h[i] >= p[current_p_idx] - T
            // 3. The total span covered by h[i] is at most 2T.
            //    If h[i] covers p[current_p_idx] and p[k], then h[i] must be in [p[current_p_idx] - T, p[k] + T].
            //    The optimal position for h[i] to cover [p[current_p_idx], p[k]] is
            //    (p[current_p_idx] + p[k]) / 2.
            //    The time taken would be max(p[k] - h[i], h[i] - p[current_p_idx]).
            //    This is equivalent to (p[k] - p[current_p_idx]) / 2 if h[i] is optimally placed.
            //    More generally, the time taken is max(p[k] - h[i], h[i] - p[current_p_idx]).
            //    This is minimized when h[i] is chosen to be p[current_p_idx] + T or p[k] - T,
            //    or somewhere in between.
            //    The condition is that there exists an x such that |x - h[i]| <= T and
            //    x covers [p[current_p_idx], p[k]].
            //    This means p[k] - p[current_p_idx] <= 2T.
            //    And h[i] must be able to reach this segment.
            //    Specifically, h[i] must be able to reach p[current_p_idx] (h[i] >= p[current_p_idx] - T)
            //    and h[i] must be able to reach p[k] (h[i] <= p[k] + T).
            //    So, h[i] must be in [p[current_p_idx] - T, p[k] + T].
            //    And the segment [p[current_p_idx], p[k]] must be coverable by a single head.
            //    This means there exists a position `x` such that `x` is within `[h[i]-T, h[i]+T]`
            //    and `x` covers `[p[current_p_idx], p[k]]`.
            //    The range `[p[current_p_idx], p[k]]` can be covered by a single head if its length `p[k] - p[current_p_idx]` is at most `2T`.
            //    And the head `h[i]` must be able to reach this covering position.
            //    The interval `[p[current_p_idx], p[k]]` can be covered by a head at `x` if `x` is in `[p[k]-T, p[current_p_idx]+T]`.
            //    We need to check if `[p[k]-T, p[current_p_idx]+T]` intersects with `[h[i]-T, h[i]+T]`.
            //    This intersection is non-empty if `max(p[k]-T, h[i]-T) <= min(p[current_p_idx]+T, h[i]+T)`.
            //    This simplifies to `p[k] - T <= h[i] + T` AND `h[i] - T <= p[current_p_idx] + T`.
            //    Which is `p[k] - h[i] <= 2T` AND `h[i] - p[current_p_idx] <= 2T`.
            //    And also `p[k] >= p[current_p_idx]`.
            //    The condition `p[k] - p[current_p_idx] <= 2T` is implicitly handled by the `p[k] - h[i] <= 2T` and `h[i] - p[current_p_idx] <= 2T`
            //    if we consider the head to be optimally placed within its range.
            //    A simpler way: the head h[i] can cover a segment [L, R] if L >= h[i] - T and R <= h[i] + T.
            //    We want to find the maximum R such that [p[current_p_idx], R] can be covered by h[i].
            //    This means R <= h[i] + T.
            //    And h[i] must be able to reach p[current_p_idx], so h[i] >= p[current_p_idx] - T.
            //    The actual range covered by h[i] is [h[i] - T, h[i] + T].
            //    We are looking for the maximum `k_prime` such that `p[k_prime]` is covered by `h[i]`
            //    and `p[current_p_idx]` is covered by `h[i]`, and all `p` in between are covered.
            //    This means `p[current_p_idx]` must be in `[h[i]-T, h[i]+T]` and `p[k_prime]` must be in `[h[i]-T, h[i]+T]`.
            //    The actual range covered by h[i] is `[h[i]-T, h[i]+T]`.
            //    We need to find the maximum `k_prime` such that `p[k_prime] <= h[i] + T` and `p[current_p_idx] >= h[i] - T`.
            //    And all `p` from `current_p_idx` to `k_prime` are covered.
            //    This is equivalent to finding the maximum `k_prime` such that `p[k_prime] <= h[i] + T`
            //    and `p[current_p_idx]` is covered by `h[i]`.
            //    The condition `p[current_p_idx] >= h[i] - T` is already checked.
            //    So we just need to find the maximum `k_prime` such that `p[k_prime] <= h[i] + T`.
            //    This is `upper_bound(p.begin() + current_p_idx, p.end(), h[i] + T) - p.begin() - 1`.
            //    Let this be `k_max_reach`.
            //    However, this is not enough. We need to consider the "gap" between p[current_p_idx] and p[k_max_reach].
            //    If h[i] covers p[current_p_idx] and p[k_max_reach], it must be able to cover the entire segment.
            //    This means h[i] must be able to reach both ends.
            //    The head h[i] can cover the segment [p[current_p_idx], p[k_prime]] if
            //    `p[k_prime] - p[current_p_idx] <= 2T` AND
            //    `h[i]` is within `[p[current_p_idx] - T, p[k_prime] + T]`.
            //    The second condition is `p[current_p_idx] - T <= h[i] <= p[k_prime] + T`.
            //    We already know `h[i] >= p[current_p_idx] - T` (from `p[current_p_idx] <= h[i] + T`).
            //    So we need to find max `k_prime` such that `p[k_prime] - p[current_p_idx] <= 2T` AND `h[i] <= p[k_prime] + T`.

            // Find the maximum k_prime such that p[k_prime] - p[current_p_idx] <= 2T
            // This means p[k_prime] <= p[current_p_idx] + 2T
            auto it_max_span = std::upper_bound(p.begin() + current_p_idx, p.end(), p[current_p_idx] + 2 * T);
            int k_max_span = (it_max_span == p.begin() + current_p_idx) ? current_p_idx - 1 : (it_max_span - p.begin() - 1);

            // Find the maximum k_prime such that h[i] <= p[k_prime] + T
            // This means p[k_prime] >= h[i] - T
            // This is equivalent to finding the first element >= h[i] - T, then taking elements to its right.
            // We need to find the maximum k_prime such that p[k_prime] is reachable by h[i] (p[k_prime] <= h[i] + T)
            // AND h[i] is reachable by p[k_prime] (h[i] >= p[k_prime] - T).
            // The second condition is equivalent to p[k_prime] <= h[i] + T.
            // So we just need to find the maximum k_prime such that p[k_prime] <= h[i] + T.
            auto it_max_reach = std::upper_bound(p.begin() + current_p_idx, p.end(), h[i] + T);
            int k_max_reach = (it_max_reach == p.begin() + current_p_idx) ? current_p_idx - 1 : (it_max_reach - p.begin() - 1);

            // The actual maximum index k_prime that can be covered by h[i]
            // is the minimum of these two upper bounds.
            // Because both conditions must hold: the span must be <= 2T AND h[i] must be able to reach the rightmost point.
            int k_prime = std::min(k_max_span, k_max_reach);

            if (k_prime >= current_p_idx) {
                dp_next[j + 1] = std::max(dp_next[j + 1], k_prime);
            }
        }
        dp = dp_next;
    }

    return dp[n] == m - 1; // Check if all m tracks (indices 0 to m-1) can be covered by n heads
}


