    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    // int count_e = 0; // Not strictly needed as 'e' is used by both and 'n'/'z' are unique identifiers
    // int count_r = 0;
    // int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
        // The problem guarantees that it's possible to form a sequence of "one"s and "zero"s.
        // This implies that the counts of 'e', 'r', 'o' will always be sufficient
        // if 'n' and 'z' are used as primary indicators.
        // For example, if we have `k` 'n's, we can form `k` "one"s.
        // If we have `m` 'z's, we can form `m` "zero"s.
        // The total 'e's, 'r's, 'o's must match the requirements.
        // 'one' uses 'o', 'n', 'e'
        // 'zero' uses 'z', 'e', 'r', 'o'
        // The number of 'n's directly tells us how many "one"s can be formed.
        // The number of 'z's directly tells us how many "zero"s can be formed.
        // This is because 'n' only appears in "one" and 'z' only appears in "zero".
    }

    // To maximize the binary number, we want to have as many '1's as possible,
    // followed by '0's.
    // So, print all '1's first, then all '0's.

    bool first_digit = true;

    for (int i = 0; i < count_n; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << "1";
        first_digit = false;
    }

    for (int i = 0; i < count_z; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << "0";
        first_digit = false;
    }

    std::cout << std::endl;

    return 0;
}

