int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // After sorting the array a, the optimal strategy is to pick the
        // n-th element (0-indexed: a[n-1]) as the median for one class
        // and the (n+1)-th element (0-indexed: a[n]) as the median for the other class.
        // This is because if we pick a[i] and a[j] as medians, and i < n-1 or j > n,
        // we could always move them closer to the center (n-1 and n) to reduce the difference
        // or keep it the same, while still being able to form valid odd-sized classes.
        // Specifically, the smallest possible median for a class of size 2k+1 is a[k].
        // The largest possible median for a class of size 2k+1 is a[2n-1-k].
        // For the two classes to cover all 2n students, if one class has median a[i]
        // and the other has median a[j], then i and j must be "central" elements.
        // The two medians will always be a[n-1] and a[n] after sorting.
        // This is a known property for this type of problem.
        // The first class will have median a[n-1] and the second class will have median a[n].
        // The difference is a[n] - a[n-1].
        long long diff = a[n] - a[n - 1];
        std::cout << diff << "\n";
    }
    return 0;
}

#include <iostream>
