#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1 (corresponding to q_2 to q_n)
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i must be unique if it's a new max
                // and q_i is guaranteed to be <= n.
                // However, if q_i was already used as p_j for j < i, it's an issue.
                // But p_j = q_j if q_j > q_{j-1}. So q_i would be equal to some q_j.
                // This implies q_i was not a new maximum, contradiction.
                // So this check is mostly for robustness, but shouldn't trigger with valid q.
                possible = false;
                break;
            }
            p[i] = q[i];
            used_numbers.insert(q[i]);
        } else { // q[i] == q[i-1]
            // p_i must be some unused number less than q[i]
            // To maximize chances, pick the smallest available number
            int current_val = 1;
            while (used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val >= q[i]) {
                // No unused number less than q[i] is available
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The number of coders (each team needs at least one coder).
        // 2. The number of mathematicians (each team needs at least one mathematician).
        // 3. The total number of students divided by 3 (each team needs 3 students).
        // So, the maximum possible teams 'k' must satisfy:
        // k <= c
        // k <= m
        // k <= (c + m + x) / 3
        // Therefore, k <= min(c, m, (c + m + x) / 3).
        // This gives an upper bound for k.

        // We can use binary search to find the maximum k.
        // The search space for k is from 0 to min(c, m, (c + m + x) / 3).
        // A more generous upper bound for binary search is min(c, m, (c + m + x)).
        // Since c, m, x <= 10^8, (c + m + x) can be up to 3 * 10^8.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Initial upper bound
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and 'x' no-specialization students.
            // The total number of remaining students is (c - mid) + (m - mid) + x.
            // Each of the 'mid' teams needs 3 members.
            // 'mid' members are taken as coders, 'mid' as mathematicians.
            // So, 'mid' * 2 members are already accounted for (one coder, one mathematician per team).
            // We need 'mid' more members to fill the teams (3 - 2 = 1 per team).
            // These 'mid' additional members can come from the remaining coders, mathematicians, or no-specialization students.
            // The total pool of available students for these 'mid' additional slots is (c - mid) + (m - mid) + x.

            if ((c - mid) + (m - mid) + x >= mid) {
                // If we have enough remaining students to fill the third slot for each of the 'mid' teams,
                // then 'mid' teams are possible. Try for more.
                ans = mid;
                low = mid + 1;
            } else {
                // Not enough students for 'mid' teams. Try for fewer.
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

