}

#include <iostream>
#include <algorithm> // For std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        // If l == r, the only number is l.
        // We need to find its smallest divisor > 1.
        // If l is prime, it's l itself.
        // If l is composite, it's its smallest prime factor.
        // Since l >= 2, it always has a divisor > 1.
        // The smallest divisor > 1 is 2 if l is even, otherwise it's the smallest prime factor.
        // However, the problem asks for the integer that appears maximum number of times.
        // If l == r, any divisor of l (except 1) appears exactly once.
        // So, any divisor of l (except 1) is a valid answer.
        // The simplest is to return 2 if l is even, otherwise l itself (if l is prime) or its smallest prime factor.
        // But the problem statement implies we should pick one that is "most frequent".
        // If all divisors appear once, any is fine.
        // The simplest is to just return 2 if l is even, otherwise l.
        // But the problem asks for the integer that we wrote down the maximum number of times.
        // If l=3, r=3, divisors are {3}. Max count is 1 for 3.
        // If l=4, r=4, divisors are {2, 4}. Max count is 1 for 2 or 4.
        // The problem asks for *any* of them.
        // The simplest is to return 2 if l is even, otherwise l.
        // But the general logic for l != r will pick 2 or 3.
        // If l=3, r=3, the general logic would check 2 (count 0), 3 (count 1). Output 3.
        // If l=4, r=4, the general logic would check 2 (count 1), 3 (count 0). Output 2.
        // This seems consistent.
        // So, the special case l==r doesn't need explicit handling if the general logic works.
        // The general logic for count is floor(r/d) - (l + d - 1) / d + 1.
        // For l=r, this is floor(l/d) - (l + d - 1) / d + 1.
        // If d divides l: floor(l/d) - l/d + 1 = l/d - l/d + 1 = 1.
        // If d does not divide l: floor(l/d) - (l/d + 1) + 1 = floor(l/d) - floor(l/d) - 1 + 1 = 0.
        // So it correctly counts 1 for divisors and 0 for non-divisors.
        // The maximum count will be 1, and any divisor will achieve it.
        // The general logic will pick 2 if l is even, or 3 if l is odd and divisible by 3, etc.
        // The problem asks for *any* of them.
        // So, the general logic should work.
    }

    // The most frequent divisor will almost always be 2.
    // The only exception is when the range [l, r] is very small and starts with an odd number,
    // such that 2 does not appear as a divisor as many times as 3 (or some other small prime).
    // For example, if l=3, r=6:
    // Divisor 2: numbers are {4, 6}. Count = 2.
    // Divisor 3: numbers are {3, 6}. Count = 2.
    // In this case, both 2 and 3 are valid answers. The problem says "print any of them".
    // If l=3, r=5:
    // Divisor 2: numbers are {4}. Count = 1.
    // Divisor 3: numbers are {3}. Count = 1.
    // Divisor 4: numbers are {4}. Count = 1.
    // Divisor 5: numbers are {5}. Count = 1.
    // Any of 2,3,4,5 is valid.
    //
    // The maximum possible count for any divisor d is floor(r/d) - ceil(l/d) + 1.
    // For d=2, count is floor(r/2) - (l+1)/2 + 1.
    // For d=3, count is floor(r/3) - (l+2)/3 + 1.
    //
    // If r - l + 1 >= 2, then there are at least two numbers in the range.
    // If r - l + 1 >= 3, then there are at least three numbers.
    // If r - l + 1 >= 4, then there are at least four numbers.
    //
    // Consider the case where 2 is not the answer. This happens when 3 (or some other prime)
    // has a count equal to or greater than 2, and 2 has a count less than 3.
    //
    // If r - l + 1 >= 2:
    // The number 2 will always be a divisor for at least floor((r-l+1)/2) numbers.
    // If r - l + 1 >= 2, there is at least one even number.
    // If r - l + 1 >= 3, there is at least one even number.
    // If r - l + 1 >= 4, there are at least two even numbers.
    //
    // If r - l + 1 >= 2, then 2 is a divisor for at least one number (if l is odd and r is l+1, e.g., 3,4 -> 4).
    // If r - l + 1 >= 3, then 2 is a divisor for at least one number (e.g., 3,4,5 -> 4).
    // If r - l + 1 >= 4, then 2 is a divisor for at least two numbers (e.g., 3,4,5,6 -> 4,6).
    //
    // The maximum count for any divisor d is at most r/d.
    // The maximum count for 2 is approximately (r-l)/2.
    // The maximum count for 3 is approximately (r-l)/3.
    //
    // If r - l + 1 is large enough (e.g., >= 4), then 2 will always be the most frequent or tied for most frequent.
    // Example: l=19, r=29. Range size = 11.
    // Count for 2: floor(29/2) - (19+1)/2 + 1 = 14 - 10 + 1 = 5. (20, 22, 24, 26, 28)
    // Count for 3: floor(29/3) - (19+2)/3 + 1 = 9 - 7 + 1 = 3. (21, 24, 27)
    // Here, 2 is the answer.
    //
    // Example: l=3, r=6. Range size = 4.
    // Count for 2: floor(6/2) - (3+1)/2 + 1 = 3 - 2 + 1 = 2. (4, 6)
    // Count for 3: floor(6/3) - (3+2)/3 + 1 = 2 - 1 + 1 = 2. (3, 6)
    // Here, both 2 and 3 are valid. The problem says "print any of them".
    //
    // The only case where 2 might not be the answer is when the range is very small.
    // If r - l + 1 < 4, i.e., r - l < 3.
    // Case 1: r - l = 0 (l=r).
    //   l=3, r=3. Divisors of 3: {3}. Count for 2 is 0, count for 3 is 1. Output 3.
    //   l=4, r=4. Divisors of 4: {2,4}. Count for 2 is 1, count for 3 is 0. Output 2.
    // Case 2: r - l = 1 (l, l+1).
    //   l=3, r=4. Numbers {3,4}. Divisors: {3}, {2,4}.
    //     Count for 2: 1 (from 4).
    //     Count for 3: 1 (from 3).
    //     Output 2 or 3.
    // Case 3: r - l = 2 (l, l+1, l+2).
    //   l=3, r=5. Numbers {3,4,5}. Divisors: {3}, {2,4}, {5}.
    //     Count for 2: 1 (from 4).
    //     Count for 3: 1 (from 3).
    //     Count for 5: 1 (from 5).
    //     Output 2, 3, or 5.
    //
    // In all these small cases, 2 is either the answer or tied with another small prime.
    // If r - l + 1 >= 4, then there are at least two even numbers in the range.
    // For example, if l is odd, then l+1, l+3 are even.
    // If l is even, then l, l+2 are even.
    // So, the count for 2 will be at least 2.
    // The count for 3 might be 1 (e.g., l=4, r=7. Numbers {4,5,6,7}. Evens: {4,6}. Count for 2 is 2. Multiples of 3: {6}. Count for 3 is 1).
    //
    // It seems that 2 is always a good candidate.
    // If r - l + 1 >= 4, then 2 is guaranteed to have a count of at least 2.
    // If r - l + 1 < 4, i.e., r - l <= 2.
    //   If r - l = 0 (l=r):
    //     If l is even, 2 is a divisor. Count for 2 is 1.
    //     If l is odd, 2 is not a divisor. Count for 2 is 0.
    //     In this case, if l is odd, 2 is not the answer. The answer would be l (if prime) or its smallest prime factor.
    //     Example: l=3, r=3. Output 3.
    //   If r - l = 1 (l, l+1):
    //     One number is even, one is odd. Count for 2 is 1.
    //     Count for 3 could be 0 (e.g., 4,5) or 1 (e.g., 3,4).
    //     If l=4, r=5. Count for 2 is 1 (from 4). Count for 3 is 0. Output 2.
    //     If l=3, r=4. Count for 2 is 1 (from 4). Count for 3 is 1 (from 3). Output 2 or 3.
    //   If r - l = 2 (l, l+1, l+2):
    //     One or two even numbers.
    //     If l is odd: l, l+1 (even), l+2 (odd). Count for 2 is 1.
    //     If l is even: l (even), l+1 (odd), l+2 (even). Count for 2 is 2.
    //     Example: l=3, r=5. Count for 2 is 1 (from 4). Count for 3 is 1 (from 3). Output 2 or 3.
    //     Example: l=4, r=6. Count for 2 is 2 (from 4,6). Count for 3 is 1 (from 6). Output 2.
    //
    // It seems that 2 is always a valid answer unless l=r and l is odd.
    // But even then, if l=3, r=3, 3 is the answer. If l=5, r=5, 5 is the answer.
    // The problem asks for *any* of them.
    //
    // Let's re-evaluate the problem statement: "Find the integer that we wrote down the maximum number of times."
    // If l=3, r=3, the numbers are {3}. Divisors (except 1) are {3}. Max count is 1 for 3.
    // If l=19, r=29, the numbers are {19, 20, ..., 29}.
    // Divisors of 2: {20, 22, 24, 26, 28}. Count = 5.
    // Divisors of 3: {21, 24, 27}. Count = 3.
    // Divisors of 4: {20, 24, 28}. Count = 3.
    // Divisors of 5: {20, 25}. Count = 2.
    // Divisors of 6: {24}. Count = 1.
    // ...
    // The maximum count is 5, achieved by 2. So 2 is the answer.
    //
    // If l=3, r=6.
    // Divisors of 2: {4, 6}. Count = 2.
    // Divisors of 3: {3, 6}. Count = 2.
    // Divisors of 4: {4}. Count = 1.
    // Divisors of 5: {5}. Count = 1.
    // Divisors of 6: {6}. Count = 1.
    // Max count is 2, achieved by 2 and 3. Both are valid answers.
    //
    // The simplest strategy is to check 2 and 3.
    // Count for 2: `r/2 - (l+1)/2 + 1`
    // Count for 3: `r/3 - (l+2)/3 + 1`
    //
    // If `r - l + 1 < 2`, i.e., `l == r`.
    //   If `l` is even, `2` is a divisor. Count for 2 is 1.
    //   If `l` is odd, `2` is not a divisor. Count for 2 is 0.
    //   In this case, if `l` is odd, `2` is not the answer.
    //   For `l=3, r=3`, count for 2 is 0, count for 3 is 1. Output 3.
    //   For `l=5, r=5`, count for 2 is 0, count for 3 is 0. Output 5.
    //
    // The problem states `l, r` up to `10^9`.
    // If `r - l + 1` is small, say `r - l + 1 < 60` (a small constant), we could iterate through all numbers in the range and find their divisors.
    // But `r - l + 1` can be `10^9`.
    //
    // The key insight is that for any `d > r/2`, `d` can be a divisor for at most one number in `[l, r]`.
    // Because if `k*d` and `(k+1)*d` are both in `[l, r]`, then `d = (k+1)*d - k*d <= r - l`.
    // If `d > r - l`, then `d` can divide at most one number in `[l, r]`.
    //
    // The number of multiples of `d` in `[l, r]` is `floor(r/d) - ceil(l/d) + 1`.
    // This count is maximized when `d` is small.
    // The smallest possible divisor (greater than 1) is 2.
    // The next smallest is 3.
    //
    // Let's consider the maximum possible count.
    // `max_count = floor(r/d) - ceil(l/d) + 1`.
    // This value is always maximized for the smallest `d`.
    // So, `d=2` will always give the highest count, or tie with another small prime.
    //
    // If `r - l + 1 >= 2`, then there is at least one even number in the range.
    // So, the count for 2 is at least 1.
    // If `r - l + 1 >= 3`, then there is at least one multiple of 3 or 2.
    //
    // The only case where 2 might not be the answer is if its count is 0.
    // This happens only if there are no even numbers in `[l, r]`.
    // This means `l` must be odd, and `r` must be odd.
    // And `r - l + 1` must be 1 (i.e., `l=r`).
    // If `l=r` and `l` is odd, then 2 is not a divisor.
    // In this specific case, the answer is `l` itself (since `l` is its only divisor > 1).
    // Example: `l=3, r=3`. Output `3`.
    // Example: `l=5, r=5`. Output `5`.
    //
    // In all other cases, there is at least one even number in `[l, r]`.
    // So, the count for 2 is at least 1.
    //
    // If `r - l + 1 >= 4`, then there are at least two even numbers.
    // Count for 2 is at least 2.
    // Count for 3 is at most `(r-l)/3 + 1`.
    // If `r-l+1 >= 4`, then `r-l >= 3`.
    // Count for 2 is `floor(r/2) - (l+1)/2 + 1`.
    // Count for 3 is `floor(r/3) - (l+2)/3 + 1`.
    //
    // Let's check the example `l=3, r=6`. `r-l+1 = 4`.
    // Count for 2: `floor(6/2) - (3+1)/2 + 1 = 3 - 2 + 1 = 2`.
    // Count for 3: `floor(6/3) - (3+2)/3 + 1 = 2 - 1 + 1 = 2`.
    // Both 2 and 3 are valid. The problem says "print any of them". So 2 is a valid answer.
    //
    // It seems that 2 is always a valid answer, except for the very specific case where `l=r` and `l` is odd.
    // In that case, `l` itself is the answer.
    //
    // Let's verify this logic.
    // If `l=r`:
    //   If `l` is even, `2` is a divisor of `l`. Count for 2 is 1.
    //     Any other divisor `d` of `l` also has count 1. So 2 is a valid answer.
    //   If `l` is odd, `2` is not a divisor of `l`. Count for 2 is 0.
    //     The smallest divisor of `l` (which is `l` itself if prime, or its smallest prime factor) will have count 1.
    //     So 2 is NOT the answer. The answer is `l` (or its smallest prime factor).
    //     Since the problem asks for *any* of them, and `l` is a divisor of `l`, `l` is a valid answer.
    //     So if `l=r` and `l` is odd, we should output `l`.
    //
    // If `l != r`:
    //   There are at least two numbers in the range.
    //   There must be at least one even number in the range.
    //   So, the count for 2 is at least 1.
    //   The count for 3 might be 0 (e.g., `l=4, r=5`).
    //   The count for 2 is `floor(r/2) - (l+1)/2 + 1`.
    //   The count for 3 is `floor(r/3) - (l+2)/3 + 1`.
    //   For `l=4, r=5`:
    //     Count for 2: `floor(5/2) - (4+1)/2 + 1 = 2 - 2 + 1 = 1`. (from 4)
    //     Count for 3: `floor(5/3) - (4+2)/3 + 1 = 1 - 2 + 1 = 0`.
    //     Here, 2 is the answer.
    //   For `l=3, r=4`:
    //     Count for 2: `floor(4/2) - (3+1)/2 + 1 = 2 - 2 + 1 = 1`. (from 4)
    //     Count for 3: `floor(4/3) - (3+2)/3 + 1 = 1 - 1 + 1 = 1`. (from 3)
    //     Here, both 2 and 3 are valid. Output 2.
    //
    // It seems that 2 is always a valid answer if `l != r`.
    //
    // So the logic is:
    // If `l == r` and `l` is odd, output `l`.
    // Otherwise, output `2`.
    //
    // Let's test this logic with examples:
    // Input: 19 29
    // `l=19, r=29`. `l != r`. Output 2. Correct.
    // Input: 3 6
    // `l=3, r=6`. `l != r`. Output 2. Correct (2 is a valid answer, as is 3).
    //
    // Test edge cases:
    // `l=2, r=2`. `l=r`, `l` is even. Output 2. Correct (divisors of 2 are {2}).
    // `l=3, r=3`. `l=r`, `l` is odd. Output 3. Correct (divisors of 3 are {3}).
    // `l=4, r=4`. `l=r`, `l` is even. Output 2. Correct (divisors of 4 are {2,4}).
    // `l=2, r=3`. `l != r`. Output 2. Correct (divisors of 2: {2}, divisors of 3: {3}. Both have count 1. 2 is valid).
    // `l=3, r=4`. `l != r`. Output 2. Correct (divisors of 3: {3}, divisors of 4: {2,4}. Both 2 and 3 have count 1. 2 is valid).
    // `l=10^9, r=10^9`. `l=r`, `l` is odd. Output `10^9`. Correct.
    // `l=10^9-1, r=10^9`. `l != r`. Output 2. Correct.
    //
    // This simple logic seems to cover all cases and satisfy the "print any of them" requirement.

    if (l == r && l % 2 != 0) {
        std::cout << l << std::endl;
    } else {
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    result.reserve(n);

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx and max_idx are both pos[1].
        // min_val is 1, max_val is 1. Length is 1.
        // This is always beautiful.

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The number 'm' is at pos[m].
        // We need to update current_min_idx and current_max_idx to cover the range
        // from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Now, the segment p[current_min_idx ... current_max_idx] contains all numbers
        // from 1 to m (and possibly some other numbers > m).
        // The minimum value in this segment is 1.
        // The maximum value in this segment is m.
        // For m to be beautiful, the length of this segment must be exactly m.
        // Length = current_max_idx - current_min_idx + 1.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a decreasing suffix
    // This is the first index `i` from the right such that `a[i] > a[i+1]`
    int p_idx = n - 1;
    while (p_idx > 0 && a[p_idx - 1] >= a[p_idx]) {
        p_idx--;
    }

    // If p_idx is 0, the entire array is non-decreasing, so it's good.
    // If p_idx is n-1, the last two elements are a[n-2] < a[n-1], so it's a decreasing suffix of length 1.
    // The loop above finds the first element from the right that breaks the non-decreasing suffix.
    // Example: [1, 2, 3, 4, 4, 2, 1]
    // n-1 = 6, a[6]=1
    // p_idx=6, a[5]=2, a[5] >= a[6] (2 >= 1) -> p_idx=5
    // p_idx=5, a[4]=4, a[4] >= a[5] (4 >= 2) -> p_idx=4
    // p_idx=4, a[3]=4, a[3] >= a[4] (4 >= 4) -> p_idx=3
    // p_idx=3, a[2]=3, a[2] < a[3] (3 < 4) -> loop terminates. p_idx = 3.
    // The suffix a[3...n-1] is [4, 4, 2, 1]. This is the non-increasing suffix.
    // The element a[p_idx-1] = a[2] = 3 is the first element to its left that is smaller.
    // So, the "peak" of the non-increasing suffix is a[p_idx] = a[3] = 4.
    // The elements from a[p_idx] to a[n-1] form a non-increasing sequence.

    // Now, find the rightmost peak of a non-increasing suffix
    // This is the first index `i` from the right such that `a[i] < a[i+1]`
    // Or, more precisely, the first index `i` from the right such that `a[i] > a[i+1]`
    // The previous loop found the start of the non-increasing suffix.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // n=7
    // p_idx=6, a[5]=3, a[6]=2. a[5] >= a[6] (3 >= 2) -> p_idx=5
    // p_idx=5, a[4]=5, a[5]=3. a[4] >= a[5] (5 >= 3) -> p_idx=4
    // p_idx=4, a[3]=4, a[4]=5. a[3] < a[4] (4 < 5) -> loop terminates. p_idx = 4.
    // The suffix a[4...n-1] is [5, 3, 2]. This is the non-increasing suffix.
    // The element a[p_idx-1] = a[3] = 4 is the first element to its left that is smaller.
    // So, the "peak" of the non-increasing suffix is a[p_idx] = a[4] = 5.

    // After the first loop, `p_idx` points to the start of the longest non-increasing suffix.
    // E.g., for [1, 2, 3, 4, 4, 2, 1], p_idx = 3 (value 4). Suffix is [4, 4, 2, 1].
    // E.g., for [4, 3, 3, 8, 4, 5, 2], p_idx = 4 (value 4). Suffix is [4, 5, 2].
    // E.g., for [1, 3, 1, 4, 5, 3, 2], p_idx = 4 (value 5). Suffix is [5, 3, 2].

    // Now, we need to find the start of the longest non-decreasing suffix within the remaining part.
    // This means we need to find the first index `i` from the right such that `a[i] < a[i+1]`
    // We continue from `p_idx`.
    int q_idx = p_idx;
    while (q_idx > 0 && a[q_idx - 1] <= a[q_idx]) {
        q_idx--;
    }
    // After this loop, `q_idx` points to the start of the longest non-decreasing suffix
    // that is to the left of `p_idx` (or includes `p_idx` if it was part of such a sequence).
    // E.g., for [1, 2, 3, 4, 4, 2, 1], p_idx = 3.
    // q_idx=3, a[2]=3, a[3]=4. a[2] <= a[3] (3 <= 4) -> q_idx=2
    // q_idx=2, a[1]=2, a[2]=3. a[1] <= a[2] (2 <= 3) -> q_idx=1
    // q_idx=1, a[0]=1, a[1]=2. a[0] <= a[1] (1 <= 2) -> q_idx=0
    // Loop terminates. q_idx = 0.
    // The prefix to remove is of length 0.

    // E.g., for [4, 3, 3, 8, 4, 5, 2], p_idx = 4.
    // q_idx=4, a[3]=8, a[4]=4. a[3] <= a[4] (8 <= 4) is false. Loop terminates. q_idx = 4.
    // The prefix to remove is of length 4.

    // E.g., for [1, 3, 1, 4, 5, 3, 2], p_idx = 4.
    // q_idx=4, a[3]=4, a[4]=5. a[3] <= a[4] (4 <= 5) -> q_idx=3
    // q_idx=3, a[2]=1, a[3]=4. a[2] <= a[3] (1 <= 4) -> q_idx=2
    // q_idx=2, a[1]=3, a[2]=1. a[1] <= a[2] (3 <= 1) is false. Loop terminates. q_idx = 2.
    // The prefix to remove is of length 2.

    std::cout << q_idx << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
