    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // For odd n, this is the 0-indexed middle element

    // First, ensure the median element itself is s
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually change it to s for subsequent checks

    // Ensure elements to the left of the median are <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Ensure elements to the right of the median are >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
