int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end
        // The condition is x[right_ptr] <= x[i] + d
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy the condition with x[i]
        // We need to choose two distinct points from the range (x[i], x[right_ptr-1]]
        // The number of points available to choose from is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i
        // Let k = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these k points.
        // The number of ways to choose 2 points from k points is k * (k - 1) / 2.

        long long num_available_points = right_ptr - 1 - i;

        if (num_available_points >= 2) {
            count += num_available_points * (num_available_points - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    std::sort(A.begin(), A.end(), compareElementA);
    std::sort(B.begin(), B.end(), compareElementB);

    std::vector<long long> result_A_prime(m);

    // The optimal strategy is to pair the largest A_i with the smallest B_j,
    // the second largest A_i with the second smallest B_j, and so on.
    // This means A_sorted[i] should be paired with B_sorted[m-1-i].
    // The value A_sorted[i] will be placed at the original index of B_sorted[m-1-i].
    for (int i = 0; i < m; ++i) {
        // A[i] is the i-th smallest value from original A.
        // B[m-1-i] is the i-th largest value from original B.
        // We want to assign A[i].value to the position corresponding to B[m-1-i].original_index.
        result_A_prime[B[m - 1 - i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

