int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int consecutive_count = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (chain[0] == 1) { // This chain starts with 1
            consecutive_count = 1;
            for (int j = 1; j < m; ++j) {
                if (chain[j] == chain[j - 1] + 1) {
                    consecutive_count++;
                } else {
                    break; // Sequence 1, 2, ..., consecutive_count is broken
                }
            }
        }
    }

    // Operations to break existing chains:
    // Each chain of length m_i requires m_i - 1 unnesting operations to break it into m_i individual dolls.
    // Total dolls = n. Total chains = k.
    // Total unnesting operations needed to break all chains into individual dolls: n - k.
    // This is because each chain of length m_i has m_i-1 nesting relationships.
    // Sum of (m_i - 1) for all k chains = (sum of m_i) - k = n - k.
    total_operations += (n - k);

    // Operations to form the target chain:
    // The target chain 1 -> 2 -> ... -> n requires n - 1 nesting operations.
    // We have already identified a prefix 1 -> 2 -> ... -> consecutive_count that is already formed.
    // So, we don't need to perform nesting operations for these consecutive_count - 1 pairs.
    // The number of nesting operations saved is (consecutive_count - 1).
    // The number of nesting operations still needed is (n - 1) - (consecutive_count - 1) = n - consecutive_count.
    total_operations += (n - consecutive_count);

    std::cout << total_operations << std::endl;

    return 0;
}

