    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>
#include <numeric>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    // Store them as pairs (prime_factor, count)
    std::vector<std::pair<long long, int>> prime_factors_q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            int count = 0;
            while (temp_q % i == 0) {
                temp_q /= i;
                count++;
            }
            prime_factors_q.push_back({i, count});
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back({temp_q, 1});
    }

    for (const auto& factor_pair : prime_factors_q) {
        long long prime_factor = factor_pair.first;
        int count_in_q = factor_pair.second;

        long long current_p = p;
        // Divide p by prime_factor until it's no longer divisible by q
        // This means we need to remove at least one 'prime_factor' from p
        // such that the resulting number is not divisible by q.
        // The smallest number of 'prime_factor's to remove is count_in_q.
        // So, we divide p by prime_factor until its exponent of prime_factor
        // is less than count_in_q.

        // Calculate p' = p / (prime_factor ^ k) such that p' is not divisible by q
        // and p' is maximized.
        // This means we want to remove just enough prime_factor's from p
        // to break its divisibility by q.
        // The number of prime_factor's in p must be reduced below count_in_q.
        // So, we need to divide p by prime_factor at least (exponent_of_prime_factor_in_p - count_in_q + 1) times.

        long long temp_p = p;
        while (temp_p % q == 0) { // While current_p is still divisible by q
            temp_p /= prime_factor;
        }
        max_x = std::max(max_x, temp_p);
    }

    return max_x;
}

