void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        char last_c1 = '0'; // Last digit colored 1
        char last_c2 = (char)('0' + pivot_digit); // Last digit colored 2 (from S1 part)

        bool possible_pivot = true;
        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < (char)('0' + pivot_digit)) {
                // Must be color 1
                if (current_digit < last_c1) {
                    possible_pivot = false;
                    break;
                }
                result[i] = '1';
                last_c1 = current_digit;
            } else if (current_digit > (char)('0' + pivot_digit)) {
                // Must be color 2
                if (current_digit < last_c2) {
                    possible_pivot = false;
                    break;
                }
                result[i] = '2';
                last_c2 = current_digit;
            } else { // current_digit == pivot_digit
                // Can be either color 1 or color 2
                // Prefer color 2 if it maintains non-decreasing order for S2
                if (current_digit >= last_c2) {
                    result[i] = '2';
                    last_c2 = current_digit;
                } else if (current_digit >= last_c1) { // Otherwise, try color 1
                    result[i] = '1';
                    last_c1 = current_digit;
                } else { // Cannot place in either
                    possible_pivot = false;
                    break;
                }
            }
        }

        if (possible_pivot) {
            found_solution = true;
            std::cout << result << "\n";
            break;
        }
    }

    if (!found_solution) {
        std::cout << "-\n";
    }
}

