#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_s(n, '?');
    bool possible = true;

    // Step 1: Propagate constraints based on s[i] == s[i+k]
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (fixed_s[i] == '?') {
                fixed_s[i] = s[i];
            } else if (fixed_s[i] != s[i]) {
                possible = false;
                break;
            }
        }
        if (i + k < n) {
            if (s[i] != '?' && s[i+k] != '?') {
                if (s[i] != s[i+k]) {
                    possible = false;
                    break;
                }
            } else if (s[i] != '?') {
                if (fixed_s[i+k] == '?') {
                    fixed_s[i+k] = s[i];
                } else if (fixed_s[i+k] != s[i]) {
                    possible = false;
                    break;
                }
            } else if (s[i+k] != '?') {
                if (fixed_s[i] == '?') {
                    fixed_s[i] = s[i+k];
                } else if (fixed_s[i] != s[i+k]) {
                    possible = false;
                    break;
                }
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Propagate fixed_s values
    for (int i = 0; i < n; ++i) {
        if (fixed_s[i] != '?') {
            for (int j = i + k; j < n; j += k) {
                if (fixed_s[j] == '?') {
                    fixed_s[j] = fixed_s[i];
                } else if (fixed_s[j] != fixed_s[i]) {
                    possible = false;
                    break;
                }
            }
            if (!possible) break;
            for (int j = i - k; j >= 0; j -= k) {
                if (fixed_s[j] == '?') {
                    fixed_s[j] = fixed_s[i];
                } else if (fixed_s[j] != fixed_s[i]) {
                    possible = false;
                    break;
                }
            }
            if (!possible) break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Check the first k characters
    // For each remainder r in [0, k-1], all characters s[r], s[r+k], s[r+2k], ... must be the same.
    // This is handled by the propagation above.
    // Now we need to count 0s and 1s in the first k characters.
    int zeros = 0;
    int ones = 0;
    int q_marks = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_s[i] == '0') {
            zeros++;
        } else if (fixed_s[i] == '1') {
            ones++;
        } else { // fixed_s[i] == '?'
            q_marks++;
        }
    }

    if (zeros > k / 2 || ones > k / 2) {
        possible = false;
    } else {
        // We need k/2 zeros and k/2 ones.
        // We have 'zeros' fixed zeros and 'ones' fixed ones.
        // We have 'q_marks' '?'s.
        // We need (k/2 - zeros) more zeros and (k/2 - ones) more ones.
        // The total needed is (k/2 - zeros) + (k/2 - ones) = k - zeros - ones.
        // This must be equal to q_marks.
        // If (k/2 - zeros) < 0 or (k/2 - ones) < 0, it's already caught by zeros > k/2 or ones > k/2.
        // So we just need to check if we have enough '?'s to fill the remaining counts.
        // The number of '?'s we need to fill is (k/2 - zeros) + (k/2 - ones).
        // This sum must be equal to q_marks.
        // (k/2 - zeros) + (k/2 - ones) = k - (zeros + ones)
        // Since q_marks = k - (zeros + ones), this condition is always met if zeros <= k/2 and ones <= k/2.
        // The only thing to check is if we can assign the remaining '?'s.
        // We need to assign (k/2 - zeros) '0's and (k/2 - ones) '1's.
        // The total number of '?'s is q_marks.
