    } else {
        long long b_minus_1 = b - 1;
        long long b_val = b;

        // Calculate (b-1) * b / 2 % MOD
        // Need to handle division by 2. Since MOD is prime, we can use modular inverse.
        // Or, since either (b-1) or b is even, we can divide one of them by 2 first.
        if (b_minus_1 % 2 == 0) {
