int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for two test values: 0 and 1023 (all bits set)
    // We need to track how 0 and 1023 transform.
    // Let's use 0 and -1 (which is all bits set in 2's complement, effectively 1023 for 10 bits)
    // Or, more simply, track how 0 and 1 transform for each bit.
    // Let's track the final value for an input of 0 and an input of 1023.
    // This is not quite right. We need to track how each bit transforms.
    // For each bit position (0 to 9), we need to know:
    // 1. What happens if the input bit is 0? (output_bit_for_input_0)
    // 2. What happens if the input bit is 1? (output_bit_for_input_1)

    // Let's represent the state for each bit position.
    // For each bit `j` (0 to 9):
    // `val_0[j]` will be the `j`-th bit of the result if the input `x` has `j`-th bit 0.
    // `val_1[j]` will be the `j`-th bit of the result if the input `x` has `j`-th bit 1.
    // Initially, if input bit is 0, output bit is 0. If input bit is 1, output bit is 1.
    // So, `val_0[j] = 0` and `val_1[j] = 1` for all `j`.

    // We can represent this more compactly.
    // Let `current_val_if_input_is_0` be the value that 0 transforms into.
    // Let `current_val_if_input_is_1023` be the value that 1023 transforms into.
    // Initially:
    int current_val_if_input_is_0 = 0;
    int current_val_if_input_is_1023 = 1023; // All 10 bits set

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_if_input_is_0 &= x;
            current_val_if_input_is_1023 &= x;
        } else if (op_char == '|') {
            current_val_if_input_is_0 |= x;
            current_val_if_input_is_1023 |= x;
        } else if (op_char == '^') {
            current_val_if_input_is_0 ^= x;
            current_val_if_input_is_1023 ^= x;
        }
    }

    // Now we have the final transformed values for input 0 and input 1023.
    // Let `final_0 = current_val_if_input_is_0`
    // Let `final_1023 = current_val_if_input_is_1023`

    // We need to find `A_AND`, `A_OR`, `A_XOR` such that:
    // `(x & A_AND | A_OR) ^ A_XOR` is equivalent to the original program.
    // Or, more generally, we need to find a sequence of at most 5 operations.
    // The problem states that the constants are 0 to 1023, so we are interested in 10 bits.

    // For each bit `j` (0 to 9):
    // Let `bit_0_result = (final_0 >> j) & 1`
    // Let `bit_1_result = (final_1023 >> j) & 1`

    // If input bit `x_j` is 0, the output bit is `bit_0_result`.
    // If input bit `x_j` is 1, the output bit is `bit_1_result`.

    // We can determine the effective AND, OR, XOR constants for each bit.
    // Let `and_mask`, `or_mask`, `xor_mask` be the constants for the simplified program.
    int and_mask = 1023; // Initially, all bits are 1 for AND (no effect)
    int or_mask = 0;     // Initially, all bits are 0 for OR (no effect)
    int xor_mask = 0;    // Initially, all bits are 0 for XOR (no effect)

    for (int j = 0; j < 10; ++j) {
        int bit_0_result = (current_val_if_input_is_0 >> j) & 1;
        int bit_1_result = (current_val_if_input_is_1023 >> j) & 1;

        // Case 1: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 0
        // This means the output bit is always 0, regardless of input.
        // This can be achieved by `& 0`.
        if (bit_0_result == 0 && bit_1_result == 0) {
            and_mask &= ~(1 << j); // Set j-th bit of and_mask to 0
        }
        // Case 2: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 1
        // This means the output bit is always 1, regardless of input.
        // This can be achieved by `| 1`.
        else if (bit_0_result == 1 && bit_1_result == 1) {
            or_mask |= (1 << j); // Set j-th bit of or_mask to 1
        }
        // Case 3: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 1
        // This means the output bit is the same as the input bit.
        // This is the identity transformation for this bit.
        // Achieved by `& 1`, `| 0`, `^ 0`.
        else if (bit_0_result == 0 && bit_1_result == 1) {
            // and_mask already has 1, or_mask already has 0, xor_mask already has 0.
            // No change needed for this bit for these masks.
        }
        // Case 4: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 0
        // This means the output bit is the inverse of the input bit.
        // Achieved by `^ 1`.
        else if (bit_0_result == 1 && bit_1_result == 0) {
            xor_mask |= (1 << j); // Set j-th bit of xor_mask to 1
        }
    }

    std::vector<std::pair<char, int>> simplified_program;

    // The order of operations matters.
    // A common simplification is `(x & A) | B ^ C`.
    // Let's try to construct this.
    // The `and_mask` determines which bits can pass through.
    // The `or_mask` forces certain bits to 1.
    // The `xor_mask` flips certain bits.

    // If `and_mask` is not 1023 (i.e., some bits are forced to 0), add '&' operation.
    if (and_mask != 1023) {
        simplified_program.push_back({'&', and_mask});
    }
    // If `or_mask` is not 0 (i.e., some bits are forced to 1), add '|' operation.
    if (or_mask != 0) {
        simplified_program.push_back({'|', or_mask});
    }
    // If `xor_mask` is not 0 (i.e., some bits are flipped), add '^' operation.
    if (xor_mask != 0) {
        simplified_program.push_back({'^', xor_mask});
    }

    std::cout << simplified_program.size() << "\n";
    for (const auto& op : simplified_program) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for differences (1 for strawberry, -1 for blueberry)
    // For left side (jars 1 to n), iterate from right to left (n-1 down to 0)
    // For right side (jars n+1 to 2n), iterate from left to right (n up to 2n-1)

    // Left side: jars a[0]...a[n-1]
    // We are interested in suffixes of this left part, starting from a[i] to a[n-1]
    // This means we eat jars a[0]...a[i-1].
    // The number of jars eaten from left is i.
    // The remaining jars are a[i]...a[n-1].
    // Let's define diff_L[k] as the difference (strawberry - blueberry) for jars a[n-k]...a[n-1]
    // where k is the number of jars remaining on the left side.
    // So, k jars remain, n-k jars are eaten from the left.
    std::map<int, int> diff_left_eaten_count; // map<diff, jars_eaten_from_left>
    diff_left_eaten_count[0] = 0; // If 0 jars are eaten from left, diff is 0.

    int current_diff_L = 0;
    for (int i = 0; i < n; ++i) { // Iterate from a[n-1] down to a[0]
        int jar_idx = n - 1 - i; // Current jar being considered (from right to left on left side)
        current_diff_L += (a[jar_idx] == 1 ? 1 : -1);
        if (diff_left_eaten_count.find(current_diff_L) == diff_left_eaten_count.end()) {
            diff_left_eaten_count[current_diff_L] = i + 1; // i+1 jars eaten from left
        }
    }

    // Right side: jars a[n]...a[2n-1]
    // We are interested in prefixes of this right part, starting from a[n] to a[j]
    // This means we eat jars a[j+1]...a[2n-1].
    // The number of jars eaten from right is (2n-1) - j.
    // Let's define diff_R[k] as the difference (strawberry - blueberry) for jars a[n]...a[n+k-1]
    // where k is the number of jars remaining on the right side.
    // So, k jars remain, n-k jars are eaten from the right.
    // We want to find the minimum total jars eaten.
    // Total initial diff = (S_total - B_total)
    // We want remaining_S - remaining_B = 0.
    // This means (S_L_rem + S_R_rem) - (B_L_rem + B_R_rem) = 0
    // (S_L_rem - B_L_rem) + (S_R_rem - B_R_rem) = 0
    // diff_L_rem + diff_R_rem = 0
    // diff_R_rem = -diff_L_rem

    int min_eaten = 2 * n; // Max possible jars eaten

    // Case 1: No jars eaten from right side (j=0)
    // The remaining right side jars are a[n]...a[2n-1].
    // Calculate their difference.
    int initial_diff_R = 0;
    for (int i = n; i < 2 * n; ++i) {
        initial_diff_R += (a[i] == 1 ? 1 : -1);
    }

    // If we eat 'k' jars from the left, the remaining left diff is 'd_L'.
    // We need d_L + initial_diff_R = 0, so d_L = -initial_diff_R.
    if (diff_left_eaten_count.count(-initial_diff_R)) {
        min_eaten = std::min(min_eaten, diff_left_eaten_count[-initial_diff_R]);
    }

    // Case 2: Iterate through eating jars from the right side
    int current_diff_R = 0;
    for (int i = 0; i < n; ++i) { // Iterate from a[n] up to a[2n-1]
        int jar_idx = n + i; // Current jar being considered (from left to right on right side)
        current_diff_R += (a[jar_idx] == 1 ? 1 : -1);
        int jars_eaten_from_right = i + 1; // i+1 jars eaten from right (a[2n-1] down to a[n+i+1])
                                           // No, this is wrong. This is the number of jars *remaining* on the right.
                                           // If we consider a prefix of length (i+1) from the right side (a[n]...a[n+i]),
                                           // then (i+1) jars remain on the right.
                                           // The number of jars eaten from the right is n - (i+1).
                                           // The difference for these remaining (i+1) jars is current_diff_R.
                                           // We need diff_L_rem + current_diff_R = 0, so diff_L_rem = -current_diff_R.

        // If we keep 'i+1' jars on the right, their diff is 'current_diff_R'.
        // The number of jars eaten from the right is n - (i+1).
        // We need to find a 'd_L' such that d_L = -current_diff_R.
        if (diff_left_eaten_count.count(-current_diff_R)) {
            int jars_eaten_from_left = diff_left_eaten_count[-current_diff_R];
            int total_eaten = jars_eaten_from_left + (n - (i + 1));
            min_eaten = std::min(min_eaten, total_eaten);
        }
    }

    std::cout << min_eaten << std::endl;
}

