int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_nodes(n, false);

    // Iterate in reverse order of deletion, effectively adding nodes
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The node being "added" in this step

        active_nodes[k] = true; // Mark node k as active

        // Update shortest paths using node k as an intermediate node
        // Floyd-Warshall update step: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // Only consider paths between currently active nodes
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;

                // Path i -> k -> j
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // Also update paths using other active nodes as intermediate for paths involving k
        // This is crucial because k might be an intermediate for paths between i and j
        // where i and j were already active.
        // And other active nodes might be intermediate for paths involving k.
        // The standard Floyd-Warshall order is k (outer loop), i (middle loop), j (inner loop).
        // We've just processed k as the "new" intermediate.
        // Now, we need to ensure all pairs (i,j) among active nodes are updated considering k
        // and any other active node as intermediate.
        // The previous loop updated dist[i][j] using k as intermediate.
        // We also need to update dist[i][k] and dist[k][j] using other active nodes as intermediate.
        // This is effectively running a partial Floyd-Warshall for all active nodes.
        // Since k is the *newest* active node, we can iterate through all active nodes
        // and update paths.

        // The standard Floyd-Warshall structure is:
        // for (k_prime : all_nodes)
        //   for (i_prime : all_nodes)
        //     for (j_prime : all_nodes)
        //       dist[i_prime][j_prime] = min(dist[i_prime][j_prime], dist[i_prime][k_prime] + dist[k_prime][j_prime])
        //
        // When we add node 'k', we need to ensure that for all active 'i' and 'j',
        // dist[i][j] is updated considering 'k' as an intermediate.
        // And also, for all active 'i_prime', 'j_prime', and 'k_prime' (where k_prime is also active),
        // dist[i_prime][j_prime] is updated.
        // The three nested loops below achieve this for the current set of active nodes.
        // The order of loops (k_prime, i_prime, j_prime) is important for correctness.
        // Here, k_prime iterates over all currently active nodes.
        for (int k_prime = 0; k_prime < n; ++k_prime) {
            if (!active_nodes[k_prime]) continue;
            for (int i_prime = 0; i_prime < n; ++i_prime) {
                if (!active_nodes[i_prime]) continue;
                for (int j_prime = 0; j_prime < n; ++j_prime) {
                    if (!active_nodes[j_prime]) continue;
                    if (dist[i_prime][k_prime] != -1 && dist[k_prime][j_prime] != -1) {
                        if (dist[i_prime][j_prime] == -1 || dist[i_prime][k_prime] + dist[k_prime][j_prime] < dist[i_prime][j_prime]) {
                            dist[i_prime][j_prime] = dist[i_prime][k_prime] + dist[k_prime][j_prime];
                        }
                    }
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before first deletion, before second, etc.)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

