    // Let's use a generous bound like n to be safe, or even n/2.
    // The maximum number of steps is actually (last_transition_idx - first_transition_idx + 1) / 2.
    // Example: 01010 (n=5). first_trans=0, last_trans=3. (3-0+1)/2 = 2. Correct.
    // Example: 0011 (n=4). first_trans=1, last_trans=1. (1-1+1)/2 = 0. Correct.
    // Example: 000111 (n=6). first_trans=2, last_trans=2. (2-2+1)/2 = 0. Correct.
    // Example: 01110 (n=5). first_trans=0, last_trans=3. (3-0+1)/2 = 2.
    // 01110 -> 01110 (stable) -> 0 steps.
    // My formula is for the "width" of the unstable region.
    // The actual number of steps is the maximum of:
    // 1. The number of steps for the first block to stabilize: first_transition_idx + 1 if a[0] != a[first_transition_idx+1]
    // 2. The number of steps for the last block to stabilize: n - (last_transition_idx + 1) if a[n-1] != a[last_transition_idx]
    // 3. The number of steps for the middle part to stabilize.
    // The maximum number of steps is actually `(last_transition_idx - first_transition_idx + 1) / 2`
    // if the sequence is of the form 0...01...10...0 or 1...10...01...1.
    // For 01010, first_trans=0, last_trans=3. (3-0+1)/2 = 2.
    // For 01110, first_trans=0, last_trans=3. (3-0+1)/2 = 2. But it's 0 steps.
    // The formula is for the maximum possible steps for a sequence of alternating values.
    // The actual number of steps is bounded by `n/2`. Let's use `n` as a safe upper bound for the loop.
    // The problem statement guarantees that if it stabilizes, it does so in a finite number of steps.
    // The maximum number of steps is actually `(n-1)/2`.
    // For N=500,000, this is 249,999.
    // A loop for `n` iterations is fine.

    for (int k = 0; k < n; ++k) { // Max steps is bounded by n/2, so n iterations is safe.
        if (!apply_median_smoothing(current_seq, next_seq)) {
            break; // Sequence became stable
        }
        steps++;
    }

    // Check for non-stability (oscillating sequences)
    // An oscillating sequence would be something like 010101...
    // However, for 0s and 1s, the median filter tends to "flatten" sequences.
    // It's known that for 0/1 sequences, the median filter always converges to a stable state.
    // The only stable sequences are blocks of 0s and 1s, e.g., 000111, 00000, 11111.
    // A sequence like 010101... will eventually become 000000... or 111111...
    // The problem statement implies that it *might* not become stable, but for 0/1 sequences, it always does.
    // So, we don't need to output -1. The loop will always break.

    std::cout << steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v;
    long long d;
    long long p;
    int original_idx;
    bool active; // To mark if child is still in line

    Child(long long v_val, long long d_val, long long p_val, int idx)
        : v(v_val), d(d_val), p(p_val), original_idx(idx), active(true) {}
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children_data;
    children_data.reserve(n);
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_data.emplace_back(v_val, d_val, p_val, i + 1);
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children_data[i].active) {
            continue; // This child has already left
        }

        // Child i goes to the dentist
        treated_children_indices.push_back(children_data[i].original_idx);
        children_data[i].active = false; // Mark as treated

        long long current_v_cry = children_data[i].v;
        long long cumulative_d_cry = 0;

        // Apply initial cry from child i
        for (int j = i + 1; j < n; ++j) {
            if (!children_data[j].active) {
                continue;
            }

            // Apply cry from child i
            if (current_v_cry > 0) {
                children_data[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply cumulative cry from children who left earlier in this chain reaction
            children_data[j].p -= cumulative_d_cry;
        }

        // Chain reaction loop
        bool chain_reaction_happened;
        do {
            chain_reaction_happened = false;
            for (int j = i + 1; j < n; ++j) {
                if (children_data[j].active && children_data[j].p < 0) {
                    children_data[j].active = false; // Child j leaves
                    cumulative_d_cry += children_data[j].d; // Add to cumulative cry
                    chain_reaction_happened = true;

                    // Apply this child's d_cry to all subsequent active children
                    for (int k = j + 1; k < n; ++k) {
                        if (children_data[k].active) {
                            children_data[k].p -= children_data[j].d;
                        }
                    }
                }
            }
        } while (chain_reaction_happened);
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], current_max_val);
            }
        }
    }

    std::vector<long long> a_prime(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == std::numeric_limits<long long>::max()) {
            a_prime[i] = 0; // Default to 0 if no upper bound from type 2 ops
        } else {
            a_prime[i] = b[i];
        }
    }

    std::vector<long long> current_a = a_prime;
    std::vector<long long> delta(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
                delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, current_a[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_prime[i] - delta[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * max(a_i) which is 2*10^5 * 10^9 = 2*10^14.
// x is an index, so it fits in int.

// Memoization tables for results and visited states
std::vector<long long> memo_y;
std::vector<int> memo_visited_step; // 0: not visited, 1: visiting (cycle detected), 2: visited (result computed)

// The actual sequence a_2, ..., a_n
std::vector<int> a_suffix;
int N;

// Recursive function to calculate y for a given starting x and step
// current_x: the current value of x
// current_step: 0 for step 2, 1 for step 3
long long solve(int current_x, int current_step) {
    // Termination condition: x <= 0 or x > N
    if (current_x <= 0 || current_x > N) {
        return 0; // Base case: program terminates, adds 0 to y
    }

    // Calculate the index for memoization
    // The state is (current_x, current_step)
    // We can map this to a single index: (current_x - 1) * 2 + current_step
    // current_x ranges from 1 to N, current_step is 0 or 1
    int memo_idx = (current_x - 1) * 2 + current_step;

    // Check memoization table
    if (memo_visited_step[memo_idx] == 1) {
        // Cycle detected
        return -1;
    }
    if (memo_visited_step[memo_idx] == 2) {
        // Already computed
        return memo_y[memo_idx];
    }

    // Mark as visiting
    memo_visited_step[memo_idx] = 1;

    long long res;
    int val_at_x;

    if (current_x == 1) {
        // This case is special: a_1 is the 'i' from the outer loop.
        // This function is called with current_x=1 only when we are calculating
        // the result for a specific starting 'i'.
        // The actual value of a_1 is passed as a parameter to the outer loop,
        // not stored in a_suffix.
        // This branch should ideally not be reached by recursive calls,
        // only by the initial call for a specific 'i'.
        // However, if it is reached, it means we are trying to access a_1
        // from within the recursive calls, which is not how the problem is structured.
        // The problem states "run the program on the sequence i, a_2, a_3, ..., a_n".
        // This implies a_1 is fixed for a given run.
        // The recursive calls will always use a_suffix for x > 1.
        // For x=1, the value is 'i' from the outer loop.
        // This function `solve` is designed for the general case where `a_x` is known.
        // The initial call for each `i` will handle `a_1 = i`.
        // So, if `current_x == 1`, this means we are trying to access `a_1`
        // from a state that is not the initial state. This should not happen
        // if the problem is interpreted correctly.
        // To be safe, we can return -1 or handle it as an error.
        // However, the problem implies that `a_1` is only set at the very beginning.
        // The `a_suffix` vector stores `a_2, ..., a_N`.
        // So, `a_suffix[k-2]` corresponds to `a_k`.
        // If `current_x == 1`, we need the value of `a_1` which is `i`.
        // This `solve` function is not designed to take `i` as a parameter.
        // The `solve` function should only be called for `x > 1` or for the initial `x=1`
        // where `a_1` is known.
        // Let's assume `solve` is only called for `x > 1` in recursive steps.
        // The initial call for each `i` will be handled separately.
        // This means `val_at_x` will always be from `a_suffix`.
        // This is a critical point. The problem states:
        // "The program increases both x and y by a value equal to a_{x} simultaneously."
        // "The program now increases y by a_{x} while decreasing x by a_{x}."
        // This `a_x` refers to the value at the current `x`.
        // So, if `x` becomes 1 during the process, it will use `a_1`.
        // The `a_1` value is different for each `i` in the outer loop.
        // This means the memoization table `memo_y` and `memo_visited_step`
        // are dependent on the initial `a_1` value.
        // Therefore, these tables must be cleared or recomputed for each `i`.
        // This makes the solution O(N * N) which is too slow (2*10^5 * 2*10^5 = 4*10^10).

        // Re-reading the problem: "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_{n}."
        // This means `a_1` is `i` for that specific run.
        // The `solve` function needs to know `a_1` if `current_x` becomes 1.
        // This implies `a_1` must be passed as a parameter to `solve` or `a_suffix` must be modified.
        // Modifying `a_suffix` for each `i` and then clearing memo tables is O(N^2).
        // We need a faster approach.

        // The key observation for optimization:
        // The path `x -> x + a_x -> (x + a_x) - a_{x+a_x}`
        // The values `a_2, ..., a_N` are fixed. Only `a_1` changes.
        // If `x` is never 1 during the execution (except for the very first step),
        // then the path is independent of `a_1`.
        // If `x` becomes 1 at some point, then `a_1` matters.

        // Let's redefine `solve` to take `a_1_val` as a parameter.
        // This would still be O(N^2) because memoization depends on `a_1_val`.

        // The problem structure suggests dynamic programming or memoization.
        // The state is (current_x, current_step).
        // The values `a_2, ..., a_N` are fixed.
        // The only variable is `a_1` (which is `i`).
        // If `current_x != 1`, then `val_at_x = a_suffix[current_x - 2]`.
        // If `current_x == 1`, then `val_at_x = a_1_val`.

        // This means we need to compute results for `x=1` separately.
        // For `x > 1`, the results `(x, step)` are independent of `a_1`.
        // So, we can precompute `memo_y` and `memo_visited_step` for `x > 1`.
        // Then, for each `i`, we only need to simulate the first few steps
        // until `x` is no longer 1, or terminates, or cycles.

        // Let's adjust the `solve` function to handle `a_1_val` for `current_x == 1`.
        // This means `memo_y` and `memo_visited_step` cannot be global for `x=1`.
        // We need to compute `solve_for_x_gt_1(current_x, current_step)`
        // and then use that for the initial `i`.

        // Let's try to make `solve` compute for `x > 1` only.
        // The initial call for each `i` will be:
        // `x = 1, y = 0`.
        // `val_a1 = i`.
        // Step 2: `next_x = 1 + val_a1`, `next_y = 0 + val_a1`.
        // Step 3: `final_x = next_x - val_a1`, `final_y = next_y + val_a1`.
        // Now, if `final_x` is `1`, we have a cycle `1 -> (1+i) -> 1`.
        // If `final_x` is `0` or `>N`, it terminates.
        // Otherwise, we call `solve_for_x_gt_1(final_x, 0)` (because it's step 2 again).

        // This approach seems viable.
        // `memo_y` and `memo_visited_step` will store results for `x` from 2 to `N`.
        // The size of these vectors will be `(N-1) * 2`.
        // `memo_idx` for `x` from 2 to `N` and step 0/1: `(current_x - 2) * 2 + current_step`.

        // Let's restart the `solve` function logic with this in mind.
        // `solve(current_x, current_step)` will compute the *additional* `y` value
        // from this state until termination, or -1 for cycle.
        // It assumes `current_x >= 2`.
    }

    // `val_at_x` is `a_x`.
    // For `current_x >= 2`, `a_x` is `a_suffix[current_x - 2]`.
    val_at_x = a_suffix[current_x - 2];

    if (current_step == 0) { // Step 2: x = x + a_x, y = y + a_x
        long long y_added = val_at_x;
        int next_x = current_x + val_at_x;
        long long next_res = solve(next_x, 1); // Next is step 3
        if (next_res == -1) {
            res = -1;
        } else {
            res = y_added + next_res;
        }
    } else { // Step 3: x = x - a_x, y = y + a_x
        long long y_added = val_at_x;
        int next_x = current_x - val_at_x;
        long long next_res = solve(next_x, 0); // Next is step 2
        if (next_res == -1) {
            res = -1;
        } else {
            res = y_added + next_res;
        }
    }

    // Store result and mark as computed
    memo_y[memo_idx] = res;
    memo_visited_step[memo_idx] = 2;
    return res;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_suffix.resize(N - 1);
    for (int k = 0; k < N - 1; ++k) {
        std::cin >> a_suffix[k];
    }

    // Precompute results for x from 2 to N.
    // The state space for x >= 2 is (N-1) * 2 states.
    // (x-2)*2 + step for x in [2, N], step in [0, 1]
    memo_y.resize((N - 1) * 2);
    memo_visited_step.resize((N - 1) * 2, 0); // 0: unvisited, 1: visiting, 2: visited

    // Populate memo tables for x >= 2
    // Iterate through all possible states (x, step) where x >= 2
    for (int x_val = 2; x_val <= N; ++x_val) {
        for (int step_val = 0; step_val < 2; ++step_val) {
            int memo_idx = (x_val - 2) * 2 + step_val;
            if (memo_visited_step[memo_idx] == 0) { // If not yet computed
                solve(x_val, step_val);
            }
        }
    }

    // Now, for each i (1 to N-1), simulate the program
    for (int i = 1; i < N; ++i) {
        long long current_y = 0;
        int current_x = 1;
        int a1_val = i; // a_1 is 'i' for this run

        // First pair of steps (Step 2 then Step 3)
        // Step 2: x = x + a_x, y = y + a_x
        long long y_added_s2 = a1_val;
        int next_x_s2 = current_x + a1_val;
        current_y += y_added_s2;

        // Check termination after Step 2
        if (next_x_s2 <= 0 || next_x_s2 > N) {
            std::cout << current_y << "\n";
            continue;
        }

        // Step 3: x = x - a_x, y = y + a_x
        long long y_added_s3 = a1_val; // a_x is still a1_val from the previous x
        int next_x_s3 = next_x_s2 - a1_val;
        current_y += y_added_s3;

        // Check termination after Step 3
        if (next_x_s3 <= 0 || next_x_s3 > N) {
            std::cout << current_y << "\n";
            continue;
        }

        // If next_x_s3 is 1, it's a cycle (1 -> (1+a1) -> 1)
        if (next_x_s3 == 1) {
            std::cout << -1 << "\n";
            continue;
        }

        // Now x is next_x_s3 (which is >= 2), and the next step is Step 2.
        // We can use the precomputed results.
        int memo_idx = (next_x_s3 - 2) * 2 + 0; // 0 for Step 2
        long long remaining_y = memo_y[memo_idx];

        if (remaining_y == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + remaining_y << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...N-1].
    // The new string is s[i...N-1] + s[0...i-1].
    // We need to find if there's any i (1 <= i < N) such that
    // s[i...N-1] + s[0...i-1] is a palindrome AND is not equal to s.
    for (int i = 1; i < n; ++i) {
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // This means 3 pieces.
    // The problem statement implies that if k=1 doesn't work,
    // then k=2 is the next minimum.
    // The only case where k=2 might not be possible is if all characters are the same.
    // If all characters are the same, e.g., "qqqq", then any rearrangement of pieces
    // will result in the same string "qqqq".
    // In this case, it's impossible to form a new string s' != s.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Example: s = "nolon"
        // Cut: no|l|on. Pieces: "no", "l", "on".
        // Rearrange: on|l|no. New string: "onlno". This is a palindrome and != "nolon".
        // This requires 2 cuts.
        // The logic is that if not all characters are the same,
        // there must be at least two distinct characters.
        // Since s is a palindrome, it has some structure.
        // If n is odd, say n=2m+1, s = c_1 ... c_m c_{m+1} c_m ... c_1.
        // If we cut s into s[0...m-1], s[m], s[m+1...n-1],
        // these are P1 = s[0...m-1], P2 = s[m], P3 = s[m+1...n-1].
        // Note that P1 is the reverse of P3.
        // So, P3 + P2 + P1 would be a palindrome.
        // Example: "nolon", n=5, m=2.
        // P1="no", P2="l", P3="on".
        // P3+P2+P1 = "onlno". This is a palindrome.
        // This new string "onlno" is different from "nolon" unless "no" == "on", which is false.
        // This strategy works as long as P1 != P3 (which is always true unless P1 is empty or P1 == P3.reverse()).
        // More generally, if s is not all same characters, we can always find a cut that works.
        // Consider s = A B A where A is s[0...k-1] and B is s[k...N-k-1].
        // If we cut s into A | B | A, we can rearrange to A | B | A (original) or A | A | B (not necessarily palindrome) or B | A | A (not necessarily palindrome).
        // The example "nolon" -> "onlno" uses pieces s[0...1], s[2], s[3...4].
        // These are "no", "l", "on". Rearranged as "on", "l", "no".
        // This is equivalent to taking s[0...k-1] and s[N-k...N-1] and swapping them around the middle part.
        // If s is not all same characters, then there exists at least one character s[i] != s[0].
        // Since s is a palindrome, s[i] == s[N-1-i].
        // If we take a prefix s[0...i] and suffix s[N-1-i...N-1] and swap them,
        // it will result in a different string.
        // The minimum number of cuts to achieve a different palindrome when k=1 fails
        // and not all characters are the same is 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = -1;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // All pairs (a_i, a_j) are in the same subsequence.
    // f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    if (n >= 2) {
        long long current_goodness = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
        min_goodness = current_goodness;
        for (int i = 0; i < n; ++i) {
            best_partition[a[i].original_index] = 1;
        }
    } else { // n=1, no pairs, goodness is 0.
        min_goodness = 0;
        best_partition[a[0].original_index] = 1;
    }


    // Case 2: Partition with at least one element in each subsequence.
    // This means there will be pairs (a_i, a_j) with a_i, a_j in same subsequence
    // AND pairs (a_i, a_j) with a_i, a_j in different subsequences.
    // So, min_f will be min(a_i + a_j) and max_f will be max(a_i + a_j + h).
    // The minimum possible sum a_i + a_j is a[0].value + a[1].value.
    // The maximum possible sum a_i + a_j + h is a[n-1].value + a[n-2].value + h.
    // So, min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value + h
    // goodness = (a[n-1].value + a[n-2].value + h) - (a[0].value + a[1].value)
    // This is the goodness if all types of pairs exist.

    // However, we can try to optimize by putting a[0] and a[n-1] in different groups.
    // Consider the partition where a[0] is in S1 and a[n-1] is in S2.
    // All other elements can be in S1 or S2.
    // The smallest possible sum a_i + a_j is a[0].value + a[1].value.
    // The largest possible sum a_i + a_j is a[n-1].value + a[n-2].value.
    // The smallest possible sum a_i + a_j + h is a[0].value + a[1].value + h (if a[0] in S1, a[1] in S2).
    // The largest possible sum a_i + a_j + h is a[n-1].value + a[n-2].value + h (if a[n-1] in S1, a[n-2] in S2).

    // Let's consider a specific partition strategy:
    // Put a[0] in S1.
    // Put a[n-1] in S2.
    // Put all other elements a[1]...a[n-2] in S1.
    // S1 = {a[0], a[1], ..., a[n-2]}
    // S2 = {a[n-1]}
    //
    // Pairs in S1:
    // min_same = a[0].value + a[1].value
    // max_same = a[n-2].value + a[n-3].value (if n-2 >= 1, i.e., n >= 3)
    // If n=2, S1={a[0]}, S2={a[1]}, no same-subsequence pairs.
    //
    // Pairs in S2: None (S2 has only one element).
    //
    // Pairs across S1 and S2:
    // min_diff = a[0].value + a[n-1].value + h
    // max_diff = a[n-2].value + a[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same, min_diff)
    // max_f = max(max_same, max_diff)

    // If n=2: S1={a[0]}, S2={a[1]}. Only one pair (a[0], a[1]) across subsequences.
    // f(a[0], a[1]) = a[0].value + a[1].value + h.
    // min_f = max_f = a[0].value + a[1].value + h. Goodness = 0.
    // This is better than Case 1 if h > 0.
    if (n == 2) {
        long long current_goodness = 0;
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            best_partition[a[1].original_index] = 2;
        }
    } else { // n >= 3
        // Strategy: a[0] in S1, a[n-1] in S2, all others in S1.
        // S1 = {a[0], a[1], ..., a[n-2]}
        // S2 = {a[n-1]}
        long long current_min_f = a[0].value + a[1].value; // from S1
        long long current_max_f = a[n-2].value + a[n-1].value + h; // from S1-S2

        // Check if a[n-2] + a[n-3] (from S1) is greater than current_max_f
        if (n >= 3) { // a[n-3] exists
            current_max_f = std::max(current_max_f, a[n-2].value + a[n-3].value);
        }

        // Check if a[0] + a[n-1] + h (from S1-S2) is smaller than current_min_f
        current_min_f = std::min(current_min_f, a[0].value + a[n-1].value + h);

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 1;
            }
            best_partition[a[n - 1].original_index] = 2;
        }

        // Strategy: a[0] in S1, a[n-1] in S2, all others in S2.
        // S1 = {a[0]}
        // S2 = {a[1], ..., a[n-1]}
        current_min_f = a[1].value + a[2].value; // from S2
        current_max_f = a[n-1].value + a[n-2].value; // from S2

        // Check if a[0] + a[n-1] + h (from S1-S2) is greater than current_max_f
        current_max_f = std::max(current_max_f, a[0].value + a[n-1].value + h);

        // Check if a[0] + a[1] + h (from S1-S2) is smaller than current_min_f
        current_min_f = std::min(current_min_f, a[0].value + a[1].value + h);

        current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 2;
            }
            best_partition[a[n - 1].original_index] = 2;
        }
    }

    // Consider a special case for n >= 3:
    // S1 = {a[0], a[n-1]}
    // S2 = {a[1], ..., a[n-2]}
    //
    // Pairs in S1: a[0].value + a[n-1].value
    // Pairs in S2: min = a[1].value + a[2].value, max = a[n-2].value + a[n-3].value
    // Pairs across S1-S2:
    // min = a[0].value + a[1].value + h
    // max = a[n-1].value + a[n-2].value + h
    //
    // This strategy is only relevant if n >= 4 for S2 to have at least two elements.
    // If n=3: S1={a[0], a[2]}, S2={a[1]}.
    // Pairs in S1: a[0].value + a[2].value
    // Pairs in S2: None
    // Pairs across S1-S2:
    // a[0].value + a[1].value + h
    // a[2].value + a[1].value + h
    //
    // min_f = min(a[0].value + a[2].value, a[0].value + a[1].value + h)
    // max_f = max(a[0].value + a[2].value, a[2].value + a[1].value + h)
    //
    // This is a specific partition that might be optimal.
    // Let's check this for n >= 3.
    if (n >= 3) {
        long long current_min_f;
        long long current_max_f;

        // S1 = {a[0], a[n-1]}, S2 = {a[1], ..., a[n-2]}
        // min_f candidates:
        //   a[0].value + a[n-1].value (from S1)
        //   a[0].value + a[1].value + h (from S1-S2)
        //   a[1].value + a[2].value (from S2, if n-2 >= 2, i.e., n >= 4)
        // max_f candidates:
        //   a[0].value + a[n-1].value (from S1)
        //   a[n-1].value + a[n-2].value + h (from S1-S2)
        //   a[n-2].value + a[n-3].value (from S2, if n-2 >= 2, i.e., n >= 4)

        current_min_f = a[0].value + a[n-1].value;
        current_max_f = a[0].value + a[n-1].value;

        current_min_f = std::min(current_min_f, a[0].value + a[1].value + h);
        current_max_f = std::max(current_max_f, a[n-1].value + a[n-2].value + h);

        if (n >= 4) { // S2 has at least two elements
            current_min_f = std::min(current_min_f, a[1].value + a[2].value);
            current_max_f = std::max(current_max_f, a[n-2].value + a[n-3].value);
        } else if (n == 3) { // S2 has only one element a[1], no same-subsequence pairs in S2
            // No additional min/max from S2 same-subsequence pairs
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            best_partition[a[n - 1].original_index] = 1;
            for (int i = 1; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = static_cast<long long>(n) * (n + 1) / 2;
    long long bad_pairs_to_subtract = 0;

    // dp[i] will store the maximum 'r' such that the substring s[i...r]
    // does NOT contain any bad triplet.
    // Initialize dp[i] to n for all i, meaning s[i...n-1] is initially considered good.
    // This is equivalent to saying that for any l, the maximum r for which (l,r) is good
    // is initially n.
    std::vector<int> dp(n + 1, n); 

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through all possible step sizes k
        // The condition x + 2k < n must hold.
        // So, 2k < n - x, or k < (n - x) / 2.
        // Also, k must be at least 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet (x, x+k, x+2k)
                // This triplet starts at x and ends at x + 2k.
                // Any substring s[l...r] that contains this triplet
                // (i.e., l <= x and x + 2k <= r) is a "bad" pair (l,r).

                // The maximum 'r' for which s[x...r] is "good" (does not contain this triplet)
                // must be less than x + 2k.
                // Specifically, if a triplet ends at x + 2k, then any good substring starting at x
                // must end at most at (x + 2k - 1).
                // So, for the starting position x, the maximum 'r' for which s[x...r] is good
                // cannot extend beyond x + 2k - 1.
                // We update dp[x] to be the minimum of its current value and (x + 2k).
                // This means that for any l <= x, the maximum r for which (l,r) is good
                // cannot be greater than (x + 2k - 1).
                // The dp[i] stores the first index 'j' such that s[i...j] contains a bad triplet.
                // Or, more precisely, dp[i] stores the minimum 'x + 2k' over all bad triplets
                // (x, x+k, x+2k) such that x >= i.
                // If dp[i] = N, it means no bad triplet starts at or after i.
                dp[x] = std::min(dp[x], x + 2 * k);

                // Optimization: If k is large, say k >= 6, then 2k >= 12.
                // The problem constraints on n are up to 300,000.
                // For k >= 6, the distance between x and x+2k is at least 12.
                // This means s[x], s[x+k], s[x+2k] are far apart.
                // If s[x] == s[x+k] == s[x+2k], then s[x] == s[x+k] and s[x+k] == s[x+2k].
                // If we have s[i] == s[i+1] == s[i+2] for some i, this is a bad triplet with k=1.
                // If we have s[i] == s[i+2] == s[i+4] for some i, this is a bad triplet with k=2.
                // The maximum k we need to check is relatively small.
                // If k is large, say k > 5, then x+2k is far from x.
                // The problem statement implies that k can be up to n.
                // However, if k is large, say k > 5, then x+2k is at least x+12.
                // If we have s[x] == s[x+k] == s[x+2k], then for any l <= x and r >= x+2k,
                // the pair (l,r) is counted.
                // The crucial observation is that if a triplet (x, x+k, x+2k) exists,
                // then for any l <= x, the maximum r for which (l,r) is *good* is x+2k-1.
                // This means we are interested in the smallest x+2k for a given x.
                // The smallest x+2k occurs for the smallest k.
                // The smallest k is 1.
                // If s[x] == s[x+1] == s[x+2], then dp[x] = min(dp[x], x+2).
                // If s[x] == s[x+2] == s[x+4], then dp[x] = min(dp[x], x+4).
                // If s[x] == s[x+3] == s[x+6], then dp[x] = min(dp[x], x+6).
                // If s[x] == s[x+4] == s[x+8], then dp[x] = min(dp[x], x+8).
                // If s[x] == s[x+5] == s[x+10], then dp[x] = min(dp[x], x+10).
                // If k > 5, then x+2k > x+10.
                // So, if there is a bad triplet with k <= 5, it will always give a smaller or equal
                // 'x+2k' value than any bad triplet with k > 5 starting at the same 'x'.
                // Therefore, we only need to check k from 1 to 5.
                // This optimization is critical for N=300,000.
                if (k > 5) break; // Optimization: only check small k values
            }
        }
    }

    // Propagate the minimum 'x+2k' values backwards.
    // dp[i] should store the minimum 'x+2k' for any bad triplet (x, x+k, x+2k)
    // such that x >= i.
    // This means dp[i] = min(dp[i], dp[i+1]).
    for (int i = n - 1; i >= 0; --i) {
        dp[i] = std::min(dp[i], dp[i + 1]);
    }

    // Now, for each starting position 'l' (0-indexed),
    // dp[l] gives the smallest 'x+2k' such that x >= l and s[x]=s[x+k]=s[x+2k].
    // If dp[l] == n, it means no bad triplet starts at or after 'l'.
    // In this case, all pairs (l, r) for r from l to n-1 are "good".
    // If dp[l] < n, it means there is a bad triplet starting at some x >= l,
    // and the earliest this triplet ends is at dp[l].
    // So, for a given 'l', any 'r' such that r >= dp[l] - 1 will make (l,r) a "bad" pair.
    // The number of 'good' pairs (l, r) for a fixed 'l' is when r < dp[l].
    // The possible values for r are l, l+1, ..., dp[l]-1.
    // The count of such 'r' values is (dp[l]-1) - l + 1 = dp[l] - l.
    // These are the pairs (l, r) that do NOT contain any bad triplet.
    // We want to subtract these from the total.
    // No, this is incorrect. We want to count (l,r) such that there IS at least one bad triplet.
    // The number of pairs (l,r) such that l <= x and x+2k <= r for some (x,k)
    // is what we need to count.
    // Let's re-evaluate.
    // dp[i] = min_end_idx for a bad triplet starting at or after i.
    // If dp[i] == n, no bad triplet starts at or after i.
    // For a given 'l', if dp[l] == n, then no bad triplet exists for any x >= l.
    // So, for this 'l', all pairs (l, r) for r from l to n-1 are "good" (don't contain a bad triplet).
    // If dp[l] < n, it means there is a bad triplet (x, x+k, x+2k) with x >= l,
    // and the earliest such triplet ends at dp[l].
    // So, for a fixed 'l', any 'r' such that r >= dp[l] - 1 will make (l,r) a "bad" pair.
    // The number of such 'r' values is (n-1) - (dp[l]-1) + 1 = n - dp[l] + 1.
    // This is the number of 'r' values for which (l,r) is a "bad" pair.
    // Sum this over all 'l'.

    for (int l = 0; l < n; ++l) {
        // dp[l] is the minimum 'x+2k' such that x >= l and s[x]=s[x+k]=s[x+2k].
        // If dp[l] == n, it means no such triplet exists for x >= l.
        // So, for this 'l', no (l,r) pair will satisfy the condition.
        // If dp[l] < n, it means there is at least one triplet (x, x+k, x+2k)
        // with x >= l and ending at dp[l].
        // For any r such that dp[l] <= r < n, the pair (l, r) contains this triplet.
        // The number of such 'r' values is n - dp[l].
        bad_pairs_to_subtract += (n - dp[l]);
    }

    std::cout << bad_pairs_to_subtract << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n && p_idx < m; ++h_idx) {
        long long current_h = h[h_idx];
        long long head_left_reach = current_h - T;
        long long head_right_reach = current_h + T;

        // If the current head cannot reach the current target track,
        // it means this head is too far to the left.
        // We need to find a head that can reach p[p_idx].
        // The current head must be able to reach p[p_idx] or a track to its right.
        // If p[p_idx] is already to the right of head_right_reach, this head cannot cover it.
        // If p[p_idx] is to the left of head_left_reach, this head cannot cover it.
        // So, we need to find a head such that head_left_reach <= p[p_idx].
        // Since h is sorted, we can skip heads that are too far left.
        // However, the problem is about covering all p_j.
        // A head h_i can cover a range [h_i - T, h_i + T].
        // We want to cover p_idx, p_idx+1, ..., m-1.

        // Find the first p_j that this head can cover.
        // If p[p_idx] is already covered by a previous head, we move to the next p_idx.
        // This loop is implicitly handled by the outer loop's p_idx advancement.

        // If the current head cannot reach the current target p[p_idx] (i.e., p[p_idx] > head_right_reach),
        // then this head cannot cover p[p_idx]. We need another head.
        // But this is not correct. A head can cover a range.
        // We need to cover p[p_idx] with *some* head.

        // Let's rephrase: we want to cover the segment [p[p_idx], p[m-1]] using the remaining heads.
        // For the current head h_idx, it can cover tracks in [h[h_idx] - T, h[h_idx] + T].
        // We want to cover p[p_idx].
        // If p[p_idx] is to the right of h[h_idx] + T, this head cannot cover p[p_idx].
        // If p[p_idx] is to the left of h[h_idx] - T, this head cannot cover p[p_idx].
        // So, we must have h[h_idx] - T <= p[p_idx] <= h[h_idx] + T.

        // This is a greedy approach:
        // For the current target track p[p_idx], find the leftmost head h[h_idx] that can cover it.
        // Once h[h_idx] covers p[p_idx], it can also cover other tracks to the right, up to h[h_idx] + T.
        // We then advance p_idx past all tracks covered by h[h_idx].

        // Skip heads that are too far to the left to cover p[p_idx].
        // If h[h_idx] + T < p[p_idx], this head cannot cover p[p_idx].
        // We need to find a head h_k such that h_k + T >= p[p_idx].
        // The current h_idx might be too far left.
        // We need to find the first h_idx such that h[h_idx] - T <= p[p_idx].
        // If no such h_idx exists, then p[p_idx] cannot be covered.

        // Let's use a two-pointer approach.
        // `p_idx` points to the first uncovered target track.
        // `h_idx` points to the current head we are considering.

        // If the current head h[h_idx] cannot reach p[p_idx] (i.e., p[p_idx] > h[h_idx] + T),
        // then this head is too far to the left to cover p[p_idx].
        // We must use a head further to the right.
        // This means the current h[h_idx] cannot cover p[p_idx], so we need to move to the next head.
        // This is not quite right. A head can move left or right.
        // The crucial part is that a head h_i can cover the range [h_i - T, h_i + T].

        // We need to cover p[p_idx].
        // The current head h[h_idx] can cover p[p_idx] if h[h_idx] - T <= p[p_idx] <= h[h_idx] + T.
        // If p[p_idx] is to the left of h[h_idx] - T, then h[h_idx] cannot cover p[p_idx] by moving right.
        // It can only cover p[p_idx] by moving left.
        // If p[p_idx] is to the right of h[h_idx] + T, then h[h_idx] cannot cover p[p_idx] by moving left.
        // It can only cover p[p_idx] by moving right.

        // The greedy strategy should be:
        // For the current `p[p_idx]` (the leftmost uncovered target track),
        // find the leftmost head `h[h_idx]` that can reach `p[p_idx]`.
        // If `h[h_idx] + T < p[p_idx]`, then `h[h_idx]` cannot reach `p[p_idx]` even by moving right.
        // In this case, `h[h_idx]` is useless for `p[p_idx]` and any `p_k > p[p_idx]`.
        // So, we must advance `h_idx` until `h[h_idx] + T >= p[p_idx]`.
        // If we run out of heads, then `p[p_idx]` cannot be covered.

        // Once we find such an `h[h_idx]`, it can cover `p[p_idx]`.
        // The range it covers is `[h[h_idx] - T, h[h_idx] + T]`.
        // We are interested in the rightmost point it can cover, which is `h[h_idx] + T`.
        // We also need to consider the constraint that `h[h_idx]` must be able to reach `p[p_idx]`.
        // This means `p[p_idx]` must be within `[h[h_idx] - T, h[h_idx] + T]`.
        // If `p[p_idx] < h[h_idx] - T`, then `h[h_idx]` cannot reach `p[p_idx]` by moving left.
        // This means `h[h_idx]` is too far to the right to cover `p[p_idx]` if it moves left.
        // This is the tricky part. A head can move left or right.

        // Let's simplify. We have a set of intervals `[h_i - T, h_i + T]`.
        // We need to cover all points `p_j`.
        // Iterate through `p_j` from left to right.
        // For `p[p_idx]`:
        // We need to find a head `h_k` such that `h_k - T <= p[p_idx] <= h_k + T`.
        // If we use `h_k` to cover `p[p_idx]`, then `h_k` can also cover all `p_j'` such that
        // `p_j'` is in `[p[p_idx], h_k + T]`.
        // To maximize the coverage to the right, we should pick a head `h_k` that can cover `p[p_idx]`
        // and has the largest `h_k + T`.

        // This is a standard interval covering problem.
        // `p_idx` is the current target track we need to cover.
        // `h_idx` is the current head we are considering.
        // While `p_idx < m`:
